mapper.select:
SELECT ROW_NUMBER() OVER(ORDER BY A.SSPS_DL_CRT_DT DESC, A.SSPS_DL_ID ASC) AS NU ,GET_CODE_NAME('M002', A.DL_P_RNM_NO_CCD) AS DL_P_RNM_NO_CCD_NM ,NVL(GET_SYNARIO_NAME(A.SSPS_TYP_CD), '수기등록') AS SSPS_TYP_NM ,(SELECT SUM(I.DL_AMT) FROM NIC75B I WHERE I.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND I.SSPS_DL_ID = A.SSPS_DL_ID ) AS DL_AMT ,(SELECT COUNT(*) FROM NIC73B J WHERE J.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND J.SSPS_DL_ID = A.SSPS_DL_ID ) AS SSPS_DL_CNT ,GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) AS RPR_CCD_NM ,GET_CODE_NAME('A004', A.RSK_GRD_CD) AS RSK_GRD_CD_NM ,GET_CODE_NAME('A004', A.RSK_GRD_CD) AS RSK_GRD_NM ,DECODE((SELECT COUNT(*) FROM NIC64B K WHERE K.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND K.SSPS_DL_ID = A.SSPS_DL_ID ), 0, 'No', 'Yes') AS FILE_ATT_YN ,(SELECT MAX(L.PROC_FALG) FROM NIC80B_LOG L WHERE L.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND L.SSPS_DL_ID = A.SSPS_DL_ID ) AS MAX_PROC_FALG /* 0: 정상, 1: 오류, '': 로그없음 */ ,(SELECT DECODE(COUNT(*), 0, 'N', 'Y') FROM NIC89B M WHERE M.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND M.SSPS_DL_ID = A.SSPS_DL_ID AND M.MN_DL_BRN_CD = A.SSPS_DL_ANLYS_BRN_CD ) AS J_2 ,NVL((SELECT CASE WHEN --(TRIM(N.RPR_RSN_CNTNT) = '' OR TRIM(N.RPR_RSN_CNTNT) = NULL) (N.RPR_RSN_CNTNT IS NULL OR (DBMS_LOB.GETLENGTH(N.RPR_RSN_CNTNT) > 1)) OR (TRIM(N.ITEM_CNTNT2) = '' OR TRIM(N.ITEM_CNTNT2) = NULL) OR (TRIM(N.ITEM_CNTNT1) = '' OR TRIM(N.ITEM_CNTNT1) = NULL) OR (TRIM(N.ITEM_CNTNT3) = '' OR TRIM(N.ITEM_CNTNT3) = NULL) OR (TRIM(N.ITEM_CNTNT4) = '' OR TRIM(N.ITEM_CNTNT4) = NULL) OR (TRIM(N.ITEM_CNTNT5) = '' OR TRIM(N.ITEM_CNTNT5) = NULL) OR (TRIM(N.ITEM_CNTNT6) = '' OR TRIM(N.ITEM_CNTNT6) = NULL) OR (TRIM(N.DOBT_DL_GRD_CD) = '' OR TRIM(N.DOBT_DL_GRD_CD) = NULL) THEN 'N' ELSE 'Y' END FROM NIC67B N WHERE N.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND N.SSPS_DL_ID = A.SSPS_DL_ID ),'N') AS B_1 ,(SELECT DECODE(COUNT(*), 0, 'N', 'Y') FROM NIC68B O WHERE O.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND O.SSPS_DL_ID = A.SSPS_DL_ID ) AS B_2 ,A.* FROM (SELECT /*+ INDEX(P PK_NIC66B) INDEX(Q PK_NIC70B) INDEX(S PK_NIC35B) */ P.SSPS_DL_ID ,P.SSPS_DL_CRT_DT ,P.SSPS_DL_CRT_DT || '-' || REPLACE(P.SSPS_DL_ID, 'CTR', 'STR') AS SSPS_DL_CRT_DT_A ,Q.DL_P_NM ,P.DL_P_RNMCNO ,R.RNMCNO AS RNMCNO_VIEW ,R.RNMCNO AS RNMCNO_HIDDEN ,Q.DL_P_RNM_NO_CCD ,P.SSPS_TYP_CD ,P.SSPS_DL_ANLYS_BRN_CD AS MN_DL_BRN_CD ,P.SSPS_DL_ANLYS_BRN_NM AS MN_DL_BRN_NM ,P.RPR_PRGRS_CCD ,P.RPR_CHRG_P_NM ,P.RPR_RSPSB_P_NM ,T.SND_RCPT_DOC_NO AS DOC_NO --문서번호 ,P.SSPS_DL_CRT_CCD ,S.LST_RSK_EAL_SOR AS RSK_GRD_MRK ,S.RSK_GRD_CD ,R.RNMCNO ,Q.INDV_CORP_CCD ,ROUND(P.RSK_MRK, 2) AS RSK_MRK ,P.RSK_GRD_CD AS RSK_GRD ,CASE WHEN RPR_PRGRS_CCD IN ('99', '10') THEN 'download' END AS TRSMT_ST_NM ,T.SND_RCPT_FILE_NM ,R.CS_TYP_CD ,P.OK_CCD ,T.FIU_NO ,T.FIU_REG_DT ,TO_CHAR(P.RPR_COMPLITE_DT, 'YYYYMMDD') AS RPR_COMPLITE_DT ,P.SSPS_DL_ANLYS_BRN_CD ,T.SND_BEFORE_RCPT_DOC_NO --종전문서번호 ,(SELECT X.GNL_AC_NO FROM NIC75B X WHERE X.SSPS_DL_CRT_DT = P.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = P.SSPS_DL_ID AND ROWNUM = 1 ) AS GNL_AC_NO -- 계좌번호 FROM NIC66B P ,NIC70B Q ,NIC01B R ,NIC35B S ,NIC80B T WHERE P.SSPS_DL_CRT_DT = Q.SSPS_DL_CRT_DT(+) AND P.DL_P_RNMCNO = Q.DL_P_RNMCNO(+) AND P.DL_P_RNMCNO = R.RNMCNO(+) AND P.DL_P_RNMCNO = S.RNMCNO(+) AND P.SSPS_DL_CRT_DT = T.SSPS_DL_CRT_DT(+) AND P.SSPS_DL_ID = T.SSPS_DL_ID(+) AND P.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND P.RPR_PRGRS_CCD IN ('9', '10', '97', '98', '99') AND P.OK_CCD = 1 -- 보고상태가 '보고' ) A
WHERE A.SSPS_DL_CRT_DT >= #{startDate}
AND A.SSPS_DL_CRT_DT <= #{endDate}
AND #{branchCode} IN (SELECT U.MN_DL_BRN_CD FROM NIC73B U WHERE U.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND U.SSPS_DL_ID = A.SSPS_DL_ID )
AND A.RPR_PRGRS_CCD = #{RPR_PRGRS_CCD, jdbcType=VARCHAR}
AND UPPER(A.DL_P_NM) LIKE '%'|| UPPER(#{CS_NM, jdbcType=VARCHAR}) || '%'
AND A.DL_P_RNMCNO LIKE #{RNMCNO, jdbcType=VARCHAR} || '%'

  SELECT NVL(XCL_RSN_CNTNT, '0') XCL_RSN_CNTNT -- 제외보고, 반려사유
 	 , OK_CCD
 FROM NIC66B
WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
  AND SSPS_DL_ID = #{SSPS_DL_ID}

SELECT COUNT(*) AS CNT
  FROM NIC88B A
 WHERE A.SSPS_DL_CRT_DT =  #{SSPS_DL_CRT_DT}
   AND A.SSPS_DL_ID = #{SSPS_DL_ID}
   AND A.MN_DL_BRN_CD = #{MN_DL_BRN_CD}

SELECT A.ITEM_CNTNT1 AS ITEM_CNTNT1 --의심스러운 거래자
,CASE WHEN TRIM(REPLACE(A.ITEM_CNTNT2, '-', '')) IS NULL THEN SUBSTR(A.SSPS_DL_CRT_DT, 1, 4) || '-' || SUBSTR(A.SSPS_DL_CRT_DT, 5, 2) || '-' || SUBSTR(A.SSPS_DL_CRT_DT, 7, 2) WHEN LENGTH(TRIM(A.ITEM_CNTNT2)) <> 10 THEN SUBSTR(A.ITEM_CNTNT2, 1, 4) || '-' || SUBSTR(A.ITEM_CNTNT2, 5, 2) || '-' || SUBSTR(A.ITEM_CNTNT2, 7, 2) ELSE A.ITEM_CNTNT2 END AS ITEM_CNTNT2 --거래 발생일자 ,A.ITEM_CNTNT3 AS ITEM_CNTNT3 --거래 발생장소(영업점) ,A.ITEM_CNTNT4 AS ITEM_CNTNT4 --금융거래 수단(상품) ,A.ITEM_CNTNT5 AS ITEM_CNTNT5 --금융거래 방법(특이거래) ,A.ITEM_CNTNT6 AS ITEM_CNTNT6 --혐의거래로 판단한 사유 ,REPLACE((A.RPR_RSN_CNTNT || A.RPR_RSN_CNTNT2), '--', CASE WHEN TRIM(REPLACE(A.ITEM_CNTNT2, '-', '')) IS NULL THEN SUBSTR(A.SSPS_DL_CRT_DT, 1, 4) || '-' || SUBSTR(A.SSPS_DL_CRT_DT, 5, 2) || '-' || SUBSTR(A.SSPS_DL_CRT_DT, 7, 2) WHEN LENGTH(TRIM(A.ITEM_CNTNT2)) <> 10 THEN SUBSTR(A.ITEM_CNTNT2, 1, 4) || '-' || SUBSTR(A.ITEM_CNTNT2, 5, 2) || '-' || SUBSTR(A.ITEM_CNTNT2, 7, 2) ELSE A.ITEM_CNTNT2 END ) AS RPR_RSN_CNTNT --RPR_RSN_CNTNT --종합의견 20190510 수정함.
,A.ATT_FILE_NM AS ATT_FILE_NM --첨부파일명 작성 ,A.DOBT_DL_GRD_CD AS DOBT_DL_GRD_CD --의심스러운 거래의 등급 설정 ,A.DOC_NM AS SEND_DOC_NM --별도송부 문서명 작성 ,NVL((SELECT I.SND_RCPT_DOC_NO FROM NIC80B I WHERE I.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND I.SSPS_DL_ID = #{SSPS_DL_ID} AND ROWNUM = 1), '' ) AS RE_DOC --관련문서번호 ,A.AI_RPR_RSN_CNTNT AS AI_RPR_RSN_CNTNT --AI 종합의견 FROM NIC67B A WHERE A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

  SELECT PRXY_NM,
      PRXY_RNM_NO_CCD,
      GET_CODE_NAME('M002',PRXY_RNM_NO_CCD) AS PRXY_RNM_NO_CCD_NM,
      PRXY_RNMCNO,
      FN_CDINFO_VAR('NO',PRXY_RNMCNO,'') AS PRXY_RNMCNO_VIEW,
      PRXY_TEL_NO,
      PRXY_NTNLT_CD,
      PRXY_NTNLT_NM,
      AC_OWN_P_RLTNS_CD,
      GET_CODE_NAME('M042',AC_OWN_P_RLTNS_CD) AS AC_OWN_P_RLTNS_CD_NMF
 FROM NIC98B
WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
  AND SSPS_DL_ID = #{SSPS_DL_ID}
  AND GNL_AC_NO = #{GNL_AC_NO}
  AND DL_DT = #{DL_DT}
  AND DL_SQ = #{DL_SQ}

SELECT A.PRXY_NM
      ,A.PRXY_RNM_NO_CCD
      ,GET_CODE_NAME('M002', A.PRXY_RNM_NO_CCD) AS PRXY_RNM_NO_CCD_NM
      ,A.PRXY_RNMCNO
      ,FN_CDINFO_VAR('NO', A.PRXY_RNMCNO, '') AS PRXY_RNMCNO_VIEW
      ,A.PRXY_TEL_NO
      ,A.PRXY_NTNLT_CD
      ,A.PRXY_NTNLT_NM
      ,A.AC_OWN_P_RLTNS_CD
      ,GET_CODE_NAME('M042', A.AC_OWN_P_RLTNS_CD) AS AC_OWN_P_RLTNS_CD_NM
  FROM NIC98B A
 WHERE A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND A.SSPS_DL_ID = #{SSPS_DL_ID}
   AND A.GNL_AC_NO = #{GNL_AC_NO}
   AND A.GDS_NO = #{GDS_NO}
   AND A.DL_DT = #{DL_DT}
   AND A.DL_SQ = #{DL_SQ}

SELECT A.*
  FROM NIC03B A
 WHERE A.RNMCNO  = #{param0}

