UPDATE NIC03B
   SET RPRST_P_RNMCNO = #{param0}
      ,RPRST_P_NM = #{param1}
      ,RPRST_P_TEL_NO = #{param2}
      ,RPRST_P_RNM_NO_CCD = #{param3}
      ,RPRST_P_NTNLT_CD = #{param4}
      ,RPRST_P_HSE_ADDR = #{param5}
      ,RPRST_P_HSE_PST_NO = #{param6}
      ,RPRST_P_SEX_CD = #{param7}
 WHERE RNMCNO  = #{param8}

mapper.select:
SELECT TBL.* , GET_CODE_NAME('M002',TBL.RNM_CNFR_CCD) AS DL_P_RNM_NO_CCD_NM , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , CASE WHEN TBL.SSPS_TYP_CD = 'KYC0' THEN '수기 등록' ELSE GET_SYNARIO_NAME(TBL.SSPS_TYP_CD) END AS SSPS_TYP_NM , GET_CODE_NAME('A004',TBL.RSK_GRD_CD) AS RSK_GRD_CD_NM , DECODE((SELECT COUNT(*) FROM NIC66B WHERE SSPS_DL_CRT_DT=TBL.SSPS_DL_CRT_DT AND DL_P_RNMCNO=TBL.DL_P_RNMCNO AND M_SSPS_DL_ID IS NOT NULL),0,'N','Y') MERGE_YN , NVL(TBL.MN_DL_DPRT_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.MN_DL_DPRT_CD)) AS MN_DL_DPRT_NM , NVL(TBL.PRFT_BRN_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.PRFT_BRN_CD)) AS PRFT_BRN_NM , DECODE((SELECT COUNT(*) FROM NIC66B WHERE SSPS_DL_CRT_DT >= TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT,'YYYYMMDD'),-1),'YYYYMMDD') AND SSPS_DL_CRT_CCD IN ('STR','KYC') AND DL_P_RNMCNO = TBL.DL_P_RNMCNO AND RPR_PRGRS_CCD = '99'),0,'','Y') STR_RPR_YN FROM ( SELECT /*+ leading(T1)*/ /* 20210823 V1 --> T1 */ ROW_NUMBER() OVER(ORDER BY T1.SSPS_DL_CRT_DT DESC, T1.SSPS_DL_ID ASC) AS NU , (T1.SSPS_DL_CRT_DT || '-' || T1.SSPS_DL_ID) AS SSPS_DL_CRT_DT_A -- , T2.CS_NM AS DL_P_NM , G.CS_NM AS DL_P_NM , T2.INDV_CORP_CCD , T2.RNM_CNFR_CCD , T3.RSK_GRD_CD AS RSK_GRD_CD , T1.SSPS_TYP_CD , T1.DL_P_RNMCNO -- , T2.CS_NO , CASE WHEN G.SPRN_KEEP_TAGT_YN = 'Y' THEN G.CS_NO ELSE T2.CS_NO END AS CS_NO , CASE WHEN G.SPRN_KEEP_TAGT_YN = 'Y' THEN G.CS_NO ELSE T2.CS_NO END AS AML_CUST_ID , V1.ACT_NAME , (NVL(T1.OK_CCD, '0')) AS OK_CCD , T1.XCL_RSN_CNTNT , T1.DNY_RSN_CNTNT , T1.SSPS_DL_CRT_DT , T1.SSPS_DL_ID , T1.INST_ID , V1.WORK_ID , V1.ACT_ID , G.GNL_AC_NO , G.ACNT_NO , G.MN_DL_DPRT_CD , G.MN_DL_DPRT_NM , G.PRFT_BRN_CD , G.PRFT_BRN_NM , T1.TRIG_CTNT , G.SPRN_KEEP_TAGT_YN FROM NIC66B T1 , NIC01B T2 , NIC35B T3 ,(SELECT /*+ FULL(D) PARALLEL(D 4) */ /* INDEX(D NIC66BIX03)*/ A.INST_ID , A.WORK_ID , A.ACT_NAME , A.ACT_ID , D.SSPS_DL_CRT_DT , D.SSPS_DL_ID , A.PROC_ID FROM V_WF_STANDBY A, NIC66B D WHERE (A.PERSON_YN = 'Y' AND A.PARTICIPANT_ID =#{userId}) AND D.INST_ID = A.PAR_INST_ID AND D.RPR_PRGRS_CCD = '2' UNION ALL SELECT /*+ FULL(D) PARALLEL(D 4) */ /* INDEX(D NIC66BIX03)*/ A.INST_ID , A.WORK_ID , A.ACT_NAME , A.ACT_ID , D.SSPS_DL_CRT_DT , D.SSPS_DL_ID , A.PROC_ID FROM V_WF_STANDBY A, NIC66B D WHERE (A.PERSON_YN = 'N' AND A.PARTICIPANT_ID =#{dptRole}) AND D.INST_ID = A.PAR_INST_ID AND D.RPR_PRGRS_CCD = '2' ) V1 ,(SELECT X.SSPS_DL_CRT_DT , X.SSPS_DL_ID , X.GNL_AC_NO , X.MN_DL_DPRT_CD , X.MN_DL_DPRT_NM , X.PRFT_BRN_CD , X.PRFT_BRN_NM , X.ACNT_NO , X.CS_NM , X.SPRN_KEEP_TAGT_YN , Y.CS_NO FROM NIC71B X , NIC70B Y WHERE (X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, X.GNL_AC_NO) IN (SELECT X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, MIN(X.GNL_AC_NO) FROM NIC71B X , NIC66B Y WHERE X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = Y.SSPS_DL_ID AND X.RNMCNO = Y.DL_P_RNMCNO GROUP BY X.SSPS_DL_CRT_DT, X.SSPS_DL_ID) AND X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT(+) AND X.RNMCNO = Y.DL_P_RNMCNO(+) ) G WHERE T1.DL_P_RNMCNO = T2.RNMCNO AND T1.DL_P_RNMCNO = T3.RNMCNO(+) AND T1.SSPS_DL_CRT_DT = V1.SSPS_DL_CRT_DT AND T1.SSPS_DL_ID = V1.SSPS_DL_ID AND T1.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = G.SSPS_DL_ID(+)
AND T1.SSPS_DL_CRT_DT >= #{stDate, jdbcType=VARCHAR}
AND T1.SSPS_DL_CRT_DT <= #{edDate, jdbcType=VARCHAR}
AND #{branchCode, jdbcType=VARCHAR} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND SSPS_DL_ID = T1.SSPS_DL_ID)
AND T1.SSPS_DL_CRT_CCD = #{SSPS_DL_CRT_CCD}
AND T1.SSPS_DL_CRT_CCD IN ('STR', 'KYC')
AND T1.SSPS_TYP_CD = #{SSPS_TYP_CD, jdbcType=VARCHAR}
AND G.ACNT_NO LIKE #{ACNT_NO, jdbcType=VARCHAR} || '%'
AND T2.CS_NM LIKE '%'|| #{CS_NM, jdbcType=VARCHAR} ||'%'
AND T2.CS_NO = #{CS_NO, jdbcType=VARCHAR}
)TBL WHERE 1=1

SELECT COUNT(*) AS CNT
  FROM (SELECT R.SSPS_DL_CRT_DT || '-' || R.SSPS_DL_ID AS SSPS_DL_CRT_DT_A
          FROM V_WF_STANDBY Q
         INNER JOIN NIC66B R
            ON R.INST_ID = Q.PAR_INST_ID
         WHERE (
                   (    Q.PERSON_YN = 'Y'
                    AND Q.PARTICIPANT_ID = #{USER_ID}
                   )
                OR (    Q.PERSON_YN = 'N'
                    AND Q.PARTICIPANT_ID IN (SELECT Y1.DEP_ID || '.' || ROLE_ID
                                               FROM C_USER_GROUP_ROLE X1
                                                   ,C_USER Y1
                                              WHERE X1.USER_ID = #{USER_ID}
                                                AND X1.USER_ID = Y1.USER_ID
                                                AND Y1.DEP_ID || '.' || ROLE_ID = #{DPT_ROLE}
                                            )
                   )
                OR (    Q.PERSON_YN = 'N'
                    AND Q.PARTICIPANT_ID IN (SELECT Z2.TGT_DEP_ID || '.' || Z2.ROLE_ID
                                               FROM C_USER_GROUP_ROLE X2
                                                   ,C_USER Y2
                                                   ,(SELECT XX.*
                                                       FROM C_MULTI_POSITION XX
                                                      WHERE XX.CHRG_P_ID = #{USER_ID}
                                                        AND XX.APPR_STAT_CD = 'E'
                                                        AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN XX.START_DT AND XX.END_DT
                                                        AND ROWNUM = 1
                                                    ) Z2
                                              WHERE X2.USER_ID = #{USER_ID}
                                                AND X2.USER_ID = Y2.USER_ID
                                                AND X2.USER_ID = Z2.CHRG_P_ID
                                                AND Y2.DEP_ID || '.' || X2.ROLE_ID = #{DPT_ROLE}
                                            )
                   )
               )
           AND R.RPR_PRGRS_CCD = '2'
           AND (R.SSPS_DL_ID LIKE 'STR%' OR R.SSPS_DL_ID LIKE 'KYC%')
       ) T1
 WHERE T1.SSPS_DL_CRT_DT_A = #{SSPS_DL_CRT_DT_A}

SELECT MAX(A.WORK_ID) AS WORK_ID
  FROM NIC66B_W A
 WHERE A.INST_ID = #{INST_ID}

SELECT A.WORK_ID
  FROM WF_PROC_INSTANCE A
 WHERE A.INST_ID = #{INST_ID}

