UPDATE NIC66B
   SET OK_CCD = #{OK_CCD}
      ,DNY_RSN_CNTNT = #{DNY_RSN_CNTNT}
      ,HNDL_DY_TM = SYSDATE
      ,HNDL_P_ENO = #{USERID}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
