UPDATE NIC66B
   SET OK_CCD = #{OK_CCD}

      ,XCL_RSN_CNTNT = #{XCL_RSN_CNTNT}


      ,XCL_RSN_CNTNT2 = #{XCL_RSN_CNTNT}

      ,HNDL_DY_TM = SYSDATE
      ,HNDL_P_ENO = #{LOGIN_ID}
  WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
    AND SSPS_DL_ID = #{SSPS_DL_ID}

mapper.select:
SELECT T1.* FROM (SELECT COUNT(*) OVER() AS TOTALCOUNT ,ROWNUM AS SEQ ,T2.* FROM (SELECT A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A ,NVL(TRIM(B.CS_NM), B.ENG_CS_NM) AS DL_P_NM ,A.DL_P_RNMCNO ,GET_CODE_NAME('M002', B.RNM_CNFR_CCD) AS DL_P_RNM_NO_CCD_NM
,NVL((SELECT X1.BIZ_NM FROM C_BIZ X1 ,MMA010TB Y1 WHERE X1.BIZ_ID = Y1.RT30_1 AND Y1.MA01_6 = A.SSPS_TYP_CD ), '수기등록' ) AS SSPS_TYP_NM
,NVL((SELECT X2.SCNR_NM FROM TMS_APPL X2 WHERE X2.SCNR_ID = A.SSPS_TYP_CD ), '수기등록' ) AS SSPS_TYP_NM
,C.LST_RSK_EAL_SOR AS RSK_GRD_MRK ,C.RSK_GRD_CD AS RSK_GRD_CD ,GET_CODE_NAME('A004', C.RSK_GRD_CD) AS RSK_GRD_CD_NM ,A.RSK_MRK AS RSK_MRK ,A.RSK_GRD_CD AS RSK_GRD ,GET_CODE_NAME('A004', A.RSK_GRD_CD) AS RSK_GRD_NM ,J.DL_AMT ,CASE WHEN A.RPR_PRGRS_CCD = '2' THEN F.ACT_NAME ELSE GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) END AS ACT_NAME ,GET_CODE_NAME('A301', NVL(A.OK_CCD, '0')) AS OK_CCD_NM ,NVL(A.XCL_RSN_CNTNT, A.XCL_RSN_CNTNT2) AS XCL_RSN_CNTNT ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,A.INST_ID ,D.MN_DL_BRN_NM AS MN_DL_BRN_NM -- 처리점 ,D.MN_DL_BRN_CD AS MN_DL_BRN_CD -- 처리점 ,G.GNL_AC_NO ,H.CNT ,I.SSPS_DL_CRT_DT AS RPR_DT ,B.LG_AMT_ASTS_F ,CASE WHEN TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'), 'YYYYMMDD') - TO_DATE(A.SSPS_DL_CRT_DT, 'YYYYMMDD') < 10 THEN '1' ELSE '2' END AS REPORTDATE ,A.SSPS_TYP_CD ,A.SCNR_MRK ,TO_CHAR(A.RPR_COMPLITE_DT, 'YYYYMMDD') AS RPR_COMPLITE_DT FROM NIC66B A INNER JOIN NIC01B B ON A.DL_P_RNMCNO = B.RNMCNO LEFT JOIN NIC35B C ON B.RNMCNO = C.RNMCNO INNER JOIN NIC73B D ON A.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = D.SSPS_DL_ID INNER JOIN NIC70B E ON A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = E.DL_P_RNMCNO
INNER JOIN (SELECT X3.INST_ID ,Y3.ACT_NAME ,X3.PROC_ID ,Y3.ACT_ID FROM WF_PROC_INSTANCE X3 LEFT JOIN MV_APRV_STATUS Y3 ON X3.INST_ID = Y3.PAR_INST_ID AND Y3.INST_STATUS_CD != 'DELETED' ) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X4.INST_ID ,Y4.ACT_NAME ,X4.PROC_ID ,Y4.ACT_ID FROM WF_PROC_INSTANCE X4 LEFT JOIN MV_APRV_STATUS Y4 ON X4.INST_ID = Y4.PAR_INST_ID AND Y4.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z4 ON X4.INST_ID = Z4.INST_ID WHERE Z4.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND Y4.ACT_NAME IN (SELECT XX.ACT_NAME FROM WF_ACT XX WHERE XX.ACT_ID IN
#{wfCodeArray1, jdbcType=VARCHAR}
) UNION SELECT X5.INST_ID ,GET_CODE_NAME('A029', X5.RPR_PRGRS_CCD) AS ACT_NAME ,0 AS PROC_ID ,0 AS ACT_ID FROM NIC66B X5 WHERE X5.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND X5.RPR_PRGRS_CCD IN
#{wfCodeArray2, jdbcType=VARCHAR}
) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X6.INST_ID ,Y6.ACT_NAME ,X6.PROC_ID ,Y6.ACT_ID FROM WF_PROC_INSTANCE X6 LEFT JOIN MV_APRV_STATUS Y6 ON X6.INST_ID = Y6.PAR_INST_ID AND Y6.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z6 ON X6.INST_ID = Z6.INST_ID WHERE Z6.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND Y6.ACT_NAME IN (SELECT YY.ACT_NAME FROM WF_ACT YY WHERE YY.ACT_ID IN
#{wfCodeArray1, jdbcType=VARCHAR}
) ) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X7.SSPS_DL_CRT_DT ,X7.SSPS_DL_ID ,MAX(X7.GNL_AC_NO) KEEP (DENSE_RANK FIRST ORDER BY X7.DL_DT DESC, X7.DL_TM DESC) AS GNL_AC_NO FROM NIC75B X7 GROUP BY X7.SSPS_DL_CRT_DT ,X7.SSPS_DL_ID ) G ON A.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = G.SSPS_DL_ID LEFT JOIN (SELECT X8.DL_P_RNMCNO ,COUNT(*) AS CNT FROM NIC66B X8 WHERE X8.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') GROUP BY X8.DL_P_RNMCNO ) H ON A.DL_P_RNMCNO = H.DL_P_RNMCNO LEFT JOIN (SELECT X9.DL_P_RNMCNO ,MAX(X9.SSPS_DL_CRT_DT) AS SSPS_DL_CRT_DT FROM NIC66B X9 WHERE X9.OK_CCD ='1' AND X9.RPR_PRGRS_CCD = '10' AND X9.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') GROUP BY X9.DL_P_RNMCNO ) I ON A.DL_P_RNMCNO = I.DL_P_RNMCNO LEFT JOIN (SELECT SUM(X10.DL_AMT) AS DL_AMT ,X10.SSPS_DL_CRT_DT ,X10.SSPS_DL_ID FROM NIC75B X10 GROUP BY X10.SSPS_DL_CRT_DT ,X10.SSPS_DL_ID ) J ON A.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = J.SSPS_DL_ID WHERE 1 = 1 AND A.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC')
AND A.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND A.SSPS_DL_CRT_CCD = #{SSPS_DL_CRT_CCD}
AND #{branchCode} IN (SELECT X11.MN_DL_BRN_CD FROM NIC73B X11 WHERE X11.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X11.SSPS_DL_ID = A.SSPS_DL_ID )
AND A.SSPS_TYP_CD IN
#{SSPS_TYP_CD_ARRAY}
AND A.RPR_PRGRS_CCD IN
#{wfCodeArray2, jdbcType=VARCHAR}
AND A.OK_CCD = #{wfCodeSts}
AND ( B.CS_NM = #{CS_NM} OR B.ENG_CS_NM = #{CS_NM} )
AND A.DL_P_RNMCNO LIKE '%' || UPPER(#{RNMCNO}) || '%'
ORDER BY
SSPS_DL_CRT_DT_A MN_DL_BRN_NM DL_P_NM DL_P_RNMCNO DL_P_RNM_NO_CCD_NM GNL_AC_NO DL_AMT SSPS_TYP_CD SSPS_TYP_NM CNT RPR_DT RSK_GRD_MRK DECODE(RSK_GRD_CD_NM, '고', 1, '중', 2, '저', 3) LG_AMT_ASTS_F ACT_NAME OK_CCD_NM XCL_RSN_CNTNT
ASC DESC
ORDER BY A.SSPS_DL_CRT_DT DESC ,A.SSPS_DL_ID ASC
) T2 WHERE 1 = 1
AND T2.REPORTDATE = #{reportdate}
) T1 WHERE 1 = 1
AND T1.SEQ >= (( #{thisPage} - 1) * #{pageCount} + 1) AND T1.SEQ <= (#{thisPage} * #{pageCount})

SELECT COUNT(*) OVER() AS TOTALCOUNT , ROW_NUMBER() OVER(ORDER BY TBL.SSPS_DL_CRT_DT DESC, TBL.SSPS_DL_ID ASC) AS SEQ , GET_CODE_NAME('M002',TBL.RNM_CNFR_CCD) AS DL_P_RNM_NO_CCD_NM , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , GET_CODE_NAME('A004',TBL.RSK_GRD_CD) AS RSK_GRD_CD_NM , CASE WHEN TBL.RPR_PRGRS_CCD = '2' THEN TBL.ACT_NAME ELSE GET_CODE_NAME('A029',TBL.RPR_PRGRS_CCD) END AS ACT_NAME , GET_CODE_NAME('A301', (NVL(TBL.OK_CCD, '0')) ) AS OK_CCD_NM , NVL(TBL.MN_DL_DPRT_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.MN_DL_DPRT_CD)) AS MN_DL_DPRT_NM , NVL(TBL.PRFT_BRN_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.PRFT_BRN_CD)) AS PRFT_BRN_NM , CASE WHEN TBL.RPR_PRGRS_CCD = '9' OR TBL.RPR_PRGRS_CCD = '99' THEN (SELECT SUBSTR(MAX(RPR_P_DY_TM),1,8) FROM NIC66B_W WHERE INST_ID = TBL.INST_ID) END AS INST_DT , CASE WHEN TBL.RPR_PRGRS_CCD = '2' THEN '' ELSE GET_CODE_NAME('S060', NVL(TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD)) END AS KFU_RPR_STS_NM , CASE WHEN TBL.INDV_CORP_CCD = '1' THEN CASE WHEN LENGTH(TRIM(TBL.AML_JOB_GUBN)) = 3 THEN '[' || TRIM(TBL.AML_JOB_GUBN) || '] ' || CASE WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '0' THEN '미제공' WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '1' THEN '근로소득자' WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '2' THEN '자영업자' WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '3' THEN '전문직' WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '4' THEN '기타금융업' WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) = '9' THEN '기타' ELSE SUBSTR(TRIM(TBL.AML_JOB_GUBN), 1, 1) END || '-' || CASE WHEN SUBSTR(TRIM(TBL.AML_JOB_GUBN), 2, 1) = '9' THEN '기타' ELSE NVL((SELECT T.CMN_CDVL_NAME FROM SID.IDO_A_UWB_COM_CD_DTL T WHERE T.CMN_CODE_ID = '01437' AND T.USE_YN = 'Y' AND T.CMN_CDVL = TRIM(TBL.AML_JOB_GUBN)), '미정의값') END || CASE WHEN NVL(TBL.JOB_CODE, '') = TRIM(TBL.AML_JOB_GUBN) AND SUBSTR(TRIM(TBL.AML_JOB_GUBN), 2, 1) = '9' AND LENGTH(TRIM(NVL(TBL.JOB_NAME, ''))) > 0 THEN '(' || TRIM(TBL.JOB_NAME) || ')' ELSE '' END ELSE TRIM(TBL.AML_JOB_GUBN) END -- AS JOB_NAME -- 직업명 ELSE CASE WHEN LENGTH(TRIM(TBL.INDST_RSK_DVD_CD)) > 0 THEN '[' || TRIM(TBL.INDST_RSK_DVD_CD) || '] ' || NVL((SELECT MAX(T.CMN_CDVL_NAME) FROM SID.IDO_A_UWB_COM_CD_DTL T WHERE T.CMN_CODE_ID = '00631' AND T.USE_YN = 'Y' AND T.CMN_CDVL = TRIM(TBL.INDST_RSK_DVD_CD)), '미정의값') ELSE '' END -- AS STND_INDY_CLSN_NAME -- 업종 END AS STND_INDY_CLSN_NAME ,TBL.* --20210525 검색화면 필터 추가 , TBL.DL_P_RNMCNO AS C_ID , MGR1.EMPY_NO AS A_EMPY_NO , NVL(MGR1_USER.USER_NAME, '') AS A_USER_NAME , NVL(MGR1_DTBR.DTBR_CODE, '') AS A_DTBR_CODE , NVL(MGR1_DTBR.DTBR_NAME, '') AS A_DTBR_NAME --, MGR2.MAIN_MNGR_EMPY_NO AS C_MAIN_MNGR_EMPY_NO --, NVL(MGR2_USER.USER_NAME, '') AS C_USER_NAME --, NVL(MGR2_DTBR.DTBR_CODE, '') AS C_DTBR_CODE --, NVL(MGR2_DTBR.DTBR_NAME, '') AS C_DTBR_NAME FROM ( SELECT /*+ LEADING(T1) INDEX(T1 NIC66BPK) */ DISTINCT (T1.SSPS_DL_CRT_DT || '-' || T1.SSPS_DL_ID) AS SSPS_DL_CRT_DT_A -- , T2.CS_NM AS DL_P_NM , G.CS_NM AS DL_P_NM , T2.INDV_CORP_CCD -- , T2.CS_NO , CASE WHEN G.SPRN_KEEP_TAGT_YN = 'Y' THEN G.CS_NO ELSE T2.CS_NO END AS CS_NO , CASE WHEN G.SPRN_KEEP_TAGT_YN = 'Y' THEN G.CS_NO ELSE T2.CS_NO END AS AML_CUST_ID , CASE WHEN T1.SSPS_TYP_CD = 'KYC0' THEN '수기 등록' ELSE GET_SYNARIO_NAME(T1.SSPS_TYP_CD) END AS SSPS_TYP_NM , T3.RSK_GRD_CD AS RSK_GRD_CD , G.PRFT_BRN_NM , T1.DL_P_RNMCNO , T1.RPR_PRGRS_CCD , NVL(T1.KFU_RPR_STS_CD, T1.RPR_PRGRS_CCD) AS KFU_RPR_STS_CD , G.MN_DL_DPRT_NM , T1.XCL_RSN_CNTNT , T1.SSPS_DL_CRT_DT , T1.SSPS_DL_ID , T1.INST_ID , G.GNL_AC_NO , G.ACNT_NO , G.MN_DL_DPRT_CD , T1.OK_CCD , G.PRFT_BRN_CD , D.ACT_NAME , T1.TRIG_CTNT , TO_CHAR(T1.KFU_RPR_DT, 'YYYYMMDD' ) AS KFU_RPR_DT , T2.INDST_RSK_DVD_CD , T2.AML_JOB_GUBN , CDD.JOB_NAME , CDD.JOB_CODE , T2.RNM_CNFR_CCD , T1.KFU_RRPR_STS_CD , T2.CS_NM , T1.SSPS_TYP_CD , T1.SSPS_DL_CRT_CCD , D.ACT_ID , (CASE WHEN ( SELECT EMPY_NO FROM SID.IDO_A_UUE_EMPLOYEE B1 WHERE B1.ENTY_ID = T1.DL_P_RNMCNO AND B1.EMPY_NO BETWEEN '100000' AND '600000' AND B1.PDSS_USER_STAS_SECT_CODE IN ('A', 'C') )IS NOT NULL THEN 'Y' ELSE '' END) AS EMPY_YN , G.SPRN_KEEP_TAGT_YN FROM NIC66B T1 , NIC01B T2 , NIC35B T3 , (SELECT A.INST_ID, C.ACT_NAME, C.ACT_ID FROM WF_PROC_INSTANCE A , WF_WORKLIST B , WF_ACT C WHERE A.WORK_ID = B.WORK_ID AND B.ACT_ID = C.ACT_ID
AND C.ACT_ID = #{wfCode}
) D ,(SELECT X.SSPS_DL_CRT_DT , X.SSPS_DL_ID , X.GNL_AC_NO , X.MN_DL_DPRT_CD , X.MN_DL_DPRT_NM , X.PRFT_BRN_CD , X.PRFT_BRN_NM , X.ACNT_NO , X.CS_NM , X.SPRN_KEEP_TAGT_YN , Y.CS_NO FROM NIC71B X , NIC70B Y WHERE (X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, X.GNL_AC_NO) IN (SELECT X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, MIN(X.GNL_AC_NO) FROM NIC71B X , NIC66B Y WHERE X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = Y.SSPS_DL_ID AND X.RNMCNO = Y.DL_P_RNMCNO GROUP BY X.SSPS_DL_CRT_DT, X.SSPS_DL_ID) AND X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT(+) AND X.RNMCNO = Y.DL_P_RNMCNO(+) ) G , SID.IDO_A_MAH_CDD_FLFL_DTLD CDD WHERE T1.DL_P_RNMCNO = T2.RNMCNO AND T1.DL_P_RNMCNO = T3.RNMCNO(+) AND T1.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND T1.INST_ID = D.INST_ID(+) AND T1.INST_ID IS NOT NULL AND T1.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = G.SSPS_DL_ID(+) AND T2.RNMCNO = CDD.CDD_TAGT_ENTY_ID(+)
)TBL --20210525 검색화면 필터추가 LEFT OUTER JOIN SID.IDO_A_UUA_ACNT_ENTY_RLTP MGR1 -- 계좌기준 ON MGR1.ACNT_ENTY_ROLE_TYPE_CODE = 'MANG' AND MGR1.ACNT_ID = TBL.GNL_AC_NO LEFT OUTER JOIN SID.IDO_A_UWA_USER MGR1_USER ON MGR1_USER.USER_ID = MGR1.EMPY_NO LEFT OUTER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT MGR1_DTBR ON MGR1_DTBR.ENTY_ID = MGR1_USER.DTBR_ENTY_ID
--LEFT OUTER JOIN SID.IDO_A_IRA_CUST_MGR MGR2 -- 고객기준 -- ON MGR2.CLNT_ENTY_ID = TBL.DL_P_RNMCNO --LEFT OUTER JOIN SID.IDO_A_UWA_USER MGR2_USER -- ON MGR2_USER.USER_ID = MGR2.MAIN_MNGR_EMPY_NO --LEFT OUTER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT MGR2_DTBR -- ON MGR2_DTBR.ENTY_ID = MGR2_USER.DTBR_ENTY_ID WHERE 1=1 -- 추출일자 전체 ..
AND TBL.SSPS_DL_CRT_DT >= #{stDate} AND TBL.SSPS_DL_CRT_DT <= #{edDate}
AND TBL.ACT_ID = #{wfCode}
AND TBL.SSPS_DL_CRT_CCD = #{SSPS_DL_CRT_CCD}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID)
AND TBL.SSPS_TYP_CD = #{SSPS_TYP_CD}
AND TBL.CS_NO = #{CS_NO}
AND TBL.RPR_PRGRS_CCD = #{wfCode2}
AND TBL.OK_CCD = #{wfCodeSts}
AND TBL.SSPS_TYP_CD IN (SELECT MA01_6 FROM C_BIZ A, MMA010TB B WHERE BIZ_ID = RT30_1 AND MA01_8 = 'S' AND BIZ_NM LIKE '%'||#{SSPS_TYP_NM}||'%')
AND TBL.ACNT_NO LIKE #{ACNT_NO} || '%'
AND TBL.CS_NM LIKE '%'|| #{CS_NM} ||'%'
AND COALESCE(TBL.KFU_RRPR_STS_CD, TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD) = #{RPR_PRGRS_CCD}

SELECT /*+ PARALLEL(4)*/ B.ACNT_NO, -- 계좌번호 A.GNL_AC_NO, -- 계좌ID A.GDS_NO, -- 표준상품분류코드 ROWNUM AS DL_SQ, -- 거래일련번호 Fn_Cdinfo_Var('DT',A.DL_DT,'') AS DL_DT, -- 거래발생일시 TO_CHAR(TO_DATE(DL_DT || LPAD(TRIM(DL_TM),6,'0'),'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS DL_DT_TM, -- 거래발생일시 GET_CODE_NAME('M045',A.DL_TYP_CD) AS DL_TYP_NM, -- 거래종류명 GET_CODE_NAME('M046',A.DL_WY_CD) AS DL_WY_NM, -- 거래수단명 GET_CODE_NAME('M044',A.DL_CHNNL_CD) AS DL_CHNNL_NM, -- 거래채널명 A.CRNCY_CD, -- 거래통화 A.DL_AMT, -- 거래금액 A.USD_EXCH_AMT, -- 달러환산금액 A.CSH, -- 현금 A.CHCK_AMT, -- 수표 -- A.ETC_CHCK_AMT, -- 기타수표금액 A.TFND_RA, -- 정산금액 DECODE(nvl(trim(A.CRNCY_CD),''),'','',#{moneyType}, '', DECODE(NVL(trim(A.FCRNCY_DL_AMT),0),0,0,A.FCRNCY_DL_AMT) ) AS FCRNCY_DL_AMT, -- 외화거래금액 (SELECT NVL(DPRT_NM, '')FROM NIC41B WHERE DPRT_CD = A.HANDLNG_BRN_CD ) AS HANDLNG_BRN_NM, -- 취급지점 DECODE(FN_CDINFO_VAR('USER',TO_CHAR(A.L_HNDL_P_ENO),''),'',TO_CHAR(A.L_HNDL_P_ENO),FN_CDINFO_VAR('USER',TO_CHAR(A.L_HNDL_P_ENO),'')) AS HNDL_P_ENO -- 처리자사번 FROM NIC61B A, NIC17B B WHERE A.RNMCNO = B.RNMCNO AND A.GNL_AC_NO = B.GNL_AC_NO AND A.DL_DT >= #{startDate} AND A.DL_DT <= #{endDate}
AND A.RNMCNO = (SELECT RNMCNO FROM NIC01B WHERE CS_NO= #{CS_NO})
AND A.GNL_AC_NO = #{GNL_AC_NO}
ORDER BY A.GNL_AC_NO, /*A.GDS_NO,*/ A.DL_DT, LPAD(TRIM(A.DL_TM),6,'0')

SELECT A.DPRT_CD ,A.DPRT_NM ,MAX(CASE WHEN B.ROLE_ID = 3 THEN BR_CNT ELSE 0 END) AS BRANCH1 ,MAX(CASE WHEN B.ROLE_ID = 6 THEN BR_CNT ELSE 0 END) AS BRANCH2 ,MAX(CASE WHEN B.ROLE_ID = 11 THEN BR_CNT ELSE 0 END) AS BRANCH3 ,MAX(CASE WHEN B.ROLE_ID = 3 THEN DECODE(NVL(B.LAST_DATE, 'N'), 'N', 'N', TO_CHAR(SYSDATE, 'YYYYMMDD'), 'Y', 'N [' || FN_CDINFO_VAR('DT', B.LAST_DATE, '') || ']') ELSE 'N' END ) AS DATE1 ,MAX(CASE WHEN B.ROLE_ID = 6 THEN DECODE(NVL(B.LAST_DATE, 'N'), 'N', 'N', TO_CHAR(SYSDATE, 'YYYYMMDD'), 'Y', 'N [' || FN_CDINFO_VAR('DT', B.LAST_DATE, '') || ']') ELSE 'N' END) AS DATE2 ,MAX(CASE WHEN B.ROLE_ID = 11 THEN DECODE(NVL(B.LAST_DATE, 'N'), 'N', 'N', TO_CHAR(SYSDATE, 'YYYYMMDD'), 'Y', 'N [' || FN_CDINFO_VAR('DT', B.LAST_DATE, '') || ']') ELSE 'N' END ) AS DATE3 ,MAX(NVL(C.CNT, 0)) AS STR_CNT ,MAX(NVL(D.CNT, 0)) AS CTR_CNT ,MAX(NVL(C.CNT, 0) || DECODE(C.CNT, '', '', ' [' || FN_CDINFO_VAR('DT', C.MINDT, '') || ']')) AS STR_CNT1 ,MAX(NVL(D.CNT, 0) || DECODE(D.CNT, '', '', ' [' || FN_CDINFO_VAR('DT', D.MINDT, '') || ']')) AS CTR_CNT1 FROM NIC41B A ,(SELECT J.ROLE_ID ,K.DEP_DESC AS DEP_ID ,COUNT(*) AS BR_CNT ,MAX(SUBSTR(I.LAST_USE_DATE, 1, 8)) AS LAST_DATE FROM C_USER I ,C_USER_GROUP_ROLE J ,C_DEP_INFO K WHERE I.USER_ID = J.USER_ID AND I.DEP_ID = K.DEP_ID AND TO_CHAR(J.ROLE_ID) IN (3, 6, 11) GROUP BY J.ROLE_ID ,K.DEP_DESC ) B ,(SELECT M.MN_DL_BRN_CD AS DEP_ID ,COUNT(*) AS CNT ,MIN(L.SSPS_DL_CRT_DT) AS MINDT FROM NIC66B L ,NIC73B M WHERE L.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND L.SSPS_DL_CRT_DT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM') || '01' AND TO_CHAR(SYSDATE, 'YYYYMMDD') AND L.RPR_PRGRS_CCD NOT IN (9, 99) AND L.SSPS_DL_CRT_DT = M.SSPS_DL_CRT_DT AND L.SSPS_DL_ID = M.SSPS_DL_ID AND M.RPR_PRGRS_CCD = 0 GROUP BY M.MN_DL_BRN_CD ) C ,(SELECT O.MN_DL_BRN_CD AS DEP_ID ,COUNT(*) AS CNT ,MIN(N.SSPS_DL_CRT_DT) AS MINDT FROM NIC66B N ,NIC73B O WHERE N.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND N.SSPS_DL_CRT_DT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM') || '01' AND TO_CHAR(SYSDATE, 'YYYYMMDD') AND N.RPR_PRGRS_CCD NOT IN (9, 99) AND N.SSPS_DL_CRT_DT = O.SSPS_DL_CRT_DT AND N.SSPS_DL_ID = O.SSPS_DL_ID AND O.RPR_PRGRS_CCD = 0 GROUP BY O.MN_DL_BRN_CD ) D WHERE ( ( A.DPRT_CD BETWEEN #{BRANCH_RANGE1} AND #{BRANCH_RANGE2} AND A.DPRT_CD NOT IN
#{BRANCH_EX_NOT_LIST}
) OR A.DPRT_CD IN
#{BRANCH_EX_LIST}
) AND ( 1 = #{branchCodeYN} OR A.DPRT_CD = #{branchCode} ) AND A.DPRT_CD = B.DEP_ID(+) AND A.DPRT_CD = C.DEP_ID(+) AND A.DPRT_CD = D.DEP_ID(+) GROUP BY A.DPRT_CD ,A.DPRT_NM ORDER BY A.DPRT_NM

SELECT GET_CODE_NAME('M056', '01') AS RELATIONROLE ,'01' AS RELATIONROLECODE -- 거래역할코드 ,A.INDV_CORP_CCD AS INDV_CORP_CCD -- 개인법인구분코드 ,NVL(DECODE(TRIM(A.DL_P_RNM_NO_CCD), '04', (SELECT I.DL_P_PSPT_NO FROM NIC78B I WHERE I.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND I.DL_P_RNMCNO = A.DL_P_RNMCNO ), TRIM(A.RNMCNO) ), TRIM(A.RNMCNO) ) AS REALNUMBERCONFIRM -- 의심거래자 실명번호 ,TRIM(A.RNMCNO) AS REALNUMBER -- 의심거래자 실명 구분코드 ,TRIM(A.DL_P_RNM_NO_CCD) AS REALNUMBERCODE -- 의심거래자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(A.DL_P_RNM_NO_CCD)) AS REALNUMBERCODENAME ,'' INSURELDESC -- 의심거래자 거래자와의 관계 ,(SELECT J.CS_CI_NO FROM NIC01B J WHERE J.RNMCNO = A.DL_P_RNMCNO AND J.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS CINUMBER -- CI번호(2020.06.02 추가) ,'' PARREALNUMBER -- 관계구분 ,C.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,A.DL_P_RNMCNO AS P_RNMCNO -- PARAMETER로 설정할 RNMCNO FROM NIC70B A ,NIC66B B ,NIC75B C WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = B.DL_P_RNMCNO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID} AND C.GNL_AC_NO = #{GNL_AC_NO} AND C.GDS_NO = #{GDS_NO} AND C.DL_DT = #{DL_DT} AND C.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '02') AS RELATIONROLE ,'02' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(A.RPRST_P_RNMCNO) AS REALNUMBERCONFIRM -- 의심거래자 실명번호 ,TRIM(A.RPRST_P_RNMCNO) AS REALNUMBER -- 의심거래자 실명번호 ,TRIM(A.RPRST_P_RNM_CNFR_CCD) AS REALNUMBERCODE -- 의심거래자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(A.RPRST_P_RNM_CNFR_CCD)) AS REALNUMBERCODENAME ,'' AS INSURELDESC -- 의심거래자 거래자와의 관계 ,(SELECT I.CS_CI_NO FROM NIC01B I WHERE I.RNMCNO = A.RNMCNO AND I.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS CINUMBER -- CI번호(2020.06.02 추가) ,A.RNMCNO AS PARREALNUMBER -- 관계구분 ,C.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,A.RNMCNO AS P_RNMCNO -- PARAMETER로 설정할 RNMCNO FROM ( SELECT A.* FROM NIC03B_1 A , ( SELECT RNMCNO , MIN(RPRST_P_SQ) AS RPRST_P_SQ FROM NIC03B_1 WHERE RPR_TGT_YN = 'Y' GROUP BY RNMCNO ) B WHERE A.RNMCNO = B.RNMCNO AND A.RPRST_P_SQ = B.RPRST_P_SQ ) A ,NIC66B B ,NIC75B C WHERE A.RNMCNO = B.DL_P_RNMCNO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID} AND C.GNL_AC_NO = #{GNL_AC_NO} AND C.GDS_NO = #{GDS_NO} AND C.DL_DT = #{DL_DT} AND C.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '03') AS RELATIONROLE ,'03' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(A.PRXY_RNMCNO) AS REALNUMBERCONFIRM -- 거래대리인 실명번호 ,TRIM(A.PRXY_RNMCNO) AS REALNUMBER -- 거래대리인 실명번호 ,TRIM(A.PRXY_RNM_NO_CCD) AS REALNUMBERCODE -- 거래대리인 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(A.PRXY_RNM_NO_CCD)) AS REALNUMBERCODENAME ,GET_CODE_NAME('M042', TRIM(A.AC_OWN_P_RLTNS_CD)) AS INSURELDESC ,DECODE(A.PRXY_RNM_NO_CCD, '14', A.PRXY_RNMCNO, '') AS CINUMBER -- CI번호(2020.06.02 추가) ,'' AS PARREALNUMBER ,A.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,'' AS P_RNMCNO -- PARAMETER로 설정할 RNMCNO FROM NIC98B A ,NIC75B B WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND A.GDS_NO = B.GDS_NO AND A.DL_DT = B.DL_DT AND A.DL_SQ = B.DL_SQ AND TRIM(A.PRXY_RNMCNO) IS NOT NULL AND TRIM(A.PRXY_RNM_NO_CCD) IS NOT NULL AND B.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND B.SSPS_DL_ID = #{SSPS_DL_ID} AND B.GNL_AC_NO = #{GNL_AC_NO} AND B.GDS_NO = #{GDS_NO} AND B.DL_DT = #{DL_DT} AND B.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '08') AS RELATIONROLE ,'08' AS RELATIONROLECODE ,C.INDV_CORP_CCD AS INDV_CORP_CCD ,NVL(DECODE(TRIM(C.DL_P_RNM_NO_CCD), '04', (SELECT I.DL_P_PSPT_NO FROM NIC78B I WHERE I.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND I.DL_P_RNMCNO = C.DL_P_RNMCNO ), TRIM(C.RNMCNO) ), TRIM(C.RNMCNO) ) AS REALNUMBERCONFIRM ,TRIM(C.RNMCNO) AS REALNUMBER ,TRIM(C.DL_P_RNM_NO_CCD) AS REALNUMBERCODE ,GET_CODE_NAME('M002', TRIM(C.DL_P_RNM_NO_CCD)) AS REALNUMBERCODENAME ,'' AS INSURELDESC ,(SELECT J.CS_CI_NO FROM NIC01B J WHERE J.RNMCNO = C.DL_P_RNMCNO AND J.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS CINUMBER ,'' AS PARREALNUMBER ,A.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,C.DL_P_RNMCNO AS P_RNMCNO -- PARAMETER로 설정할 RNMCNO FROM NIC75B A ,NIC71B B ,NIC70B C WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND A.GDS_NO = B.GDS_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.RNMCNO = C.DL_P_RNMCNO AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} AND A.GNL_AC_NO = #{GNL_AC_NO} AND A.GDS_NO = #{GDS_NO} AND A.DL_DT = #{DL_DT} AND A.DL_SQ = #{DL_SQ}
