SELECT GET_CODE_NAME('M056', '11') AS RELATIONROLE ,'11' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(A.RNMCNO) AS REALNUMBER -- 의심거래자 실명번호 ,NVL(DECODE(TRIM(D.RNM_CNFR_CCD), '04', E.PSPT_NO, TRIM(A.RNMCNO)), TRIM(A.RNMCNO)) AS REALNUMBERCONFIRM -- 의심거래자 실명번호 ,TRIM(D.RNM_CNFR_CCD) AS REALNUMBERCODE -- 의심거래자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(D.RNM_CNFR_CCD)) AS REALNUMBERCODENAME ,'' AS INSURELDESC -- 의심거래자 거래자와의 관계 ,DECODE(D.RNM_CNFR_CCD, '14', D.CS_CI_NO, '') AS CINUMBER -- CI번호(2020.06.02 추가) ,'' AS PARREALNUMBER -- 관계구분 ,A.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,A.RNMCNO AS P_RNMCNO -- PARAMETER로 설정할 RNMCNO FROM NIC17B A ,NIC83B B ,NIC75B C ,NIC01B D ,NIC02B E WHERE A.GNL_AC_NO = B.CPRTY_TRSNS_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.DL_DT = C.DL_DT AND B.DL_SQ = C.DL_SQ AND A.RNMCNO = D.RNMCNO AND D.RNMCNO = E.RNMCNO (+) AND TRIM(A.RNMCNO ) IS NOT NULL AND TRIM(D.RNM_CNFR_CCD) IS NOT NULL AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID} AND C.GNL_AC_NO = #{GNL_AC_NO} AND C.GDS_NO = #{GDS_NO} AND C.DL_DT = #{DL_DT} AND C.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '12') AS RELATIONROLE ,'12' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(A.PRXY_RNMCNO) AS REALNUMBERCONFIRM -- 계좌개설대리인 실명번호 ,TRIM(A.PRXY_RNMCNO) AS REALNUMBER -- 계좌개설대리인 실명번호 ,TRIM(A.PRXY_RNM_NO_CCD) AS REALNUMBERCODE -- 계좌개설대리인 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(A.PRXY_RNM_NO_CCD)) AS REALNUMBERCODENAME ,GET_CODE_NAME('M042', TRIM(A.PRXY_RLTNS_CD)) AS INSURELDESC ,DECODE(A.PRXY_RNM_NO_CCD, '14', A.PRXY_RNMCNO, '') AS CINUMBER -- CI번호(2020.06.02 추가) ,'' AS PARREALNUMBER -- 관계구분 ,A.GNL_AC_NO AS CHK_ACCOUNTNUMBER -- USER생성 시 체크를 위한 계좌 추가(2024.10.24) ,'' AS P_RNMCNO FROM NIC18B A ,NIC83B B ,NIC75B C WHERE A.GNL_AC_NO = B.CPRTY_TRSNS_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.DL_DT = C.DL_DT AND B.DL_SQ = C.DL_SQ AND TRIM(A.PRXY_RNMCNO) IS NOT NULL AND TRIM(A.PRXY_RNM_NO_CCD) IS NOT NULL AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID} AND C.GNL_AC_NO = #{GNL_AC_NO} AND C.GDS_NO = #{GDS_NO} AND C.DL_DT = #{DL_DT} AND C.DL_SQ = #{DL_SQ}

SELECT TRIM(B.TRNS_OGN_CD) AS ORGNAMECODE ,TRIM(B.RPR_OGN_NM) AS ORGNAME ,TRIM(A.GNL_AC_NO) AS ACCOUNTNUMBER ,'01' AS ACCOUNTROLECODE ,GET_CODE_NAME('M057', '01') AS ACCOUNTROLE FROM NIC75B A ,NIC86B B WHERE A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} AND A.GNL_AC_NO = #{GNL_AC_NO} AND A.DL_DT = #{DL_DT} AND A.DL_SQ = #{DL_SQ}
UNION
SELECT TRIM(C.TRNS_OGN_CD) AS ORGNAMECODE ,TRIM(C.RPR_OGN_NM) AS ORGNAME ,TRIM(D.GNL_AC_NO) AS ACCOUNTNUMBER ,'02' AS ACCOUNTROLECODE ,GET_CODE_NAME('M057', '02') AS ACCOUNTROLE FROM NIC75B A ,NIC83B B ,NIC86B C ,NIC17B D WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND A.DL_DT = B.DL_DT AND A.DL_SQ = B.DL_SQ AND B.CPRTY_TRSNS_OGN_CD = C.TRNS_OGN_CD AND B.CPRTY_TRSNS_AC_NO = D.GNL_AC_NO AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} AND A.GNL_AC_NO = #{GNL_AC_NO} AND A.DL_DT = #{DL_DT} AND A.DL_SQ = #{DL_SQ}

SELECT B.RNMCNO AS REALNUMBER ,C.DL_P_HSE_TEL_NO AS PHONE -- 자택전화번호 ,C.DL_P_MBL_TEL_NO AS PHONEHANDPHONE -- 휴대전화번호 ,NVL(NVL(C.DL_P_HSE_ADDR, C.DL_P_WP_ADDR), 'UNKNOWN') AS ADDRESS -- 주소(자택) ,NVL(REPLACE(NVL(C.DL_P_HSE_PST_NO, DL_P_WP_PST_NO), '-', ''), '999999') AS ADDRESSZIPCODE -- 우편번호(법인_단체의 경우, 사업체 우편번호_주소-본점에 해당) ,NVL(C.DL_P_WP_ADDR, 'UNKNOWN') AS ADDRESSCOMPANY -- 주소(직장) ,NVL(REPLACE(C.DL_P_WP_PST_NO, '-', ''), '999999') AS ADDRESSCOMPANYZIPCODE -- 우편번호 ,C.DL_P_WP_TEL_NO AS PHONECOMPANY -- 직장전화번호 ,C.RNM_CMBNTN_NO AS MIXEDREALNUMBER -- 실명조합번호
,CASE WHEN NVL(C.DL_P_BRTDY, '0') < 19000101 THEN NULL ELSE C.DL_P_BRTDY END AS BIRTHDAY -- 생년월일
,C.RPRST_P_NM AS CEONAME -- 대표자명 ,C.RPRST_P_RNM_NO AS CEOREALNUMBER -- 대표자실명번호 ,NVL(SUBSTR(C.IND_TYP_CD, '2', '5'), 'ZZZZZ') AS KSICCODE -- 업종코드 ,NVL(GET_CODE_NAME('M008', C.IND_TYP_CD), 'UNKNOWN') AS KSIC -- 업종코드명 -- ,GET_CODE_NAME('M013', C.DL_P_SEX_CD) AS GENDER -- 성별 -- ,C.DL_P_SEX_CD AS GENDERCODE -- 성별코드 ,B.IDNO AS IDNO ,GET_CODE_NAME('M013', CASE WHEN C.DL_P_SEX_CD NOT IN ('1', '2') OR C.DL_P_SEX_CD IS NULL THEN CASE WHEN SUBSTR(B.IDNO, 7, 1) IN ('0', '2', '4', '6', '8') THEN '2'-- 여성 WHEN SUBSTR(B.IDNO, 7, 1) IN ('1', '3', '5', '7', '9') THEN '1'-- 남성 END ELSE C.DL_P_SEX_CD END ) AS GENDER ,CASE WHEN C.DL_P_SEX_CD NOT IN ('1', '2') OR C.DL_P_SEX_CD IS NULL THEN CASE WHEN SUBSTR(B.IDNO, 7, 1) IN ('0', '2', '4', '6', '8') THEN '2' -- 여성 WHEN SUBSTR(B.IDNO, 7, 1) IN ('1', '3', '5', '7', '9') THEN '1' -- 남성 END ELSE C.DL_P_SEX_CD END AS GENDERCODE ,TRIM(C.DL_P_PSPT_NO) AS PASSPORTNO -- 여권번호 ,C.WP_NM AS COMPANY -- 직장명 ,C.DTY_DPRT_NM AS DEPTNAME -- 근무부점명 ,C.CS_PSTN_CD AS POSITION -- 직위 ,GET_CODE_NAME('M059', C.OCPTN_CCD) AS OCCUPATIONTYPE -- 직업구분 ,C.OCPTN_CCD AS OCCUPATIONTYPECODE -- 직업구분코드 ,'' AS BIZNO -- 직업내용 ,DECODE(C.LG_AMT_ASTS_F, 'Y', 'Y', 'N') AS ISHIGHASSET -- 고액자산여부 ,(SELECT I.INDV_CORP_CCD FROM NIC01B I WHERE I.RNMCNO = A.DL_P_RNMCNO ) AS INDV_CORP_CCD -- 개인법인구분코드 FROM NIC66B A -- 혐의거래추출내역_NIC66B ,(SELECT J.* ,J.DL_P_RNMCNO AS IDNO FROM NIC70B J ) B --혐의거래고객공통정보_NIC70B ,NIC78B C -- 혐의거래고객개인정보_NIC78B WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = B.DL_P_RNMCNO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.DL_P_RNMCNO = C.DL_P_RNMCNO AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} AND A.DL_P_RNMCNO = #{RNMCNO}

SELECT T1.* FROM (SELECT T2.ORGNAME --금융기관명 ,T2.ORGNAMECODE --금융기관코드 ,T2.BRANCHOFFICE --지점명 ,T2.BRANCHOFFICECODE --지점코드 ,T2.BRANCHOFFICEZIPCODE --지점 우편번호 ,T2.ACCOUNTNUMBER --계좌번호 ,T2.REGDATE --계좌개설일 ,T2.ACCOUNTUSER --계좌주실명번호 ,T2.ACCOUNTUSERCODE --실명번호구분코드 ,T2.ACCOUNTUSERCINUMBER --계좌주CI번호 ,T2.AGENTFLAG --대리인존재여부 ,DECODE(T2.AGENTFLAG, 'Y', T2.AGENTUSER, '') AS AGENTUSER --대리인실명번호 ,DECODE(T2.AGENTFLAG, 'Y', T2.AGENTUSERCODE, '') AS AGENTUSERCODE --실명번호구분코드 ,T2.AGENTUSERCINUMBER --대리인CI번호 ,T2.ACCOUNTOPENPURPOSE --계좌개설목적 ,T2.ACCOUNTOPENPURPOSECODE --계좌개설목적코드 ,ROW_NUMBER() OVER(PARTITION BY T2.BRANCHOFFICECODE, T2.BRANCHOFFICEZIPCODE, T2.ACCOUNTNUMBER, T2.REGDATE, T2.ACCOUNTUSER ORDER BY T2.BRANCHOFFICECODE, T2.BRANCHOFFICEZIPCODE, T2.ACCOUNTNUMBER, T2.REGDATE) AS RNUM FROM (SELECT A.RPR_OGN_NM AS ORGNAME --금융기관명 ,A.TRNS_OGN_CD AS ORGNAMECODE --금융기관코드* ,DECODE(NVL((SELECT I.KFB_DPRT_CD FROM NIC41B I WHERE I.DPRT_CD = B.GDS_OPN_BRN_CD ), 'UNKNOWN' ),'UNKNOWN', 'UNKNOWN', NVL(B.AC_OPN_BRN_NM, 'UNKNOWN') ) AS BRANCHOFFICE --지점명 ,NVL((SELECT SUBSTR(NVL(J.KFB_DPRT_CD, J.DPRT_CD), 0, 7) FROM NIC41B J WHERE J.DPRT_CD = B.GDS_OPN_BRN_CD ) , 'ZZZZZZZ' ) AS BRANCHOFFICECODE --지점코드 char 7 ,NVL((SELECT RPAD(TRIM(K.DPRT_POST_NO), 6, 0) FROM NIC41B K WHERE K.DPRT_CD = B.GDS_OPN_BRN_CD ), '999999' ) AS BRANCHOFFICEZIPCODE --지점 우편번호 ,B.GNL_AC_NO AS ACCOUNTNUMBER --계좌번호 ,NVL(B.GDS_OPN_DT, TO_CHAR(SYSDATE, 'YYYYMMDD')) AS REGDATE --계좌개설일 ,NVL(DECODE(TRIM(D.DL_P_RNM_NO_CCD), '04', (SELECT L.DL_P_PSPT_NO FROM NIC78B L WHERE L.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT AND L.DL_P_RNMCNO = D.DL_P_RNMCNO ), TRIM(D.RNMCNO) ), TRIM(D.RNMCNO) ) AS ACCOUNTUSER --계좌주실명번호 ,D.DL_P_RNM_NO_CCD AS ACCOUNTUSERCODE --실명번호구분코드* ,(SELECT M.CS_CI_NO FROM NIC01B M WHERE M.RNMCNO = D.DL_P_RNMCNO AND M.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS ACCOUNTUSERCINUMBER --계좌주CI번호(2020.07.23 추가) ,DECODE(NVL(B.AC_OPN_PRXY_F, 'N'), 'Y', 'Y', 'N') AS AGENTFLAG --대리인존재여부 ,NVL(E.PRXY_RNMCNO, '999999999999999') AS AGENTUSER --대리인실명번호 ,NVL(E.PRXY_RNM_NO_CCD, 'ZZ') AS AGENTUSERCODE --실명번호구분코드* ,(SELECT N.CS_CI_NO FROM NIC01B N WHERE N.RNMCNO = E.PRXY_RNMCNO AND N.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS AGENTUSERCINUMBER --대리인CI번호(2020.07.23 추가) ,GET_CODE_NAME('M038', NVL(B.AC_OPN_OBJ_CCD, '99')) AS ACCOUNTOPENPURPOSE --계좌개설목적 ,NVL(B.AC_OPN_OBJ_CCD, '99') AS ACCOUNTOPENPURPOSECODE --계좌개설목적코드* FROM NIC86B A ,NIC71B B ,NIC66B C ,NIC70B D ,NIC72B E WHERE C.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND C.SSPS_DL_ID = B.SSPS_DL_ID AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT AND C.DL_P_RNMCNO = D.DL_P_RNMCNO AND B.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = E.SSPS_DL_ID(+) AND B.GNL_AC_NO = E.GNL_AC_NO(+) AND B.GDS_NO = E.GDS_NO(+) AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID}
UNION ALL
SELECT F.RPR_OGN_NM AS ORGNAME --금융기관명 ,F.TRNS_OGN_CD AS ORGNAMECODE --금융기관코드* ,NVL((SELECT I.DPRT_NM FROM NIC41B I WHERE I.DPRT_CD = D.OPN_BRN_CD ), 'UNKNOWN' ) AS BRANCHOFFICE --지점명 ,NVL((SELECT SUBSTR(NVL(J.KFB_DPRT_CD, J.DPRT_CD), 0, 7) FROM NIC41B J WHERE J.DPRT_CD = D.OPN_BRN_CD ), 'ZZZZZZZ' ) AS BRANCHOFFICECODE --지점코드 ,NVL((SELECT RPAD(TRIM(K.DPRT_POST_NO), 6, 0) FROM NIC41B K WHERE K.DPRT_CD = D.OPN_BRN_CD ), '999999' ) AS BRANCHOFFICEZIPCODE --우편번호* ,C.CPRTY_TRSNS_AC_NO AS ACCOUNTNUMBER --계좌번호 ,NVL(D.AC_OPN_DT, '99991231') AS REGDATE --계좌개설일 ,D.RNMCNO AS ACCOUNTUSER --계좌주실명번호 ,TRIM(G.RNM_CNFR_CCD) AS ACCOUNTUSERCODE --실명번호구분코드* ,(SELECT L.CS_CI_NO FROM NIC01B L WHERE L.RNMCNO = D.RNMCNO AND L.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS ACCOUNTUSERCINUMBER --계좌주CI번호(2020.07.23 추가) ,DECODE((SELECT COUNT(M.PRXY_NM) FROM NIC18B M WHERE M.GNL_AC_NO = D.GNL_AC_NO ), 0, 'N', 'Y' ) AS AGENTFLAG --대리인존재여부 ,NVL(E.PRXY_RNMCNO, '999999999999999') AS AGENTUSER --대리인실명번호 ,NVL(E.PRXY_RNM_NO_CCD, 'ZZ') AS AGENTUSERCODE --실명번호구분코드* ,(SELECT N.CS_CI_NO FROM NIC01B N WHERE N.RNMCNO = E.PRXY_RNMCNO AND N.RNM_CNFR_CCD = '14' AND ROWNUM = 1 ) AS AGENTUSERCINUMBER --대리인CI번호(2020.07.23 추가) ,GET_CODE_NAME('M038', '99') AS ACCOUNTOPENPURPOSE --계좌개설목적 ,'99' AS ACCOUNTOPENPURPOSECODE --계좌개설목적코드* FROM NIC66B A ,NIC75B B ,NIC83B C ,NIC17B D ,NIC18B E ,NIC86B F ,NIC01B G WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.DL_DT = C.DL_DT AND B.DL_SQ = C.DL_SQ AND C.CPRTY_TRSNS_AC_NO = D.GNL_AC_NO AND D.RNMCNO IS NOT NULL AND D.GNL_AC_NO = E.GNL_AC_NO(+) AND D.RNMCNO = G.RNMCNO AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) T2 ) T1 WHERE T1.RNUM = 1

/* 문서시작 */ SELECT 'CTRSTART' AS CTR00 -- 0 문서시작 ,A.RPR_CCD AS CTR01 -- 1 메시지타입
/* 표제부에 관한 정보 */ ,TRIM(A.RPR_DOC_NO_DL_YR || '-' || LPAD(A.RPR_DOC_NO_FNL_SQ, 8, '0')) AS CTR02 -- 2 문서번호(YYYY ,TO_CHAR(SYSDATE, 'YYYYMMDD') AS CTR03 -- 3 보고일자 ,CASE WHEN A.RPR_CCD NOT IN ('01', '99') THEN TRIM(B.RPR_DOC_NO_DL_YR || '-' || LPAD(B.RPR_DOC_NO_FNL_SQ, 8, '0')) ELSE '' END AS CTR04 -- 4 종전문서번호 ,LPAD(A.RNM_PR_DL_SQ, 7, '0') || '/' || (SELECT LPAD(COUNT(*), 7, '0') FROM NIC66B X1 WHERE X1.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X1.DL_P_RNMCNO = A.DL_P_RNMCNO AND X1.SSPS_DL_CRT_CCD = A.SSPS_DL_CRT_CCD AND X1.OK_CCD != 2 ) AS CTR05 --5 거래순번 ,TRIM(A.RPR_DOC_NO_DL_YR || '-' || LPAD(A.DOC_SQ, 8, '0')) AS CTR06 -- 6 기본문서번호 /* I. 보고기관에 관한 정보 */ ,N.RPR_OGN_NM AS CTR07 -- 7 보고기관명 ,N.TRNS_OGN_CD AS CTR08 -- 8 보고기관코드 ,N.RPR_RSPSB_P_NM AS CTR09 -- 9 보고책임자명 ,N.RPR_CHRG_P_NM AS CTR10 -- 10 보고담당자명 ,N.RPR_CHRG_P_TEL_NO AS CTR11 -- 11 보고담당자전화번호
/* II 거래자에 관한 정보 */ /* II-1 공통사항 */ --12, 13, 14항목을 반드시 기입. 단, 20번 항목이 기입될 경우 13, 14항목 선택항목 ,C.DL_P_NM AS CTR12 -- 12 거래자명 ,C.DL_P_RNM_NO_CCD AS CTR13 -- 13 거래자실명번호구분 ,C.RNMCNO AS CTR14 -- 14 거래자실명번호 ,C.DL_P_NTNLT_CD AS CTR15 -- 15 거래자국적코드 ,GET_CODE_NAME('M004', C.DL_P_NTNLT_CD) AS CTR16 -- 16 거래자국적명
/* II-2 개인인 경우 */ --(13번 거래자 실명번호 구분 중 주민등록번호(개인),외국인등록번호, 여권번호,국내거소신고번호, 기타일경우 기입) --(20번 실명조합번호는 15번 국적에서 코드가 KR이 아닐 경우 기입) ,REPLACE(NVL(TRIM(D.DL_P_HSE_PST_NO), TRIM(D.DL_P_WP_PST_NO)), '-', '') AS CTR17 -- 17 거래자우편번호 ,NVL(D.DL_P_HSE_ADDR, D.DL_P_WP_ADDR) AS CTR18 -- 18 거래자주소 ,D.DL_P_BRTDY AS CTR19 -- 19 거래자생년월일 ,CASE WHEN D.DL_P_SEX_CD IN ('1', '3') THEN '3' WHEN D.DL_P_SEX_CD IN ('2', '4') THEN '4' ELSE '' END AS CTR20 -- 20 성별 ,NVL(D.DL_P_HSE_TEL_NO, D.DL_P_MBL_TEL_NO) AS CTR21 -- 21 거래자전화번호 ,D.RNM_CMBNTN_NO AS CTR22 -- 22 실명조합번호 ,D.DL_P_PSPT_NO AS CTR23 -- 23 여권번호 ,CASE WHEN D.OCPTN_CCD = '91' OR D.OCPTN_CCD IS NULL THEN '99' ELSE D.OCPTN_CCD END AS CTR24 -- 24 거래자직업구분 ,D.WP_NM AS CTR25 -- 25 거래자직장(회사)명 ,SUBSTR(D.IND_TYP_CD, 2, LENGTH(D.IND_TYP_CD)) AS CTR26 -- 26 거래자직장업종코드 ,'' AS CTR27 -- 27 거래자직장사업자번호
/* II-3 법인인 경우 */ --13번 거래자 실명번호 구분 중 주민등록번호(기타단체), 사업자등록번호, 투자등록번호, 고유번호/납세번호, 기타일 경우 기입되며, 모두 선택기재사항 ,M.RPRST_P_NM AS CTR28 -- 28 대표자명 ,M.RPRST_P_RNM_CNFR_CCD AS CTR29 -- 29 대표자실명번호구분 ,M.RPRST_P_RNMCNO AS CTR30 -- 30 대표자실명번호 ,M.RPRST_P_NTNLT AS CTR31 -- 31 대표자국적코드 ,GET_CODE_NAME('M004', M.RPRST_P_NTNLT) AS CTR32 -- 32 대표자국적명 ,E.BSNSG_FNDTN_DT AS CTR33 -- 33 사업체설립일 --업종코드 앞에 안자르게 수정 20190725 --,SUBSTR(E.IND_TYP_CD, 2, LENGTH(E.IND_TYP_CD)) AS CTR34 -- 34 업종코드 --,E.IND_TYP_CD AS CTR34 --34 업종코드 --업종코드 앞에 자르도록 다시 수정 20190819 ,CASE WHEN SUBSTR(E.IND_TYP_CD, 0, 1) = 'A' THEN SUBSTR(E.IND_TYP_CD, 2, LENGTH(E.IND_TYP_CD)) ELSE E.IND_TYP_CD END AS CTR34 -- 34 업종코드 옵션 05 /5자리 KSIC코드 ,E.CORP_RGST_NO AS CTR35 -- 35 법인등록번호 ,TRIM(E.HD_BRNCH_PST_NO) AS CTR36 -- 36 사업체본점우편번호 ,TRIM(E.BSNS_CMPNY_PST_NO) AS CTR37 -- 37 사업체사업장우편번호 ,E.HD_BRNCH_ADDR AS CTR38 -- 38 사업체본점주소 ,E.BSNS_CMPNY_ADDR AS CTR39 -- 39 사업체사업장주소 ,E.HD_BRNCH_TEL_NO AS CTR40 -- 40 사업체본점전화번호 ,E.BSNS_CMPNY_TEL_NO AS CTR41 -- 41 사업체사업장전화번호
/* III 현금거래 내역에 관한 정보 */ /* III-1 공통사항 */ --전체 필수항목 ,G.DL_DT || LPAD(DL_TM, 6, '0') AS CTR42 -- 42 거래발생일시 ,G.HANDLNG_BRN_NM AS CTR43 -- 43 거래영업점명 ,TRIM(G.HANDLNG_BRN_PST_NO) AS CTR44 -- 44 거래영업점우편번호
,G.DL_CHNNL_CD AS CTR45_TEMP --45 거래채널 ,DECODE(G.DL_CHNNL_CD, '01', '01', '02', '02', '99') AS CTR45 -- 45 거래채널(20.07.30 수정)
,'01' AS CTR46 -- 46 거래수단 ,G.CSH AS CTR47 -- 47 거래금액 ,G.CTR_DL_KND_CD AS CTR48 -- 48 거래종류 ,DECODE(NVL(H.SSPS_DL_CRT_DT, ''), '', '2', '1') AS CTR49 -- 49 거래대리인존재여부 ,H.PRXY_NM AS CTR50 -- 50 거래대리인명 ,DECODE(DECODE(NVL(H.SSPS_DL_CRT_DT, ''), '', '2', '1'), '2', '',NVL(H.PRXY_RNM_NO_CCD, '99')) AS CTR51 -- 51 거래대리인실명번호구분 ,H.PRXY_RNMCNO AS CTR52 -- 52 거래대리인실명번호 ,H.PRXY_TEL_NO AS CTR53 -- 53 거래대리인전화번호 ,H.PRXY_NTNLT_CD AS CTR54 -- 54 거래대리인국적코드 ,GET_CODE_NAME('M004', H.PRXY_NTNLT_CD) AS CTR55 -- 55 거래대리인국적명
,H.AC_OWN_P_RLTNS_CD AS CTR56_TEMP -- 56 거래대리인거래자와관계코드 ,CASE H.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE H.AC_OWN_P_RLTNS_CD END AS CTR56 -- 56 거래대리인거래자와관계코드 ,GET_CODE_NAME('M070', CASE H.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE H.AC_OWN_P_RLTNS_CD END) AS CTR57 -- 57 거래대리인거래자와 관계명
/* III-2 계좌거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 11.계좌+지급,12계좌+영수 일 경우 모두 필수 ,L.GNL_AC_NO AS CTR58 -- 58 관련계좌번호
,L.AC_OPN_BRN_NM AS CTR59 -- 59 계좌개설점 ,TRIM(L.AC_OPN_BRN_PST_NO) AS CTR60 -- 60 계좌개설점우편번호 ,L.GDS_OPN_DT AS CTR61 -- 61 계좌개설일 ,CASE WHEN G.CTR_DL_KND_CD IN ('11', '12') THEN DECODE(NVL(I.PRXY_NM, ''), '', '2', '1') ELSE '' END AS CTR62 -- 62 계좌대리인존재여부 ,I.PRXY_NM AS CTR63 -- 63 계좌대리인명 ,DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11', '12') THEN DECODE(NVL(I.PRXY_NM, ''), '', '2', '1') ELSE '' END), 2, '', I.PRXY_RNM_NO_CCD ) AS CTR64 -- 64 계좌대리인실명번호구분 ,I.PRXY_RNMCNO AS CTR65 -- 65 계좌대리인실명번호 ,I.PRXY_TEL_NO AS CTR66 -- 66 계좌대리인전화번호 ,I.PRXY_NTNLT_CD AS CTR67 -- 67 계좌대리인국적코드 ,GET_CODE_NAME('M004', I.PRXY_NTNLT_CD) AS CTR68 -- 68 계좌대리인국적명 ,I.AC_OWN_P_RLTNS_CD AS CTR69_TEMP --69 계좌대리인관계코드 ,DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11', '12') THEN DECODE(NVL(I.PRXY_NM, ''), '', '2', '1') ELSE '' END), 2, '', CASE I.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE I.AC_OWN_P_RLTNS_CD END ) AS CTR69 -- 69 계좌대리인관계코드
,GET_CODE_NAME('M070', DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11', '12') THEN DECODE(NVL(I.PRXY_NM, ''), '', '2', '1') ELSE '' END ), 2, '', CASE I.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE I.AC_OWN_P_RLTNS_CD END ) ) AS CTR70 -- 70 계좌대리인관계명
/* III-3 유가증권거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 25.비계좌(유가증권)+지급, 26.비계좌(유가증권)+영수일경우 모두필수이나, --40. 관련유가증권종류 코드값이 11.선불카드일 경우 33,33-1 선택항목 ,J.CHCK_KND_CD AS CTR71 -- 71 관련유가증권종류 ,J.CHCK_STRT_NO AS CTR72 -- 72 관련유가증권시작번호 ,J.CHCK_END_NO AS CTR73 -- 73 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ --40번 유가증권종류에서 코드값이 05.자기앞수표일경우 필수 항목 ,J.BNK_NM AS CTR74 --74 현금지급은행명 ,J.BNK_CD AS CTR75 --75 현금지급은행기관코드 ,J.BRN_NM AS CTR76 --76 현금지급영업점명 ,TRIM(J.BRN_PST_NO) AS CTR77 --77 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ --35번 거래종류항목코드 중 22.비계좌(송금)+영수일 경우 필수 항목 ,K.CPRTY_TRSNS_AC_NO AS CTR78 -- 78 수취인계좌번호 ,K.CPRTY_TRSNS_FOGN_NM AS CTR79 -- 79 수취금융기관명 ,K.CPRTY_TRSNS_OGN_CD AS CTR80 -- 80 수취금융기관코드 ,K.CPRTY_TRSNS_AC_NM AS CTR81 -- 81 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ --선택사항이며, 01번 메시지 타입 코드값이 02,03,97,98일경우 필수 항목 ,CASE WHEN A.RPR_CCD NOT IN ('01', '93') THEN (SELECT X2.CNTNT FROM NIC66B_W X2 WHERE (X2.INST_ID, X2.WORK_ID) IN (SELECT Y2.INST_ID ,MIN(Y2.WORK_ID) FROM NIC66B_W Y2 WHERE Y2.INST_ID = A.INST_ID GROUP BY Y2.INST_ID ) ) ELSE '' END AS CTR82 -- 82 정정,취소 ,'CTREND' AS CTR83 -- 83 문서끝 ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,G.GNL_AC_NO --종합계좌번호 ,G.GDS_NO --상품번호 ,G.DL_DT --거래일자 ,G.DL_SQ --거래일련번호 ,K.CPRTY_TRSNS_AC_RNM_NO ,K.CPRTY_TRSNS_AC_RNM_CNFR_CCD ,K.CPRTY_TRSNS_AC_OWN_NTN_CD ,A.DL_P_RNMCNO FROM NIC66B A ,NIC84B B ,NIC70B C /*혐의거래고객공통정보*/ ,NIC78B D /*혐의거래고객개인정보*/ ,NIC79B E /*혐의거래고객법인정보*/ ,NIC71B F /*혐의거래계좌정보*/ ,NIC75B G /*혐의거래내역*/ ,NIC98B H ,NIC72B I /*혐의계좌대리인정보*/ ,(SELECT P.SSPS_DL_CRT_DT ,P.SSPS_DL_ID ,P.GNL_AC_NO ,P.GDS_NO ,P.DL_DT ,P.DL_SQ ,Q.CHCK_KND_CD ,Q.CHCK_STRT_NO ,Q.CHCK_END_NO ,DECODE(Q.CHCK_KND_CD, '05', R.RPR_OGN_NM, '') AS BNK_NM ,DECODE(Q.CHCK_KND_CD, '05', R.TRNS_OGN_CD, '') AS BNK_CD ,DECODE(Q.CHCK_KND_CD, '05', P.HANDLNG_BRN_NM, '') AS BRN_NM ,DECODE(Q.CHCK_KND_CD, '05', P.HANDLNG_BRN_PST_NO, '') AS BRN_PST_NO FROM NIC71B O ,NIC75B P ,NIC76B Q ,NIC86B R WHERE O.SSPS_DL_CRT_DT = P.SSPS_DL_CRT_DT AND O.SSPS_DL_ID = P.SSPS_DL_ID AND O.GNL_AC_NO = P.GNL_AC_NO AND O.GDS_NO = P.GDS_NO AND P.SSPS_DL_CRT_DT = Q.SSPS_DL_CRT_DT(+) AND P.SSPS_DL_ID = Q.SSPS_DL_ID(+) AND P.GNL_AC_NO = Q.GNL_AC_NO(+) AND P.GDS_NO = Q.GDS_NO(+) AND P.DL_DT = Q.DL_DT(+) AND P.DL_SQ = Q.DL_SQ(+) AND P.CTR_DL_KND_CD IN ('25', '26') AND O.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND O.SSPS_DL_ID = #{SSPS_DL_ID} ) J --수표정보 ,(SELECT T.SSPS_DL_CRT_DT ,T.SSPS_DL_ID ,T.GNL_AC_NO ,T.GDS_NO ,T.DL_DT ,T.DL_SQ ,NVL(U.CPRTY_TRSNS_AC_NO, S.GNL_AC_NO) AS CPRTY_TRSNS_AC_NO ,NVL(U.CPRTY_TRSNS_FOGN_NM, V.RPR_OGN_NM) AS CPRTY_TRSNS_FOGN_NM ,NVL(U.CPRTY_TRSNS_OGN_CD, V.TRNS_OGN_CD) AS CPRTY_TRSNS_OGN_CD ,NVL(U.CPRTY_TRSNS_AC_NM, S.CS_NM) AS CPRTY_TRSNS_AC_NM ,U.CPRTY_TRSNS_AC_RNM_NO ,U.CPRTY_TRSNS_AC_RNM_CNFR_CCD ,U.CPRTY_TRSNS_AC_OWN_NTN_CD FROM NIC71B S ,NIC75B T ,NIC83B U ,NIC86B V WHERE S.SSPS_DL_CRT_DT = T.SSPS_DL_CRT_DT AND S.SSPS_DL_ID = T.SSPS_DL_ID AND S.GNL_AC_NO = T.GNL_AC_NO AND S.GDS_NO = T.GDS_NO AND T.SSPS_DL_CRT_DT = U.SSPS_DL_CRT_DT(+) AND T.SSPS_DL_ID = U.SSPS_DL_ID(+) AND T.GNL_AC_NO = U.GNL_AC_NO(+) AND T.GDS_NO = U.GDS_NO(+) AND T.DL_DT = U.DL_DT(+) AND T.DL_SQ = U.DL_SQ(+) AND T.CTR_DL_KND_CD IN ('21', '22') AND S.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND S.SSPS_DL_ID = #{SSPS_DL_ID} ) K ,(SELECT W.* FROM NIC71B W ,NIC75B X WHERE W.SSPS_DL_CRT_DT = X.SSPS_DL_CRT_DT AND W.SSPS_DL_ID = X.SSPS_DL_ID AND W.GNL_AC_NO = X.GNL_AC_NO AND W.GDS_NO = X.GDS_NO AND X.CTR_DL_KND_CD IN ('11', '12') AND W.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND W.SSPS_DL_ID = #{SSPS_DL_ID} ) L ,( SELECT A.* FROM NIC03B_1 A , ( SELECT RNMCNO , MIN(RPRST_P_SQ) AS RPRST_P_SQ FROM NIC03B_1 WHERE RPR_TGT_YN = 'Y' GROUP BY RNMCNO ) B WHERE A.RNMCNO = B.RNMCNO AND A.RPRST_P_SQ = B.RPRST_P_SQ ) M ,NIC86B N WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = C.DL_P_RNMCNO
AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = D.DL_P_RNMCNO(+) AND C.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = E.DL_P_RNMCNO(+)
AND C.DL_P_RNMCNO = M.RNMCNO(+)
AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = F.SSPS_DL_ID
AND F.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND F.SSPS_DL_ID = G.SSPS_DL_ID AND F.GNL_AC_NO = G.GNL_AC_NO AND F.GDS_NO = G.GDS_NO
AND F.SSPS_DL_CRT_DT = L.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = L.SSPS_DL_ID(+) AND F.GNL_AC_NO = L.GNL_AC_NO(+) AND F.GDS_NO = L.GDS_NO(+)
AND G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = H.SSPS_DL_ID(+) AND G.GNL_AC_NO = H.GNL_AC_NO(+) AND G.GDS_NO = H.GDS_NO(+) AND G.DL_DT = H.DL_DT(+) AND G.DL_SQ = H.DL_SQ(+)
AND F.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = I.SSPS_DL_ID(+) AND F.GNL_AC_NO = I.GNL_AC_NO(+) AND F.GDS_NO = I.GDS_NO(+)
AND G.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = J.SSPS_DL_ID(+) AND G.GNL_AC_NO = J.GNL_AC_NO(+) AND G.GDS_NO = J.GDS_NO(+) AND G.DL_DT = J.DL_DT(+) AND G.DL_SQ = J.DL_SQ(+)
AND G.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = K.SSPS_DL_ID(+) AND G.GNL_AC_NO = K.GNL_AC_NO(+) AND G.GDS_NO = K.GDS_NO(+) AND G.DL_DT = K.DL_DT(+) AND G.DL_SQ = K.DL_SQ(+)
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

/* 문서시작 */ SELECT 'CTRSTART' AS CTR00 --문서시작 ,A.RPR_CCD AS CTR01 --메시지타입
/* 표제부에 관한 정보 */ ,TRIM(A.RPR_DOC_NO_DL_YR || '-' || LPAD(A.RPR_DOC_NO_FNL_SQ, 8, '0')) AS CTR02 --2 문서번호(YYYY ,TO_CHAR(SYSDATE, 'YYYYMMDD') AS CTR03 --3 보고일자 ,CASE WHEN A.RPR_CCD NOT IN ('01', '99') THEN TRIM(B.RPR_DOC_NO_DL_YR || '-' || LPAD(B.RPR_DOC_NO_FNL_SQ, 8, '0')) ELSE '' END AS CTR04 --4 종전문서번호 ,LPAD(A.RNM_PR_DL_SQ, 7, '0') || '/' || LPAD(A.RNM_PR_TL_DL_CNT, 7, '0') AS CTR05 --5 거래순번 ,TRIM(A.RPR_DOC_NO_DL_YR || '-' || LPAD(A.DOC_SQ, 8, '0')) AS CTR06 --6 기본문서번호
