/* III-3 유가증권거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 25.비계좌(유가증권)+지급, 26.비계좌(유가증권)+영수일경우 모두필수이나, --40. 관련유가증권종류 코드값이 11.선불카드일 경우 33,33-1 선택항목 ,'' AS CTR71 --71 관련유가증권종류 ,'' AS CTR72 --72 관련유가증권시작번호 ,'' AS CTR73 --73 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ --40번 유가증권종류에서 코드값이 05.자기앞수표일경우 필수 항목 ,'' AS CTR74 --74 현금지급은행명 ,'' AS CTR75 --75 현금지급은행기관코드 ,'' AS CTR76 --76 현금지급영업점명 ,'' AS CTR77 --77 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ --35번 거래종류항목코드 중 22.비계좌(송금)+영수일 경우 필수 항목 ,'' AS CTR78 --78 수취인계좌번호 ,'' AS CTR79 --79 수취금융기관명 ,'' AS CTR80 --80 수취금융기관코드 ,'' AS CTR81 --81 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ --선택사항이며, 01번 메시지 타입 코드값이 02,03,97,98일경우 필수 항목 ,CASE WHEN A.RPR_CCD NOT IN ('01', '93') THEN SUBSTRB((SELECT I.CNTNT FROM NIC66B_W I WHERE (I.INST_ID, I.WORK_ID) IN (SELECT J.INST_ID ,MIN(J.WORK_ID) FROM NIC66B_W J WHERE J.INST_ID = A.INST_ID GROUP BY J.INST_ID ) ), 1, 1000) ELSE '' END AS CTR82 , 'CTREND' AS CTR83 FROM NIC66B A ,NIC84B B ,NIC86B C WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

SELECT DECODE(CNT,0,'N','Y') MERGE_YN
FROM (SELECT COUNT(*) CNT
        FROM NIC66B                                                     
       WHERE M_SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
         AND M_SSPS_DL_ID = #{SSPS_DL_ID}
         AND DL_P_RNMCNO = #{DL_P_RNMCNO}
     )

SELECT DECODE(A.CNT, 0, 'N', 'Y') AS MERGE_YN
  FROM (SELECT COUNT(*) CNT
          FROM NIC66B B
         WHERE B.SSPS_DL_CRT_DT = #{param0}
           AND B.SSPS_DL_ID != #{param1}
           AND B.DL_P_RNMCNO  = #{param2}
           AND (    B.M_INST_ID != 0
                AND B.M_INST_ID IS NOT NULL
               )
       ) A

SELECT DISTINCT '0' AS SELECTED ,A.SSPS_DL_ID AS SSPS_DL_ID_F ,GET_SYNARIO_NAME(A.SSPS_TYP_CD) AS SSPS_TYP_NM ,CASE WHEN A.RPR_PRGRS_CCD = '2' THEN C.ACT_NAME ELSE GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) END AS ACT_NAME ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,CASE WHEN A.M_SSPS_DL_CRT_DT IS NULL OR A.M_SSPS_DL_CRT_DT = '' THEN 'N' ELSE 'Y' END AS M_SSPS_DL_CRT_DT FROM NIC66B A ,NIC35B B ,(SELECT I.INST_ID ,K.ACT_NAME FROM WF_PROC_INSTANCE I ,WF_WORKLIST J ,WF_ACT K WHERE I.WORK_ID = J.WORK_ID AND J.ACT_ID = K.ACT_ID) C WHERE A.DL_P_RNMCNO = B.RNMCNO (+) AND A.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND A.INST_ID = C.INST_ID AND A.RPR_PRGRS_CCD IN ('0', '1', '2') AND A.DL_P_RNMCNO = #{DL_P_RNMCNO} AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID != #{SSPS_DL_ID}
UNION
SELECT DISTINCT '0' AS SELECTED ,D.SSPS_DL_ID AS SSPS_DL_ID_F ,GET_SYNARIO_NAME(D.SSPS_TYP_CD) AS SSPS_TYP_NM ,F.ACT_NAME ,D.SSPS_DL_CRT_DT ,D.SSPS_DL_ID ,CASE WHEN D.M_SSPS_DL_CRT_DT IS NULL OR D.M_SSPS_DL_CRT_DT = '' THEN 'N' ELSE 'Y' END AS M_SSPS_DL_CRT_DT FROM NIC66B D ,NIC35B E ,( SELECT L.ACT_NAME ,M.SSPS_DL_CRT_DT ,M.SSPS_DL_ID FROM V_WF_STANDBY L ,NIC66B M WHERE ( ( L.PERSON_YN = 'Y' AND L.PARTICIPANT_ID = #{USER_ID} ) OR ( L.PERSON_YN = 'N' AND L.PARTICIPANT_ID IN (SELECT Y.DEP_ID || '.' || ROLE_ID FROM C_USER_GROUP_ROLE X ,C_USER Y WHERE X.USER_ID= #{USER_ID} AND X.USER_ID = Y.USER_ID AND Y.DEP_ID || '.' || ROLE_ID = #{DPT_ROLE} ) ) ) AND M.M_INST_ID = L.PAR_INST_ID AND M.RPR_PRGRS_CCD = '9' AND M.XCL_RSN_CNTNT = '병합처리' ) F WHERE D.DL_P_RNMCNO = E.RNMCNO(+) AND D.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND D.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND D.SSPS_DL_ID = F.SSPS_DL_ID AND D.DL_P_RNMCNO = #{DL_P_RNMCNO} AND D.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND D.M_SSPS_DL_ID = #{SSPS_DL_ID} ORDER BY SSPS_DL_ID_F

