      ,FRST_SSPS_DL_CRT_DT  = #{SSPS_DL_CRT_DT}         -- 최초혐의거래생성일자
      ,FRST_SSPS_DL_ID      = #{SSPS_DL_ID}             -- 최초혐의거래ID
 WHERE SSPS_DL_CRT_DT       = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID           = #{SSPS_DL_ID}

