      ,RPR_COMPLITE_DT     = TO_DATE(TO_CHAR(#{RPR_COMPLITE_DT}), 'yyyymmddHH24miss')
      ,RPR_COMPLITE_P_ENO  = #{LOGIN_ID}
 WHERE SSPS_DL_CRT_DT  = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID      = #{SSPS_DL_ID}

