mapper.select:
SELECT B.MA01_6 AS SSPS_TYP_CD ,A.BIZ_NM AS SSPS_TYP_NM ,A.BIZ_DESC AS RULE_DESC1 ,C.RULE_DESC2 ,C.RULE_DESC3 ,C.RULE_DESC4 ,C.RULE_DESC5 ,C.REG_USER AS REG_USER ,C.REG_DATE ,C.CHG_USER AS CHG_USER ,C.CHG_DATE ,A.BIZ_ID ,NVL(REPLACE(B.MA01_1, ' ', ''), 'N') AS USE_YN ,NVL(D.RULE_DAY, 'N') AS RULE_DAY ,NVL(D.RULE_MONTH, 'N') AS RULE_MONTH ,NVL(D.RULE_QUARTER, 'N') AS RULE_QUARTER ,NVL(D.RULE_WEEK, 'N') AS RULE_WEEK ,B.RT31_1 FROM C_BIZ A ,MMA010TB B ,AML_TB_STRINF_MNG C ,(SELECT MA07_1 ,MAX(CASE WHEN I.MA06_1 = 'D' THEN 'Y' ELSE 'N' END) AS RULE_DAY ,MAX(CASE WHEN I.MA06_1 = 'M' THEN 'Y' ELSE 'N' END) AS RULE_MONTH ,MAX(CASE WHEN I.MA06_1 = 'Q' THEN 'Y' ELSE 'N' END) AS RULE_QUARTER ,MAX(CASE WHEN I.MA06_1 = 'W' THEN 'Y' ELSE 'N' END) AS RULE_WEEK FROM MMA070TB I GROUP BY MA07_1 ) D WHERE A.BIZ_ID = B.RT30_1 AND B.MA01_6 = C.SSPS_TYP_CD(+) AND B.MA01_8 ='S' AND B.MA01_6 = D.MA07_1(+)
AND B.MA01_6 = #{SSPS_TYP_CD}
ORDER BY B.MA01_6

SELECT TBL.* , ROW_NUMBER() OVER(ORDER BY TBL.DL_DT||TBL.DL_TM DESC, TBL.SSPS_DL_ID DESC) AS NU , FN_CDINFO_VAR('DT',TBL.DL_DT||TBL.DL_TM,'') AS DL_DT_TM_VIEW , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , CASE WHEN ( SELECT COUNT(*) AS CNT FROM NIC66B WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND DL_P_RNMCNO = TBL.DL_P_RNMCNO AND SSPS_DL_ID LIKE 'CTR%' ) = 1 THEN 0 ELSE TBL.RNM_PR_DL_SQ END AS RNM_PR_DL_SQ , GET_CODE_NAME('M062',TBL.CTR_DL_KND_CD) AS CTR_DL_KND_CD_NM , FN_CDINFO_VAR('DPT',TBL.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM --거래점 , CASE WHEN TBL.CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.MN_DL_DPRT_CD,'') END AS MN_DL_DPRT_NM --계좌관리점 , CASE WHEN TBL.CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.PRFT_BRN_CD,'') END AS PRFT_BRN_NM --계좌실적점 , AML_CODE.CODE_NM('A301', TBL.OK_CCD) AS OK_CCD_NM , DECODE((SELECT COUNT(*) FROM NIC64B WHERE SSPS_DL_CRT_DT=TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID=TBL.SSPS_DL_ID),0,'No','Yes') AS FILE_ATT_YN , CASE WHEN TRIM(TBL.AC_OWN_P_RLTNS_CD) IS NULL THEN '' ELSE (TBL.AC_OWN_P_RLTNS_CD|| ' / ' ||(SELECT CD_VL_NM FROM NIC95B WHERE CD='L058' AND TRNSFRM_CD = TBL.AC_OWN_P_RLTNS_CD)) END AS RLTNS_CD_NM , GET_CODE_NAME('M045',TBL.DL_TYP_CD) AS DL_TYP_NM , GET_CODE_NAME('M045',DECODE(TBL.DL_TYP_CD,'01','02','02','01')) AS DL_TYP_NM_CPRTY , (SELECT SUM(CSH) FROM NIC61B_CTR WHERE RNMCNO = TBL.DL_P_RNMCNO AND DL_DT = TBL.DL_DT AND DL_TYP_CD = DECODE(TBL.DL_TYP_CD,'01','02','02','01')) AS CSH_CPRTY , Fn_Cdinfo_Var('USER',TBL.HNDL_P_ENO,'') AS HNDL_P_NM FROM ( SELECT '0' AS SELECTED , T1.SSPS_DL_CRT_DT||'-'||T1.SSPS_DL_ID AS SSPS_DL_CRT_DT_A , T3.DL_DT , T3.DL_TM , T5.DL_P_NM , T1.DL_P_RNMCNO , T1.RNM_PR_DL_SQ , T3.CTR_DL_KND_CD , T3.CSH , CASE WHEN T3.CTR_DL_KND_CD IN ('11','12') THEN T2.ACNT_NO ELSE '' END AS ACNT_NO , T2.GNL_AC_NO , T3.HANDLNG_BRN_CD , T2.MN_DL_DPRT_CD , T2.PRFT_BRN_CD , V1.ACT_NAME , T1.OK_CCD , T1.XCL_RSN_CNTNT , T1.SSPS_DL_CRT_DT , T1.SSPS_DL_ID , T1.INST_ID , V1.WORK_ID , V1.ACT_ID , DECODE(T7.NTV_FGNR_CCD, 'A','','B','Y') AS DL_P_NTNLT_CD -- 외국인여부 , T5.CS_NO , T5.INDV_CORP_CCD , T6.AC_OWN_P_RLTNS_CD , CASE WHEN TRIM(T6.PRXY_CS_NO) IS NOT NULL OR TRIM(T6.AC_OWN_P_RLTNS_CD) IS NOT NULL THEN 'Y' ELSE NULL END PRXY_YN , T7.CS_NO AS PRXY_CS_NO , T6.PRXY_NM AS DL_PRXY_NM , CASE WHEN T3.CTR_DL_KND_CD IN ('11','12') THEN T9.PRXY_NM ELSE '' END AS AC_PRXY_NM , T1.STR_YN , T3.DL_TYP_CD , T3.DTLS_TRDG_NAME , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') THEN NVL(T10.RLTV_FNC_ACNT_NO_CRYP, TRIM(T2.ACNT_NO)) ELSE '' END AS CPRTY_TRSNS_AC_NO , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE IN ('240') THEN NVL(T10.RLTV_BANK_ACNT_NAME, TRIM(T2.CS_NM)) ELSE '' END AS CPRTY_TRSNS_AC_NM , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE NOT IN ('240') THEN NVL(T10.RLBK_NAME, '') ELSE '' END AS CPRTY_TRSNS_FOGN_NM , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE NOT IN ('240') THEN NVL(T10.RLTV_BANK_ACNT_NAME, '') ELSE '' END AS CPRTY_TRSNS_AC_RNM_CLSF_NM , T3.HNDL_P_ENO , T2.AC_OPN_DT -- 계좌개설일 , T5.SPRN_KEEP_TAGT_YN ,'Click' AS SELECT_TEXT , T1.CORT_CNCL_RSN_CNTNT -- 취소정정사유 , T1.XCL_RSN_CNTNT2 , T1.DNY_RSN_CNTNT FROM NIC66B T1, NIC71B T2, NIC75B T3, NIC83B T4, NIC70B T5, NIC98B T6, NIC01B T7, NIC72B T9, NIC61B_CTR T10, (SELECT /*+INDEX(D NIC66BIX03)*/ A.INST_ID , A.WORK_ID , A.ACT_NAME , A.ACT_ID , D.SSPS_DL_CRT_DT , D.SSPS_DL_ID FROM V_WF_STANDBY A, NIC66B D WHERE (A.PERSON_YN='Y' AND A.PARTICIPANT_ID = #{userId}) AND D.INST_ID = A.PAR_INST_ID AND D.RPR_PRGRS_CCD = '2' UNION ALL SELECT /*+INDEX(D NIC66BIX03)*/ A.INST_ID , A.WORK_ID , A.ACT_NAME , A.ACT_ID , D.SSPS_DL_CRT_DT , D.SSPS_DL_ID FROM V_WF_STANDBY A, NIC66B D WHERE (A.PERSON_YN='N' AND A.PARTICIPANT_ID IN ( #{dptRole} )) AND D.INST_ID = A.PAR_INST_ID AND D.RPR_PRGRS_CCD = '2' ) V1 WHERE T1.SSPS_DL_CRT_DT = T2.SSPS_DL_CRT_DT AND T1.SSPS_DL_ID = T2.SSPS_DL_ID AND T2.SSPS_DL_CRT_DT = T3.SSPS_DL_CRT_DT AND T2.SSPS_DL_ID = T3.SSPS_DL_ID AND T2.GNL_AC_NO = T3.GNL_AC_NO AND T3.SSPS_DL_CRT_DT = T4.SSPS_DL_CRT_DT(+) AND T3.SSPS_DL_ID = T4.SSPS_DL_ID(+) AND T3.GNL_AC_NO = T4.GNL_AC_NO(+) AND T3.DL_DT = T4.DL_DT(+) AND T3.DL_SQ = T4.DL_SQ(+) AND T1.SSPS_DL_CRT_DT = T5.SSPS_DL_CRT_DT(+) AND T1.DL_P_RNMCNO = T5.DL_P_RNMCNO(+) AND T1.SSPS_DL_CRT_DT = V1.SSPS_DL_CRT_DT AND T1.SSPS_DL_ID = V1.SSPS_DL_ID AND T1.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND T1.SSPS_DL_CRT_DT = T6.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = T6.SSPS_DL_ID(+) AND T1.SSPS_DL_CRT_DT = T9.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = T9.SSPS_DL_ID(+) AND T6.PRXY_RNMCNO = T7.RNMCNO(+) AND T3.GNL_AC_NO = T10.GNL_AC_NO(+) AND T3.DL_DT = T10.DL_DT(+) AND T3.DL_SQ = T10.DL_SQ(+)
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND SSPS_DL_ID = T1.SSPS_DL_ID)
