 IDX3_NIC66B)*/ K.INST_ID ,K.WORK_ID ,K.ACT_NAME ,K.ACT_ID ,L.SSPS_DL_CRT_DT ,L.SSPS_DL_ID ,K.PROC_ID FROM V_WF_STANDBY K ,NIC66B L WHERE ( (K.PERSON_YN = 'Y' AND K.PARTICIPANT_ID = #{param0}) OR (K.PERSON_YN = 'N' AND K.PARTICIPANT_ID IN (SELECT /*+ PUSH_SUBQ */ Y2.DEP_ID || '.' || X2.ROLE_ID FROM C_USER_GROUP_ROLE X2 ,C_USER Y2 WHERE X2.USER_ID = #{param1} AND X2.USER_ID = Y2.USER_ID AND Y2.DEP_ID || '.' || X2.ROLE_ID = #{param2} ) ) OR (K.PERSON_YN = 'N' AND K.PARTICIPANT_ID IN (SELECT Z3.TGT_DEP_ID || '.' || Z3.ROLE_ID FROM C_USER_GROUP_ROLE X3 ,C_USER Y3 ,(SELECT X4.* FROM C_MULTI_POSITION X4 WHERE X4.CHRG_P_ID = #{param1} AND X4.APPR_STAT_CD = 'E' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN X4.START_DT AND X4.END_DT AND ROWNUM = 1 ) Z3 WHERE X3.USER_ID = #{param1} AND X3.USER_ID = Y3.USER_ID AND X3.USER_ID = Z3.CHRG_P_ID AND Y3.DEP_ID || '.' || X3.ROLE_ID = #{param2} ) ) ) AND L.INST_ID = K.PAR_INST_ID AND L.RPR_PRGRS_CCD = '2' ) E WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.GDS_NO = C.GDS_NO AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.SSPS_DL_ID = D.SSPS_DL_ID(+) AND C.GNL_AC_NO = D.GNL_AC_NO(+) AND C.GDS_NO = D.GDS_NO(+) AND C.DL_DT = D.DL_DT(+) AND C.DL_SQ = D.DL_SQ(+) AND A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = E.SSPS_DL_ID AND A.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') ) T2 ) T1 WHERE 1 = 1
AND T1.SSPS_DL_CRT_DT >= #{stDate}
