AND T1.CS_NM LIKE '%' || UPPER(#{CS_NM}) || '%'

SELECT /*+ INDEX(T1 PK_NIC66B) */ A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A ,(SELECT CS_NM FROM NIC01B WHERE RNMCNO = A.DL_P_RNMCNO ) AS DL_P_NM ,A.DL_P_RNMCNO ,A.RNM_PR_DL_SQ ,TO_CHAR(C.CSH, 'FM999,999,999,999') AS CSH ,TO_CHAR(NVL(C.FRST_CSH, C.CSH), 'FM999,999,999,999') AS FRST_CSH ,CASE WHEN C.CTR_DL_KND_CD IN ('11', '12') THEN B.GNL_AC_NO ELSE '' END AS GNL_AC_NO_FULL ,CASE WHEN C.CTR_DL_KND_CD IN ('21', '22') THEN NVL(D.CPRTY_TRSNS_AC_NO, B.GNL_AC_NO) ELSE '' END AS CPRTY_TRSNS_AC_NO ,E.ACT_NAME ,A.OK_CCD ,A.XCL_RSN_CNTNT ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,A.INST_ID ,E.WORK_ID ,E.ACT_ID ,C.DL_CHNNL_CD ,C.DL_CHNNL_NM ,C.SMRY_TYP_CD ,C.SMRY_TYP_NM ,C.GNL_AC_NO ,C.GDS_NO ,C.DL_DT ,C.DL_SQ ,CASE WHEN A.RPR_PRGRS_CCD = '2' AND A.SSPS_DL_CRT_CCD = 'CTR' THEN TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'), 'YYYYMMDD') - TO_DATE(A.SSPS_DL_CRT_DT, 'YYYYMMDD') + 1 || '' ELSE '' END AS DURATION ,'Click' AS SELECT_TEXT ,A.XCL_RSN_CNTNT2 ,A.DNY_RSN_CNTNT ,A.DL_P_RNMCNO ,C.HANDLNG_BRN_CD ,C.CTR_DL_KND_CD ,C.DL_TM ,A.RPR_CCD ,GET_CODE_NAME('A103', A.RPR_CCD) AS RPR_CCD_NM ,A.CORT_CNCL_RSN_CNTNT -- 취소정정사유 ,NVL((SELECT X1.CSH_UPD_RSCD FROM NIC75B_LOG X1 WHERE X1.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND X1.SSPS_DL_ID = C.SSPS_DL_ID AND X1.GNL_AC_NO = C.GNL_AC_NO AND X1.GDS_NO = C.GDS_NO AND X1.DL_DT = C.DL_DT AND X1.DL_SQ = C.DL_SQ AND X1.SEQ = 0 ), '01') AS CSH_UPD_RSCD -- 현금거래금액 수정 사유 ,NVL((SELECT Y2.USER_NM FROM NIC75B_LOG X2 ,C_USER Y2 WHERE X2.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND X2.SSPS_DL_ID = C.SSPS_DL_ID AND X2.GNL_AC_NO = C.GNL_AC_NO AND X2.GDS_NO = C.GDS_NO AND X2.DL_DT = C.DL_DT AND X2.DL_SQ = C.DL_SQ AND X2.SEQ = 0 AND X2.UPD_ID = Y2.USER_ID ), '') AS UPD_ID -- 수정처리자ID ,NVL((SELECT TO_CHAR(TO_DATE(X3.UPD_DT, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') FROM NIC75B_LOG X3 WHERE X3.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND X3.SSPS_DL_ID = C.SSPS_DL_ID AND X3.GNL_AC_NO = C.GNL_AC_NO AND X3.GDS_NO = C.GDS_NO AND X3.DL_DT = C.DL_DT AND X3.DL_SQ = C.DL_SQ AND X3.SEQ = 0 ), '') AS UPD_DT -- 수정일시 FROM NIC66B A ,NIC71B B ,NIC75B C ,NIC83B D ,(SELECT /*+ INDEX(D IDX3_NIC66B)*/ I.INST_ID ,I.WORK_ID ,I.ACT_NAME ,I.ACT_ID ,J.SSPS_DL_CRT_DT ,J.SSPS_DL_ID ,I.PROC_ID FROM V_WF_STANDBY I ,NIC66B J WHERE ( ( I.PERSON_YN = 'Y' AND I.PARTICIPANT_ID = #{userId} ) OR ( I.PERSON_YN = 'N' AND I.PARTICIPANT_ID IN (SELECT /*+ PUSH_SUBQ */ Y4.DEP_ID || '.' || X4.ROLE_ID FROM C_USER_GROUP_ROLE X4 ,C_USER Y4 WHERE X4.USER_ID = #{userId} AND X4.USER_ID = Y4.USER_ID AND Y4.DEP_ID || '.' || X4.ROLE_ID = #{dptRole} ) ) OR ( I.PERSON_YN = 'N' AND I.PARTICIPANT_ID IN (SELECT Z5.TGT_DEP_ID || '.' || Z5.ROLE_ID FROM C_USER_GROUP_ROLE X5 ,C_USER Y5 ,(SELECT X6.* FROM C_MULTI_POSITION X6 WHERE X6.CHRG_P_ID = #{userId} AND X6.APPR_STAT_CD = 'E' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN X6.START_DT AND X6.END_DT AND ROWNUM = 1 ) Z5 WHERE X5.USER_ID = #{userId} AND X5.USER_ID = Y5.USER_ID AND X5.USER_ID = Z5.CHRG_P_ID AND Y5.DEP_ID || '.' || X5.ROLE_ID = #{dptRole} ) ) ) AND J.INST_ID = I.PAR_INST_ID AND J.RPR_PRGRS_CCD = '2' ) E WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.SSPS_DL_ID = D.SSPS_DL_ID(+) AND C.GNL_AC_NO = D.GNL_AC_NO(+) AND C.GDS_NO = D.GDS_NO(+) AND C.DL_DT = D.DL_DT(+) AND C.DL_SQ = D.DL_SQ(+) AND A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = E.SSPS_DL_ID AND A.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND A.SSPS_DL_CRT_DT IN #{param1, jdbcType=VARCHAR}
