SELECT TBL.* , ROW_NUMBER() OVER(ORDER BY TBL.SSPS_DL_CRT_DT DESC, TBL.SSPS_DL_ID ASC) AS NU , FN_CDINFO_VAR('DT',TBL.DL_DT||TBL.DL_TM,'') AS DL_DT_TM_VIEW -- 거래발생일 , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN -- 고액자산가 , GET_CODE_NAME('M045',TBL.DL_TYP_CD) AS DL_TYP_NM -- 거래유형코드 , GET_CODE_NAME('M062',TBL.CTR_DL_KND_CD) AS CTR_DL_KND_CD_NM -- ctr거래종류코드 , CASE WHEN TBL.RPR_PRGRS_CCD = '2' THEN '' ELSE GET_CODE_NAME('S060', NVL(TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD)) END AS KFU_RPR_STS_NM , FN_CDINFO_VAR('DPT',TBL.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM , CASE WHEN TBL.CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.MN_DL_DPRT_CD,'') END AS MN_DL_DPRT_NM --계좌관리점 , CASE WHEN TBL.CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.PRFT_BRN_CD,'') END AS PRFT_BRN_NM --계좌실적점 , CASE WHEN TBL.RPR_PRGRS_CCD = '2' THEN TBL.ACT_NAME ELSE GET_CODE_NAME('A029',TBL.RPR_PRGRS_CCD) END AS ACT_NAME , AML_CODE.CODE_NM('A301', TBL.OK_CCD) AS OK_CCD_NM , CASE WHEN TRIM(TBL.AC_OWN_P_RLTNS_CD) IS NULL THEN '' ELSE (TBL.AC_OWN_P_RLTNS_CD|| ' / ' ||(SELECT CD_VL_NM FROM NIC95B WHERE CD='L058' AND TRNSFRM_CD = TBL.AC_OWN_P_RLTNS_CD)) END AS RLTNS_CD_NM , (SELECT TO_CHAR(MAX(KFU_RPR_DT),'YYYYMMDD') FROM NIC66B WHERE DL_P_RNMCNO = TBL.DL_P_RNMCNO AND KFU_RPR_DT < TO_DATE(TBL.DL_DT,'YYYY/MM/DD') AND SSPS_DL_CRT_CCD IN ('STR','KYC') AND OK_CCD = '1') AS STR_KFU_RPR_DT , (SELECT SUM(CSH) FROM NIC61B_CTR WHERE RNMCNO = TBL.DL_P_RNMCNO AND DL_DT = TBL.DL_DT AND DL_TYP_CD = DECODE(TBL.DL_TYP_CD,'01','02','02','01')) AS CSH_CPRTY , CASE WHEN TBL.INDV_CORP_CCD = '1' THEN NVL( (SELECT MAX(CLNT_IFMN_CHAN_DATE) FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG WHERE CLNT_ENTY_ID = TBL.RNMCNO AND CLNT_IFMN_CHAN_ITEM_CODE IN ('06','24', '25','26', '27') ), TBL.CS_RGST_DT ) ELSE NVL( (SELECT MAX(CLNT_IFMN_CHAN_DATE) FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG WHERE CLNT_ENTY_ID = TBL.RNMCNO AND CLNT_IFMN_CHAN_ITEM_CODE IN ('25') ), TBL.CS_RGST_DT ) END AS CLNT_IFMN_CHAN_DATE , Fn_Cdinfo_Var('USER',TBL.HNDL_P_ENO,'') AS HNDL_P_NM --20210525 검색화면 필터 추가 , TBL.DL_P_RNMCNO AS C_ID , MGR1.EMPY_NO AS A_EMPY_NO , NVL(MGR1_USER.USER_NAME, '') AS A_USER_NAME , NVL(MGR1_DTBR.DTBR_CODE, '') AS A_DTBR_CODE , NVL(MGR1_DTBR.DTBR_NAME, '') AS A_DTBR_NAME
--, MGR2.MAIN_MNGR_EMPY_NO AS C_MAIN_MNGR_EMPY_NO --, NVL(MGR2_USER.USER_NAME, '') AS C_USER_NAME --, NVL(MGR2_DTBR.DTBR_CODE, '') AS C_DTBR_CODE --, NVL(MGR2_DTBR.DTBR_NAME, '') AS C_DTBR_NAME
FROM ( SELECT T1.SSPS_DL_CRT_DT||'-'||T1.SSPS_DL_ID AS SSPS_DL_CRT_DT_A , T1.SSPS_DL_CRT_DT , T1.SSPS_DL_ID -- 일련번호 , T3.DL_DT , T3.DL_TM , TO_CHAR(T1.KFU_RPR_DT, 'YYYYMMDD' ) AS KFU_RPR_DT -- 보고일자 , DECODE(T7.NTV_FGNR_CCD, 'A','','B','Y') AS DL_P_NTNLT_CD -- 외국인여부 , T2.AC_OPN_BRN_NM -- 계좌개설점 , T2.AC_OPN_DT -- 계좌개설일 , T5.DL_P_NM -- 거래자명 , T1.DL_P_RNMCNO -- 거래자실명확인번호암호문 , T1.RNM_PR_DL_SQ -- 실명별거래일련번호 , T3.DL_TYP_CD , T3.CTR_DL_KND_CD , NVL(T1.KFU_RPR_STS_CD, T1.RPR_PRGRS_CCD) AS KFU_RPR_STS_CD , T1.RPR_PRGRS_CCD , T3.DTLS_TRDG_NAME AS DTLS_TRDG_NAME -- 거래명 , T3.CSH -- 거래금액 , CASE WHEN T3.CTR_DL_KND_CD IN ('11','12') THEN T2.ACNT_NO ELSE '' END AS ACNT_NO -- 계좌번호 , CASE WHEN T3.CTR_DL_KND_CD IN ('11','12') THEN T2.CS_NM ELSE '' END AS CS_NM -- 계좌명 , T2.GNL_AC_NO , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') THEN NVL(T10.RLTV_FNC_ACNT_NO_CRYP, TRIM(T2.ACNT_NO)) ELSE '' END AS CPRTY_TRSNS_AC_NO , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE IN ('240') THEN NVL(T10.RLTV_BANK_ACNT_NAME, TRIM(T2.CS_NM)) ELSE '' END AS CPRTY_TRSNS_AC_NM , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE NOT IN ('240') THEN NVL(T10.RLBK_NAME, '') ELSE '' END AS CPRTY_TRSNS_FOGN_NM , CASE WHEN T3.CTR_DL_KND_CD IN ('21','22') AND T10.RLBK_CODE NOT IN ('240') THEN NVL(T10.RLTV_BANK_ACNT_NAME, '') ELSE '' END AS CPRTY_TRSNS_AC_RNM_CLSF_NM , T3.HANDLNG_BRN_CD , T2.MN_DL_DPRT_CD , T2.PRFT_BRN_CD , D.ACT_NAME , T1.OK_CCD , T1.XCL_RSN_CNTNT , T1.INST_ID , T5.CS_NO , T5.INDV_CORP_CCD , CASE WHEN TRIM(T6.PRXY_CS_NO) IS NOT NULL OR TRIM(T6.AC_OWN_P_RLTNS_CD) IS NOT NULL THEN 'Y' ELSE NULL END PRXY_YN , T6.PRXY_NM AS DL_PRXY_NM , T6.PRXY_CS_NO AS DL_PRXY_CS_NO , CASE WHEN T3.CTR_DL_KND_CD IN ('11','12') THEN T9.PRXY_NM ELSE '' END AS AC_PRXY_NM , T7.CS_NO AS PRXY_CS_NO , T6.AC_OWN_P_RLTNS_CD , T1.STR_YN , T8.CS_CDD_REG_DT , T7.RNMCNO , T7.CS_RGST_DT , T3.HNDL_P_ENO , (CASE WHEN ( SELECT EMPY_NO FROM SID.IDO_A_UUE_EMPLOYEE B1 WHERE B1.ENTY_ID = T1.DL_P_RNMCNO AND B1.EMPY_NO BETWEEN '100000' AND '600000' AND B1.PDSS_USER_STAS_SECT_CODE IN ('A', 'C') )IS NOT NULL THEN 'Y' ELSE '' END) AS EMPY_YN , T5.SPRN_KEEP_TAGT_YN , T5.CS_NO AS AML_CUST_ID FROM NIC66B T1 , NIC71B T2 , NIC75B T3 , NIC83B T4 , NIC70B T5 , NIC98B T6 , NIC01B T7 , (SELECT A.INST_ID, C.ACT_NAME FROM WF_PROC_INSTANCE A , WF_WORKLIST B , WF_ACT C WHERE A.WORK_ID = B.WORK_ID AND B.ACT_ID = C.ACT_ID AND (1 = #{wfCodeYN} OR C.ACT_ID = #{wfCode}) ) D , NIC35B T8 , NIC72B T9 , NIC61B_CTR T10 WHERE T1.SSPS_DL_CRT_DT = T2.SSPS_DL_CRT_DT AND T1.SSPS_DL_ID = T2.SSPS_DL_ID AND T2.SSPS_DL_CRT_DT = T3.SSPS_DL_CRT_DT AND T2.SSPS_DL_ID = T3.SSPS_DL_ID AND T2.GNL_AC_NO = T3.GNL_AC_NO AND T3.SSPS_DL_CRT_DT = T4.SSPS_DL_CRT_DT(+) AND T3.SSPS_DL_ID = T4.SSPS_DL_ID(+) AND T3.GNL_AC_NO = T4.GNL_AC_NO(+) AND T3.DL_DT = T4.DL_DT(+) AND T3.DL_SQ = T4.DL_SQ(+) AND T1.SSPS_DL_CRT_DT = T5.SSPS_DL_CRT_DT(+) AND T1.DL_P_RNMCNO = T5.DL_P_RNMCNO(+) AND T1.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND T1.INST_ID = D.INST_ID AND T1.SSPS_DL_CRT_DT = T6.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = T6.SSPS_DL_ID(+) AND T1.SSPS_DL_CRT_DT = T9.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = T9.SSPS_DL_ID(+) AND T1.DL_P_RNMCNO = T7.RNMCNO(+) AND T1.DL_P_RNMCNO = T8.RNMCNO(+) AND T3.GNL_AC_NO = T10.GNL_AC_NO(+) AND T3.DL_DT = T10.DL_DT(+) AND T3.DL_SQ = T10.DL_SQ(+) AND (1 = #{wfCodeYN2} OR T1.RPR_PRGRS_CCD = #{wfCode2}) AND (1 = #{wfCodeStsYN} OR T1.OK_CCD = #{wfCodeSts})
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND SSPS_DL_ID = T1.SSPS_DL_ID)
AND T3.DL_DT BETWEEN #{stDate} AND #{edDate}
AND T3.CSH >= #{dlAmt}
AND T5.CS_NO = #{CS_NO}
AND T5.DL_P_NM LIKE '%'|| #{CS_NM} ||'%'
AND T1.DL_P_RNMCNO = (SELECT RNMCNO FROM NIC17B WHERE ACNT_NO LIKE #{ACNT_NO} || '%')
AND COALESCE(T1.KFU_RRPR_STS_CD, T1.KFU_RPR_STS_CD, T1.RPR_PRGRS_CCD) = #{RPR_PRGRS_CCD}
) TBL --20210525 검색화면 필터 추가 LEFT OUTER JOIN SID.IDO_A_UUA_ACNT_ENTY_RLTP MGR1 -- 계좌기준 ON MGR1.ACNT_ENTY_ROLE_TYPE_CODE = 'MANG' AND MGR1.ACNT_ID = TBL.GNL_AC_NO LEFT OUTER JOIN SID.IDO_A_UWA_USER MGR1_USER ON MGR1_USER.USER_ID = MGR1.EMPY_NO LEFT OUTER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT MGR1_DTBR ON MGR1_DTBR.ENTY_ID = MGR1_USER.DTBR_ENTY_ID
--LEFT OUTER JOIN SID.IDO_A_IRA_CUST_MGR MGR2 -- 고객기준 -- ON MGR2.CLNT_ENTY_ID = TBL.DL_P_RNMCNO --LEFT OUTER JOIN SID.IDO_A_UWA_USER MGR2_USER -- ON MGR2_USER.USER_ID = MGR2.MAIN_MNGR_EMPY_NO --LEFT OUTER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT MGR2_DTBR -- ON MGR2_DTBR.ENTY_ID = MGR2_USER.DTBR_ENTY_ID

SELECT T1.* FROM (SELECT COUNT(*) OVER() AS TOTALCOUNT ,ROWNUM AS SEQ ,T2.* FROM (SELECT T3.* FROM (SELECT I.DL_P_NM AS LST_DL_P_NM ,FN_CDINFO_VAR('DPT', C.HANDLNG_BRN_CD, '') AS HANDLNG_BRN_NM ,H.TEXT1 AS LST_RPR_PRGRS_CCD ,H.TEXT2 || CASE WHEN A.RPR_PRGRS_CCD = '2' THEN F.ACT_NAME ELSE GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) END AS LST_ACT_NAME ,GET_CODE_NAME('A301', A.OK_CCD) AS OK_CCD_NM -- ASIS RNMCNO 없음 NIC70B ,I.RNMCNO AS RNMCNO ,(SELECT TO_DATE(SUBSTR(X1.FIU_TMSG_TRX_DH, 1, 8), 'YYYY-MM-DD') FROM FIU03B X1 WHERE X1.FIU_TMSG_ID ='03100050' /*파일종료응답 전문*/ AND X1.FIU_RPT_TYPE_C = '01' /*보고*/ AND X1.SSPS_DL_CRT_DT = A.SSPS_DL_ID AND X1.SSPS_DL_ID = A.SSPS_DL_ID) AS KOFIUDATE --KoFIU보고일자 ,J.RPR_P_NM AS INPUT_P_NM ,GET_CODE_NAME('A103', A.RPR_CCD) AS RPR_CCD_NM ,GET_CODE_NAME('M044', C.DL_CHNNL_CD) AS DL_CHNNL_NM ,I.DL_P_NM ,A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,C.DL_DT AS DL_DT_TM_VIEW ,A.DL_P_RNMCNO ,A.RNM_PR_DL_SQ ,A.OK_CCD ,CASE WHEN C.CTR_DL_KND_CD IN ('12', '22', '24', '26', '99') THEN '입금' WHEN C.CTR_DL_KND_CD IN ('11', '21', '23', '25', '98') THEN '출금' ELSE '' END AS CTR_DL_KND_CD_NM ,TO_CHAR(C.CSH, 'FM999,999,999,999') AS CSH ,CASE WHEN C.CTR_DL_KND_CD IN ('11', '12') THEN B.GNL_AC_NO ELSE '' END AS GNL_AC_NO_FULL ,B.GNL_AC_NO AS LST_ACNT_NO ,D.CPRTY_TRSNS_AC_NO AS CPRTY_TRSNS_AC_NO ,A.RPR_PRGRS_CCD ,A.XCL_RSN_CNTNT ,'' AS HDQT_XCL_RSN_CNTNT ,A.INST_ID -- 여기는 없네요. 적요 0616 NIC61B ,E.SMRY_TYP_NM AS SMRY_TYP_NM ,CASE WHEN (CASE WHEN A.OK_CCD = '2' AND A.RPR_PRGRS_CCD IN ('9', '10') THEN '99999999' WHEN A.OK_CCD = '1' AND A.RPR_PRGRS_CCD = '10' THEN A.RPR_DT END) = '99999999' THEN '-' --보고제외로 결재종료 ELSE (CASE WHEN(CASE WHEN A.OK_CCD = '1' AND A.RPR_PRGRS_CCD = '10' THEN A.RPR_DT --Kofiu보고완요일자 ELSE 'X' END) = 'X' THEN TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'), 'YYYYMMDD') - TO_DATE(SUBSTR(A.SSPS_DL_CRT_DT, 1, 8), 'YYYYMMDD') || '일' --결재가 종료 되지 않았을때 ELSE TO_DATE(A.RPR_DT, 'YYYYMMDD') - TO_DATE(SUBSTR(A.SSPS_DL_CRT_DT, 1, 8), 'YYYYMMDD') || '일' -- Kofiu에 보고 되었을때 END) END AS DL_DT_CNT --경과일수 ,C.HANDLNG_BRN_CD ,F.ACT_NAME ,A.RPR_CCD ,C.CSH AS DL_AMT ,C.DL_CHNNL_CD FROM NIC66B A INNER JOIN NIC71B B ON A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID INNER JOIN NIC75B C ON B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.GDS_NO = C.GDS_NO LEFT JOIN NIC83B D ON C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT AND C.SSPS_DL_ID = D.SSPS_DL_ID AND C.GNL_AC_NO = D.GNL_AC_NO AND C.GDS_NO = D.GDS_NO AND C.DL_DT = D.DL_DT AND C.DL_SQ = D.DL_SQ INNER JOIN NIC61B E ON C.GNL_AC_NO = E.GNL_AC_NO AND C.GDS_NO = E.GDS_NO AND C.DL_DT = E.DL_DT AND C.DL_SQ = E.DL_SQ
INNER JOIN (SELECT X2.INST_ID ,Y2.ACT_NAME ,X2.PROC_ID ,Y2.ACT_ID FROM WF_PROC_INSTANCE X2 LEFT JOIN MV_APRV_STATUS Y2 ON X2.INST_ID = Y2.PAR_INST_ID AND Y2.INST_STATUS_CD != 'DELETED' ) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X3.INST_ID ,Y3.ACT_NAME ,X3.PROC_ID ,Y3.ACT_ID FROM WF_PROC_INSTANCE X3 LEFT JOIN MV_APRV_STATUS Y3 ON X3.INST_ID = Y3.PAR_INST_ID AND Y3.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z3 ON X3.INST_ID = Z3.INST_ID WHERE Z3.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND Y3.ACT_NAME IN (SELECT X4.ACT_NAME FROM WF_ACT X4 WHERE X4.ACT_ID IN #{wfCodeArray1, jdbcType=VARCHAR}
) UNION
SELECT X5.INST_ID ,GET_CODE_NAME('A029', X5.RPR_PRGRS_CCD) AS ACT_NAME ,0 AS PROC_ID ,0 AS ACT_ID FROM NIC66B X5 WHERE X5.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND X5.RPR_PRGRS_CCD IN #{wfCodeArray2, jdbcType=VARCHAR}
) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X6.INST_ID ,Y6.ACT_NAME ,X6.PROC_ID ,Y6.ACT_ID FROM WF_PROC_INSTANCE X6 LEFT JOIN MV_APRV_STATUS Y6 ON X6.INST_ID = Y6.PAR_INST_ID AND Y6.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z6 ON X6.INST_ID = Z6.INST_ID WHERE Z6.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND Y6.ACT_NAME IN (SELECT X7.ACT_NAME FROM WF_ACT X7 WHERE X7.ACT_ID IN #{wfCodeArray1, jdbcType=VARCHAR}
) ) F ON A.INST_ID = F.INST_ID
LEFT JOIN NIC01B G ON A.DL_P_RNMCNO = G.RNMCNO LEFT JOIN (SELECT 'D' AS TEXT1 ,'[반려]' AS TEXT2 ,X8.INST_ID FROM NIC66B_W X8 INNER JOIN (SELECT X9.INST_ID ,MAX(X9.WORK_ID) AS WORK_ID FROM NIC66B_W X9 WHERE X9.RPR_PRGRS_CCD = 'D' GROUP BY X9.INST_ID ) Y8 ON X8.INST_ID = Y8.INST_ID AND X8.WORK_ID = Y8.WORK_ID ) H ON A.INST_ID = H.INST_ID LEFT JOIN NIC70B I ON A.DL_P_RNMCNO = I.DL_P_RNMCNO AND A.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT LEFT JOIN (SELECT MAX(X10.RPR_P_NM) AS RPR_P_NM ,X10.PAR_INST_ID FROM NIC66B_W X10 INNER JOIN (SELECT X11.PAR_INST_ID ,MAX(X11.WORK_ID) AS WORK_ID FROM NIC66B_W X11 --WHERE X11.RPR_P_ENO != 0 -- 시스템담당자 제외 GROUP BY X11.PAR_INST_ID ) Y10 ON X10.WORK_ID = Y10.WORK_ID GROUP BY X10.PAR_INST_ID ) J ON A.INST_ID = J.PAR_INST_ID WHERE A.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') ) T3 WHERE 1 = 1
AND T3.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND #{branchCode} IN (SELECT X11.HANDLNG_BRN_CD FROM NIC75B X11 WHERE X11.SSPS_DL_CRT_DT = T3.SSPS_DL_CRT_DT AND X11.SSPS_DL_ID = T3.SSPS_DL_ID )
AND T3.DL_AMT >= #{dlAmt}
AND T3.DL_P_RNMCNO = #{RNMCNO}
AND T3.RPR_PRGRS_CCD IN #{wfCodeArray2, jdbcType=VARCHAR}
AND T3.OK_CCD= #{wfCodeSts}
AND T3.DL_P_NM LIKE '%' || #{CS_NM, jdbcType=VARCHAR} || '%'
AND T3.RPR_CCD = #{RPR_CCD}
) T2
ORDER BY
T2.SSPS_DL_CRT_DT_A T2.DL_DT_TM_VIEW T2.LST_DL_P_NM T2.DL_P_RNMCNO T2.RPR_CCD_NM T2.CTR_DL_KND_CD_NM T2.CSH T2.GNL_AC_NO_FULL T2.CPRTY_TRSNS_AC_NO T2.SMRY_TYP_NM T2.DL_CHNNL_NM T2.HANDLNG_BRN_NM
T2.INPUT_P_NM T2.LST_ACT_NAME T2.OK_CCD_NM
T2.XCL_RSN_CNTNT
ASC DESC
ORDER BY T2.SSPS_DL_CRT_DT DESC ,T2.SSPS_DL_ID ASC
) T1 WHERE 1 = 1
AND T1.SEQ >= ((#{thisPage} - 1) * #{pageCount} + 1) AND T1.SEQ <= (#{thisPage} * #{pageCount})

WITH TMP1 AS (
SELECT (SELECT X1.BIZ_NM FROM C_BIZ X1 WHERE X1.BIZ_ID = K.PAR_BIZ_ID ) AS PAR_NM ,K.PAR_BIZ_ID AS PAR_ID ,J.MA01_6 AS CODE ,I.BIZ_NM AS NAME ,I.BIZ_ID AS ID FROM C_BIZ I LEFT OUTER JOIN MMA010TB J ON I.BIZ_ID = J.RT30_1 ,C_PKG_BIZ_MAP K WHERE I.BIZ_ID = K.BIZ_ID AND K.PKG_ID = 6 AND J.MA01_6 IS NOT NULL AND ( K.PAR_BIZ_ID = 11 OR K.PAR_BIZ_ID IN (SELECT X2.BIZ_ID FROM C_PKG_BIZ_MAP X2 WHERE X2.PAR_BIZ_ID = 11 ) ) ORDER BY ID
SELECT I.BZDM_CD , GET_CODE_NAME('A045', I.BZDM_CD) , I.BIZ_CD AS PAR_ID , GET_CODE_NAME('A046', I.BIZ_CD) AS PAR_NM , I.SCNR_ID AS CODE , I.SCNR_NM AS NAME FROM TMS_APPL I INNER JOIN TMS_BZDM_MNG J ON I.BIZ_CD = J.BIZ_CD WHERE I.SCNR_CCD = 'STR' ORDER BY I.BIZ_CD ASC , I.SCNR_ID ASC
) ,TMP2 AS (SELECT M.SSPS_TYP_CD AS SSPS_TYP_CD ,ROUND(NVL(L.PRE / DECODE(M.TOTAL, 0, NULL, M.TOTAL), 0), 2) AS RELIABILITY ,L.PRE ,M.TOTAL FROM (SELECT X3.SSPS_TYP_CD ,COUNT(*) AS PRE FROM NIC66B X3 WHERE 1 = 1 AND X3.RPR_PRGRS_CCD = 10 /*10Kofiu보고,99파일생성,9결재완료,2진행중*/ AND X3.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X3.INST_ID IS NOT NULL AND X3.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') GROUP BY X3.SSPS_TYP_CD ) L ,(SELECT X4.SSPS_TYP_CD ,COUNT(*) AS TOTAL FROM NIC66B X4 WHERE 1 = 1 AND X4.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X4.INST_ID IS NOT NULL AND X4.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') GROUP BY X4.SSPS_TYP_CD ) M WHERE M.SSPS_TYP_CD = L.SSPS_TYP_CD(+) ) ,TMP3 AS (SELECT N.SSPS_TYP_CD AS SSPS_TYP_CD ,ROUND(NVL(N.COV / DECODE(O.TOTAL, 0, NULL, O.TOTAL), 0), 2) AS COVERAGE FROM (SELECT X5.SSPS_TYP_CD ,COUNT(*) AS COV FROM NIC66B X5 WHERE 1 = 1 AND X5.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X5.INST_ID IS NOT NULL AND X5.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') GROUP BY X5.SSPS_TYP_CD ) N ,(SELECT COUNT(*) AS TOTAL FROM NIC66B X6 WHERE 1 = 1 AND X6.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X6.INST_ID IS NOT NULL AND X6.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') ) O ) ,TMP4 AS (SELECT ROUND(NVL(P.PRE / DECODE(Q.TOTAL, 0, NULL, Q.TOTAL), 0), 2) AS LIFT FROM (SELECT COUNT(*) AS PRE FROM NIC66B X7 WHERE X7.INST_ID IS NOT NULL AND X7.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X7.RPR_PRGRS_CCD = '99' AND X7.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') ) P ,(SELECT COUNT(*) AS TOTAL FROM NIC66B X8 WHERE X8.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X8.INST_ID IS NOT NULL AND X8.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') ) Q ) ,TMP5 AS (SELECT R.SSPS_TYP_CD ,ROUND(NVL((R.C_TOTAL - S.P_TOTAL) / DECODE(S.P_TOTAL, 0, NULL, S.P_TOTAL), 0), 2) AS ALPHA FROM (SELECT X9.SSPS_TYP_CD ,COUNT(*) AS C_TOTAL FROM NIC66B X9 WHERE 1 = 1 AND X9.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X9.INST_ID IS NOT NULL AND X9.SSPS_DL_CRT_DT BETWEEN #{Date} AND TO_CHAR(LAST_DAY(TO_DATE(#{Date}, 'YYYYMMDD')), 'YYYYMMDD') GROUP BY X9.SSPS_TYP_CD ) R ,(SELECT X10.SSPS_TYP_CD ,COUNT(*) AS P_TOTAL FROM NIC66B X10 WHERE 1 = 1 AND X10.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X10.INST_ID IS NOT NULL AND X10.SSPS_DL_CRT_DT BETWEEN TO_CHAR(ADD_MONTHS(TRUNC(TO_DATE(#{Date}, 'YYYYMMDD'), 'MM'), -1), 'YYYYMMDD') AND TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(#{Date}, 'YYYYMMDD'), -1)), 'YYYYMMDD') GROUP BY X10.SSPS_TYP_CD ) S WHERE R.SSPS_TYP_CD = S.SSPS_TYP_CD(+) ) ,TMP6 AS (SELECT U.SSPS_TYP_CD AS SSPS_TYP_CD ,ROUND(NVL(T.PRE / DECODE(U.TOTAL, 0, NULL, U.TOTAL), 0), 2) AS RELIABILITY_BEFORE ,T.PRE ,U.TOTAL FROM (SELECT X11.SSPS_TYP_CD ,COUNT(*) AS PRE FROM NIC66B X11 WHERE 1 = 1 AND X11.RPR_PRGRS_CCD = 10 /*10Kofiu보고완료,99파일생성,9결재완료,2진행중*/ AND X11.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X11.INST_ID IS NOT NULL AND X11.SSPS_DL_CRT_DT BETWEEN TO_CHAR(ADD_MONTHS(TRUNC(TO_DATE(#{Date}, 'YYYYMMDD'), 'MM'), -1), 'YYYYMMDD') AND TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(#{Date}, 'YYYYMMDD'), -1)), 'YYYYMMDD') GROUP BY X11.SSPS_TYP_CD ) T ,(SELECT X12.SSPS_TYP_CD ,COUNT(*) AS TOTAL FROM NIC66B X12 WHERE 1 = 1 AND X12.SSPS_DL_CRT_CCD IN ('STR', 'KYC') AND X12.INST_ID IS NOT NULL AND X12.SSPS_DL_CRT_DT BETWEEN TO_CHAR(ADD_MONTHS(TRUNC(TO_DATE(#{Date}, 'YYYYMMDD'), 'MM'), -1), 'YYYYMMDD') AND TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(#{Date}, 'YYYYMMDD'), -1)), 'YYYYMMDD') GROUP BY X12.SSPS_TYP_CD ) U WHERE U.SSPS_TYP_CD = T.SSPS_TYP_CD(+) ) SELECT T1.* FROM (SELECT TMP1.CODE ,TMP1.PAR_NM ,TMP1.NAME ,TMP2.TOTAL AS TOTAL_ALERT ,TMP2.PRE AS KOFIU_ALERT ,TMP6.TOTAL AS MONTH_AGO_TOTAL_ALERT ,TMP6.PRE AS MONTH_AGO_KOFIU_ALERT ,RTRIM(TO_CHAR((2 * TMP2.RELIABILITY * TMP3.COVERAGE) / (DECODE(TMP2.RELIABILITY, 0, 1, TMP2.RELIABILITY) + TMP3.COVERAGE), 'FM9990D99'), '.') AS FMEASURE ,RTRIM(TO_CHAR(TMP2.RELIABILITY, 'FM9990D99'), '.') AS RELIABILITY ,RTRIM(TO_CHAR(TMP3.COVERAGE, 'FM9990D99'), '.') AS COVERAGE ,RTRIM(TO_CHAR(ROUND(TMP2.RELIABILITY / DECODE(TMP4.LIFT, 0, NULL, TMP4.LIFT), 2), 'FM9990D99'), '.') AS LIFT ,RTRIM(TO_CHAR(TMP5.ALPHA, 'FM9990D99'), '.') AS ALPHA ,CASE WHEN NVL(TMP5.ALPHA, 0) <= 0.15 THEN 'GREEN' WHEN NVL(TMP5.ALPHA, 0) > 0.15 AND TMP5.ALPHA <= 0.5 THEN 'YELLOW' WHEN NVL(TMP5.ALPHA, 0) > 0.5 AND TMP5.ALPHA <= 0.8 THEN 'RED' ELSE 'BLACK' END AS ALPHA_P ,CASE WHEN NVL(RTRIM(TO_CHAR(ROUND(TMP2.RELIABILITY / DECODE(TMP4.LIFT, 0, NULL, TMP4.LIFT), 2), 'FM9990D99'), '.'), 0) >= 1 THEN '유지' WHEN NVL(RTRIM(TO_CHAR(ROUND(TMP2.RELIABILITY / DECODE(TMP4.LIFT, 0, NULL, TMP4.LIFT), 2), 'FM9990D99'), '.'), 0) < 0 AND NVL(RTRIM(TO_CHAR(ROUND(TMP2.RELIABILITY / DECODE(TMP4.LIFT, 0, NULL, TMP4.LIFT), 2), 'FM9990D99'), '.'), 0) < 1 THEN '수정' WHEN NVL(RTRIM(TO_CHAR(ROUND(TMP2.RELIABILITY / DECODE(TMP4.LIFT, 0, NULL, TMP4.LIFT), 2), 'FM9990D99'), '.'), 0) = 0 THEN '개선' ELSE '' END AS LIFT_P
FROM BRS150TB A ,MMA070TB B ,TMP1 ,TMP2 ,TMP3 ,TMP4 ,TMP5 ,TMP6 WHERE A.RS11_1 = 9 AND B.MA07_1 IS NOT NULL AND B.MA06_1 = A.RS15_1(+) AND TMP1.CODE = B.MA07_1(+) AND TMP1.CODE = TMP2.SSPS_TYP_CD(+) AND TMP1.CODE = TMP3.SSPS_TYP_CD(+) AND TMP1.CODE = TMP5.SSPS_TYP_CD(+) AND TMP1.CODE = TMP6.SSPS_TYP_CD(+)
FROM TMP1 ,TMP2 ,TMP3 ,TMP4 ,TMP5 ,TMP6 WHERE TMP1.CODE = TMP2.SSPS_TYP_CD(+) AND TMP1.CODE = TMP3.SSPS_TYP_CD(+) AND TMP1.CODE = TMP5.SSPS_TYP_CD(+) AND TMP1.CODE = TMP6.SSPS_TYP_CD(+)
AND TMP1.PAR_ID = #{KBN}
AND TMP1.CODE = #{SSPS_TYP_CD}
) T1

