MERGE INTO AML_TB_STRINF_MNG
USING DUAL
   ON (SSPS_TYP_CD = #{SSPS_TYP_CD, jdbcType=VARCHAR})
 WHEN MATCHED
 THEN UPDATE
         SET RULE_DESC1 = #{RULE_DESC1, jdbcType=VARCHAR}
            ,RULE_DESC2 = #{RULE_DESC2, jdbcType=VARCHAR}
            ,RULE_DESC3 = #{RULE_DESC3, jdbcType=VARCHAR}
            ,RULE_DESC4 = #{RULE_DESC4, jdbcType=VARCHAR}
            ,CHG_DATE = TO_CHAR(SYSDATE, 'YYYYMMDD')
            ,CHG_USER = #{CHG_USER, jdbcType=VARCHAR}
 WHEN NOT MATCHED
 THEN INSERT
           (
             SSPS_TYP_CD
            ,RULE_DESC1
            ,RULE_DESC2
            ,RULE_DESC3
            ,RULE_DESC4
            ,REG_DATE
            ,REG_USER
            ,CHG_DATE
            ,CHG_USER
           )
      VALUES
           (
             #{SSPS_TYP_CD, jdbcType=VARCHAR}
            ,#{RULE_DESC1, jdbcType=VARCHAR}
            ,#{RULE_DESC2, jdbcType=VARCHAR}
            ,#{RULE_DESC3, jdbcType=VARCHAR}
            ,#{RULE_DESC4, jdbcType=VARCHAR}
            ,TO_CHAR(SYSDATE, 'YYYYMMDD')
            ,#{CHG_USER, jdbcType=VARCHAR}
            ,TO_CHAR(SYSDATE, 'YYYYMMDD')
            ,#{REG_USER, jdbcType=VARCHAR}
           )

