mapper.select:
SELECT /*+ PARALLEL(4) */ A.CS_NM, --고객명 GET_CODE_NAME('A004',B.RSK_GRD_CD) AS RSK_GRD_CD, --위험등급 CASE B.SSPS_DL_F WHEN '0' THEN 'N' ELSE 'Y' END AS SSPS_DL_F, --혐의거래 CASE (B.STR_RPR_TNO + B.CTR_RPR_TNO) WHEN 0 THEN 'N' ELSE 'Y' END AS RPR_TNO_YN, --보고여부 NVL(B.CS_EDD_MNG_F,'N') AS CS_EDD_ST_CD_NM, --EDD상태 GET_CODE_NAME('M002',A.RNM_CNFR_CCD) AS RNM_CNFR_CCD_NM, --실명구분 A.CS_NO, --실명번호 A.CS_NO AS CS_NO_DEC, A.RNMCNO, GET_CODE_NAME('A009',NVL(A.NTN_CD,'KR')) AS NTN_NM, --국적 TEL.CNTY_NATI_CRYP, --연락처 국가번호 TEL.CNTY_AREA_CRYP, --연락처 지역번호 TEL.CNTY_ECNO_CRYP, --연락처 국번 TEL.CNTY_NO_CRYP, --연락처 번호 ADDR.BSC_ADDR, --기본주소 ADDR.DNG_FLWG_ADDR, --동이하주소 A.RNM_CNFR_CCD, --실명구분 A.INDV_CORP_CCD --개인법인구분 FROM NIC01B A , NIC35B B , (SELECT RNMCNO , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(TEL_NO3), TRIM(SUBSTR(TEL_NO3,1,64)), TRIM(SUBSTR(TEL_NO1,1,64))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(TEL_NO1), TRIM(SUBSTR(TEL_NO1,1,64)), TRIM(SUBSTR(TEL_NO2,1,64))) END AS CNTY_NATI_CRYP , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(TEL_NO3), TRIM(SUBSTR(TEL_NO3,65,64)), TRIM(SUBSTR(TEL_NO1,65,64))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(TEL_NO1), TRIM(SUBSTR(TEL_NO1,65,64)), TRIM(SUBSTR(TEL_NO2,65,64))) END AS CNTY_AREA_CRYP , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(TEL_NO3), TRIM(SUBSTR(TEL_NO3,129,64)), TRIM(SUBSTR(TEL_NO1,129,64))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(TEL_NO1), TRIM(SUBSTR(TEL_NO1,129,64)), TRIM(SUBSTR(TEL_NO2,129,64))) END AS CNTY_ECNO_CRYP , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(TEL_NO3), TRIM(SUBSTR(TEL_NO3,193,64)), TRIM(SUBSTR(TEL_NO1,193,64))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(TEL_NO1), TRIM(SUBSTR(TEL_NO1,193,64)), TRIM(SUBSTR(TEL_NO2,193,64))) END AS CNTY_NO_CRYP FROM ( SELECT RNMCNO, INDV_CORP_CCD , MAX(DECODE(CNTC_TYP_CD,'1',TEL_NO)) AS TEL_NO1 , MAX(DECODE(CNTC_TYP_CD,'2',TEL_NO)) AS TEL_NO2 , MAX(DECODE(CNTC_TYP_CD,'3',TEL_NO)) AS TEL_NO3 FROM ( SELECT X.RNMCNO, Y.INDV_CORP_CCD, X.CNTC_TYP_CD , RPAD(X.CNTY_NATI_CRYP,64,' ')||RPAD(X.CNTY_AREA_CRYP,64,' ')||RPAD(X.CNTY_ECNO_CRYP,64,' ')||RPAD(X.CNTY_NO_CRYP,64,' ') AS TEL_NO FROM NIC04B X , NIC01B Y WHERE 1=1
AND Y.CS_NO = #{CS_NO}
AND X.RNMCNO = Y.RNMCNO ) GROUP BY RNMCNO, INDV_CORP_CCD ) ) TEL , ( SELECT RNMCNO , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(ADDR1), TRIM(SUBSTR(ADDR1,1,320)), TRIM(SUBSTR(ADDR2,1,320))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(ADDR2), TRIM(SUBSTR(ADDR2,1,320)), TRIM(SUBSTR(ADDR1,1,320))) END AS BSC_ADDR , CASE WHEN INDV_CORP_CCD = '1' THEN NVL2(TRIM(ADDR1), TRIM(SUBSTR(ADDR1,321,320)), TRIM(SUBSTR(ADDR2,321,320))) WHEN INDV_CORP_CCD = '2' THEN NVL2(TRIM(ADDR2), TRIM(SUBSTR(ADDR2,321,320)), TRIM(SUBSTR(ADDR1,321,320))) END AS DNG_FLWG_ADDR FROM ( SELECT RNMCNO, INDV_CORP_CCD , MAX(DECODE(ADDR_TYP_CD,'1',ADDR)) AS ADDR1 , MAX(DECODE(ADDR_TYP_CD,'2',ADDR)) AS ADDR2 FROM ( SELECT X.RNMCNO, Y.INDV_CORP_CCD, X.ADDR_TYP_CD , RPAD(X.BSC_ADDR,320,' ')||RPAD(X.DNG_FLWG_ADDR,320,' ') AS ADDR FROM NIC05B X , NIC01B Y WHERE 1=1
AND Y.CS_NO = #{CS_NO}
AND X.RNMCNO = Y.RNMCNO ) GROUP BY RNMCNO, INDV_CORP_CCD ) ) ADDR WHERE A.RNMCNO = B.RNMCNO AND A.RNMCNO = TEL.RNMCNO(+) AND A.RNMCNO = ADDR.RNMCNO(+)
AND A.CS_NO = #{CS_NO}
AND A.RNMCNO = (SELECT RNMCNO FROM NIC17B WHERE TRIM(ACNT_NO) = #{ACNT_NO})
AND A.CS_NM = #{CS_NM}

SELECT * FROM ( SELECT /* PARALLEL(4) */ B.ACNT_NO, B.GNL_AC_NO, (SELECT ACNT_NAME FROM SID.IDO_A_UUA_ACNT_NAME WHERE ACNT_NAME_TYPE_CODE = 'TYPE' AND LANG_CODE = 'KO' AND ACNT_ID = B.GNL_AC_NO ) AC_TYP_CD_NM, B.AC_OPN_DT, (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD=OPN_BRN_CD) AS GDS_OPN_BRN_CD_NM, GET_CODE_NAME('M035',B.AC_ST_CCD) AS GDS_ST_CCD_NM, /* C.LAST_TRDG_DATE AS FNL_DL_DT, */ B.FNL_DL_DT AS FNL_DL_DT, B.CLSD_DT FROM NIC01B A, NIC17B B, /* SID.IDO_A_MAA_CLIENT_ACNT_DTLS C, */ SID.IDO_A_UUA_ACNT D WHERE A.RNMCNO=B.RNMCNO /* AND B.GNL_AC_NO = C.ACNT_ID(+) */ AND B.GNL_AC_NO = D.ACNT_ID AND D.ACNT_TYPE_CODE IN ('GNAC','FOAC','FPAC','SVAC')
AND A.CS_NO = #{CS_NO}
) X WHERE 1=1
AND TRIM(ACNT_NO) LIKE '%' || #{ACNT_NO} || '%'

SELECT A.GNL_AC_NO, B.ACNT_NO, A.GDS_NO, A.DL_DT, SUBSTR(A.DL_TM,1,2)||':'||SUBSTR(A.DL_TM,3,2)||':'||SUBSTR(A.DL_TM,5,2) AS DL_TM, A.DL_SQ, A.DL_AMT, A.TFND_RA , GET_CODE_NAME('M046', A.DL_WY_CD) DL_WY_CD_NM , A.CHCK_AMT , GET_CODE_NAME('M048', A.CRNCY_CD) CRNCY_CD_NM , GET_CODE_NAME('M044', A.DL_CHNNL_CD) DL_CHNNL_CD_NM , GET_CODE_NAME('M045', A.DL_TYP_CD) STR_DL_KND_CD_NM, (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD=A.HANDLNG_BRN_CD) HANDLNG_BRN_CD_NM FROM NIC61B A, NIC17B B WHERE A.GNL_AC_NO = B.GNL_AC_NO AND A.GNL_AC_NO = #{GNL_AC_NO} AND A.DL_DT >= #{sDate} AND A.DL_DT <= #{eDate}
AND A.DL_TYP_CD = #{DL_TYP_CD}
ORDER BY A.DL_DT DESC, A.DL_SQ DESC

SELECT A.GNL_AC_NO ,A.GDS_NO ,A.GNL_AC_NO || '-' || A.GDS_NO AS GNL_GDS_NO ,A.DL_DT ,A.DL_SQ ,A.DL_AMT ,A.TFND_RA ,GET_CODE_NAME('M046', A.DL_WY_CD) AS DL_WY_CD_NM ,A.CHCK_AMT ,NVL(A.CRNCY_CD, 'KRW') AS CRNCY_CD_NM ,GET_CODE_NAME('M044', A.DL_CHNNL_CD) AS DL_CHNNL_CD_NM ,GET_CODE_NAME('M045', A.DL_TYP_CD) AS STR_DL_KND_CD_NM ,(SELECT I.DPRT_NM FROM NIC41B I WHERE I.DPRT_CD = A.HANDLNG_BRN_CD ) AS HANDLNG_BRN_CD_NM ,CASE A.CNCL_F WHEN 'Y' THEN 'CANCEL' ELSE '' END AS CNCL_F FROM NIC61B A ,NIC17B B WHERE A.GNL_AC_NO = B.GNL_AC_NO AND A.GDS_NO = B.GDS_NO AND A.GNL_AC_NO IN #{GNL_AC_NO_LIST}
AND A.GDS_NO IN #{GDS_NO_LIST}
AND A.DL_DT IN #{DL_DT_LIST}
AND A.DL_SQ IN #{DL_SQ_LIST}

SELECT COUNT(*) AS CNT
  FROM NIC10B A
 WHERE A.RNMCNO  = #{DL_P_RNMCNO}

SELECT COUNT(*) AS CNT
  FROM NIC14B A
 WHERE A.RNMCNO  = #{DL_P_RNMCNO}

