INSERT INTO NIC71B
     ( SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,GNL_AC_NO
      ,GDS_NO
      ,HNDL_DY_TM
      ,HNDL_P_ENO
      ,GDS_OPN_DT
      ,GDS_OPN_BRN_CD
      ,MN_DL_DPRT_CD
      ,RNMCNO
      ,CS_NM
      ,DPT_CD
      ,AC_OPN_OBJ_CCD
      ,DL_GDS_CD
      ,EXPR_DATE
      ,AC_OPN_PRXY_F
      ,AC_OPN_BRN_NM
      ,AC_OPN_BRN_PST_NO
      ,MN_DL_DPRT_NM
     )
VALUES
     ( #{SSPS_DL_CRT_DT}
      ,#{SSPS_DL_ID}
      ,#{GNL_AC_NO}
      ,#{GDS_NO}
      ,SYSDATE
      ,#{HNDL_P_ENO}
      ,#{SSPS_DL_CRT_DT}
      ,#{SESS_AML_BDPT_CD}
      ,#{SESS_AML_BDPT_CD}
      ,#{DL_P_RNMCNO}
      ,(SELECT X.CS_NM FROM NIC01B X WHERE X.RNMCNO  = #{DL_P_RNMCNO})
      ,#{SESS_AML_BDPT_CD}
      ,'99'               /* NIC17B.AC_RE_OBJ_CCD : 계좌개설목적코드_M038 : 99 기타(기재_____)*/
      ,''                 /* DL_GDS_CD 보고파일에서 사용하지 않아 비워둠 */
      ,'99991231'         /* 만기일자 */
      ,'N'                /* 계좌개설대리인여부 */
      ,#{SESS_DEPT_NAME}
      ,(SELECT A.DPRT_POST_NO
          FROM NIC41B A
         WHERE A.DPRT_CD = #{SESS_AML_BDPT_CD}
       )
      ,#{SESS_DEPT_NAME}
     )

