SELECT -- T1.* SELECTED ,SSPS_DL_CRT_DT --혐의거래생성일자 ,SSPS_DL_ID --혐의거래ID ,SSPS_DL_CRT_DT_A ,DL_P_NM --거래자명 ,XML_FILE_EDIT --보고파일 ,A_DL_P_RNMCNO AS DL_P_RNMCNO -- 고객ID ,DL_P_RNM_NO_CCD_NM --실명구분 ,SSPS_TYP_NM --혐의명 ,C_RNMCNO AS RNMCNO -- 실명확인번호 ,DL_AMT --거래금액 ,FIU_RPT_TYPE_NM --보고상태 ,FIU_SEND_PRBL_NM --송수신장애 ,RPR_DT --보고일자 ,DOC_NO --문서번호 ,RE_SEND --재보고(문서종류코드가 재보고요청이면 '재보고' 표시) ,FIU_NO --KoFIU 등록번호 ,FIU_REG_DT --KoFIU 등록일 ,SSPS_TYP_CD --혐의유형코드 ,SND_RCPT_FILE_NM --KoFIU보고파일명 ,MN_DL_BRN_CD --혐의거래분석지점코드 ,MN_DL_BRN_NM --혐의거래분석지점명 ,OK_CCD --확인보고제외 ,DL_P_RNM_NO_CCD --실명구분코드 ,RPR_PRGRS_CCD --확인코드 ,INDV_CORP_CCD --개인법인구분 ,FIU_TMSG_TRA_C --전문트랜잭션코드 ,FIU_TMSG_ID --전문ID ,FIU_TMSG_TRX_DT --전문거래일시 ,FIU_RPT_TYPE_C --보고메세지유형코드 ,FIU_SEND_PRBL_C --송수신장애코드 ,RPT_DOC_NO --보고문서번호 ,DOC_KIND_CD --문서종류코드 ,A_DL_P_RNMCNO --,DL_P_RNMCNO --실명번호 ,A_RNMCNO --,RNMCNO ,BTN_SAVE_F ,SND_BEFORE_RCPT_DOC_NO --종전문서번호 FROM (SELECT '0' AS SELECTED ,A.SSPS_DL_CRT_DT --혐의거래생성일자 ,A.SSPS_DL_ID --혐의거래ID ,A.SSPS_DL_CRT_DT || '-' || REPLACE(A.SSPS_DL_ID, 'CTR', 'STR') AS SSPS_DL_CRT_DT_A ,B.DL_P_NM --거래자명 ,(CASE WHEN ( F.DOC_KIND_CD = 'REP001' AND F.FIU_RPT_TYPE_C = '04') OR (F.DOC_KIND_CD = 'FIU004') THEN '수정' ELSE '미리보기' END) AS XML_FILE_EDIT --보고파일 ,A.DL_P_RNMCNO AS A_DL_P_RNMCNO -- 고객ID ,GET_CODE_NAME('M002', B.DL_P_RNM_NO_CCD) AS DL_P_RNM_NO_CCD_NM --실명구분 ,GET_SYNARIO_NAME(A.SSPS_TYP_CD) AS SSPS_TYP_NM --혐의명 ,C.RNMCNO AS C_RNMCNO -- 실명확인번호 ,(SELECT SUM(X1.DL_AMT) FROM NIC75B X1 WHERE X1.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X1.SSPS_DL_ID = A.SSPS_DL_ID ) AS DL_AMT --거래금액 ,GET_CODE_NAME('F002', F.FIU_RPT_TYPE_C) AS FIU_RPT_TYPE_NM --보고상태 ,GET_CODE_NAME('F004', F.FIU_SEND_PRBL_C) AS FIU_SEND_PRBL_NM --송수신장애 ,A.RPR_DT --보고일자 ,E.SND_RCPT_DOC_NO AS DOC_NO --문서번호 ,CASE WHEN A.RPR_PRGRS_CCD IN ('9', '10', '99') THEN 'download' END AS TRSMT_ST_NM --KoFIU보고파일 ,DECODE((SELECT COUNT(*) FROM NIC64B X2 WHERE X2.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X2.SSPS_DL_ID = A.SSPS_DL_ID ) , 0, 'No', 'Yes' ) AS FILE_ATT_YN --첨부파일 ,(CASE WHEN ( F.DOC_KIND_CD = 'REP001' AND F.FIU_RPT_TYPE_C = '04') OR (F.DOC_KIND_CD = 'FIU004') THEN '재보고' ELSE '' END) AS RE_SEND --재보고(문서종류코드가 재보고요청이면 '재보고' 표시) ,E.FIU_NO --KoFIU 등록번호 ,E.FIU_REG_DT --KoFIU 등록일 ,A.SSPS_TYP_CD --혐의유형코드 ,E.SND_RCPT_FILE_NM --KoFIU보고파일명 ,A.SSPS_DL_ANLYS_BRN_CD AS MN_DL_BRN_CD --혐의거래분석지점코드 ,A.SSPS_DL_ANLYS_BRN_NM AS MN_DL_BRN_NM --혐의거래분석지점명 ,A.OK_CCD --확인보고제외 ,B.DL_P_RNM_NO_CCD --실명구분코드 ,A.RPR_PRGRS_CCD --확인코드 ,B.INDV_CORP_CCD --개인법인구분 ,F.FIU_TMSG_TRA_C --전문트랜잭션코드 ,F.FIU_TMSG_ID --전문ID ,F.FIU_TMSG_TRX_DT --전문거래일시 ,F.FIU_RPT_TYPE_C --보고메세지유형코드 ,F.FIU_SEND_PRBL_C --송수신장애코드 ,F.RPT_DOC_NO --보고문서번호 ,F.DOC_KIND_CD --문서종류코드 ,A.DL_P_RNMCNO AS A_RNMCNO ,(CASE WHEN ( F.DOC_KIND_CD = 'REP001' AND F.FIU_RPT_TYPE_C = '04') OR (F.DOC_KIND_CD = 'FIU004') THEN 'Y' ELSE 'N' END) AS BTN_SAVE_F ,E.SND_BEFORE_RCPT_DOC_NO --종전문서번호 FROM NIC66B A /* 혐의거래추출내역 */ ,NIC70B B /* 혐의거래고객공통정보 */ ,NIC01B C /* 고객통합기본 */ ,NIC35B D /* 고객AML정보 */ ,NIC80B E /* 혐의거래일별보고정보 */ ,(SELECT T2.SSPS_DL_CRT_DT ,T2.SSPS_DL_ID ,T2.FIU_TMSG_TRX_DT ,T2.FIU_TMSG_ID ,T2.FIU_RPT_TYPE_C ,T2.FIU_SEND_PRBL_C ,T2.DOC_KIND_CD ,T2.RPT_DOC_NO ,T2.FIU_TMSG_TRA_C FROM (SELECT G.SSPS_DL_CRT_DT --혐의거래생성일자 ,G.SSPS_DL_ID --혐의거래ID ,G.FIU_TMSG_TRX_DT --전문거래일 ,G.FIU_TMSG_ID --전문ID ,G.FIU_RPT_TYPE_C --보고메세지유형코드 ,G.FIU_SEND_PRBL_C --송수신장애코드 ,G.DOC_KIND_CD --문서종류코드 ,G.RPT_DOC_NO --보고문서번호 ,G.FIU_TMSG_TRA_C --전문트랜잭션코드 ,ROW_NUMBER() OVER(PARTITION BY G.SSPS_DL_CRT_DT, G.SSPS_DL_ID ORDER BY G.FIU_TMSG_TRX_DT DESC) AS RNUM FROM FIU04B G ,NIC66B H WHERE G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT AND G.SSPS_DL_ID = H.SSPS_DL_ID
AND G.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
) T2 WHERE T2.RNUM = 1 ) F WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = B.DL_P_RNMCNO (+) AND A.DL_P_RNMCNO = C.RNMCNO (+) AND A.DL_P_RNMCNO = D.RNMCNO (+) AND A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = E.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = F.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND A.INST_ID != 1 --결재ID AND A.RPR_PRGRS_CCD IN ('9', '10', '99') --(9:결재완료, 10:보고완료, 99:파일생성) ) T1
WHERE T1.SSPS_DL_CRT_DT >= #{startDate}
AND T1.SSPS_DL_CRT_DT <= #{endDate}
AND #{branchCode} IN (SELECT X3.MN_DL_BRN_CD FROM NIC73B X3 WHERE X3.SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND X3.SSPS_DL_ID = T1.SSPS_DL_ID )
AND T1.OK_CCD = #{OK_CCD}
AND UPPER(T1.DL_P_NM) LIKE '%' || UPPER(#{DL_P_NM}) || '%'
AND T1.DL_P_RNMCNO LIKE '%' || #{RNMCNO} || '%'
AND T1.FIU_RPT_TYPE_C = #{FIU_RPT_TYPE_C}
AND T1.FIU_SEND_PRBL_C = #{FIU_SEND_PRBL_C}
ORDER BY T1.SSPS_DL_CRT_DT DESC ,T1.SSPS_DL_ID

SELECT '0' AS SELECTED ,GET_CODE_NAME('A103', A.RPR_CCD) AS RPR_NM --상태(보고구분코드명) ,A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A --혐의거래일 ,FN_CDINFO_VAR('DT', C.DL_DT || C.DL_TM, '') AS DL_DT_TM_VIEW --거래발생일 ,FN_NIC70B_INFO(A.SSPS_DL_CRT_DT, A.DL_P_RNMCNO , 'DL_P_NM') AS DL_P_NM --거래자명 ,(CASE WHEN ( F.DOC_KIND_CD IN ('FEP002', 'FIU001') AND F.FIU_SEND_PRBL_C != '000' ) THEN '수정' ELSE '미리보기' END) AS XML_FILE_EDIT --보고파일(Click) ,A.DL_P_RNMCNO --실명번호 ,A.RNM_PR_DL_SQ --순번 ,GET_CODE_NAME('M062', C.CTR_DL_KND_CD) AS CTR_DL_KND_CD_NM --종류 ,TO_CHAR(C.CSH, 'FM999,999,999,999') AS CSH --거래금액 ,CASE WHEN CTR_DL_KND_CD IN ('11', '12') THEN B.GNL_AC_NO ELSE '' END GNL_AC_NO_FULL --계좌번호 ,CASE WHEN CTR_DL_KND_CD IN ('21', '22') THEN NVL(D.CPRTY_TRSNS_AC_NO, B.GNL_AC_NO) END AS CPRTY_TRSNS_AC_NO --수취인계좌 ,GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) AS RPR_CCD_NM --진행상태 ,FN_CDINFO_VAR('DPT', C.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM --거래점 ,GET_CODE_NAME('F002', F.FIU_RPT_TYPE_C) AS FIU_RPT_TYPE_NM --보고상태 ,GET_CODE_NAME('F004', F.FIU_SEND_PRBL_C) AS FIU_SEND_PRBL_NM --송수신장애여부 ,CASE WHEN A.RPR_PRGRS_CCD in ('99', '10') THEN TRIM(A.RPR_DOC_NO_DL_YR) || '-' || TRIM(TO_CHAR(A.RPR_DOC_NO_FNL_SQ, '0000000')) END RPR_DOC_NO_FNL_SQ --문서번호 ,CASE WHEN A.RPR_PRGRS_CCD in ('99', '10') THEN TRIM(A.DOC_NO_YR) || '-' || TRIM(TO_CHAR(A.DOC_SQ, '0000000')) END DOC_SQ --대표문서번호 ,(SELECT CASE WHEN (SELECT X1.RPR_PRGRS_CCD || X1.OK_CCD FROM NIC66B X1 WHERE X1.SSPS_DL_CRT_DT = T5.SSPS_DL_CRT_DT AND X1.SSPS_DL_ID = T5.SSPS_DL_ID ) = '92' THEN '' ELSE DECODE(A.RPR_DOC_NO_DL_YR, NULL, '', A.RPR_DOC_NO_DL_YR || '-') || DECODE(A.RPR_DOC_NO_FNL_SQ, '0', '', TRIM(LPAD(A.RPR_DOC_NO_FNL_SQ, '7', '0'))) END FROM NIC84B T5 WHERE T5.ORG_SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND T5.ORG_SSPS_DL_ID = A.SSPS_DL_ID AND T5.RPR_DOC_NO_DL_YR = A.RPR_DOC_NO_DL_YR AND T5.RPR_DOC_NO_FNL_SQ = A.RPR_DOC_NO_FNL_SQ AND ROWNUM = 1 ) AS RPR_DOC_NO_FNL_SQ_CAN --취소문서번호 ,CASE WHEN A.RPR_PRGRS_CCD IN ('9', '99', '10') THEN 'DOWNLOAD' END AS TRSMT_ST_NM --KoFIU보고파일 ,A.CORT_CNCL_RSN_CNTNT -- 정정/취소보고사유 ,E.SND_RCPT_FILE_NM AS KOFIU_FILE --KoFIU보고파일명 ,E.FIU_NO --KoFIU 등록번호 ,E.FIU_REG_DT --KoFIU 등록일 ,A.RPR_PRGRS_CCD --보고진행구분코드 ,A.OK_CCD --확인보고제외 ,A.RPR_CCD --보고구분코드 ,F.FIU_RPT_TYPE_C --보고메세지유형코드 ,F.FIU_SEND_PRBL_C --송수신장애코드 ,A.SSPS_DL_CRT_DT --혐의거래생성일자 ,A.SSPS_DL_ID --혐의거래ID ,A.DL_P_RNMCNO --실명번호 ,(CASE WHEN ( F.DOC_KIND_CD IN ('FEP002', 'FIU001') AND F.FIU_SEND_PRBL_C != '000' ) THEN 'Y' ELSE 'N' END) AS BTN_SAVE_F FROM NIC66B A /* 혐의거래추출내역 */ ,NIC71B B /* 혐의거래게좌정보 */ ,NIC75B C /* 혐의거래거래내역 */ ,NIC83B D /* 혐의거래송금내역 */ ,NIC80B E /* 혐의거래일별보고정보 */ ,(SELECT T1.SSPS_DL_CRT_DT ,T1.SSPS_DL_ID ,T1.FIU_RPT_TYPE_C ,T1.FIU_SEND_PRBL_C ,T1.DOC_KIND_CD FROM (SELECT I.SSPS_DL_CRT_DT ,I.SSPS_DL_ID ,I.FIU_RPT_TYPE_C ,I.FIU_SEND_PRBL_C ,I.DOC_KIND_CD ,ROW_NUMBER() OVER(PARTITION BY I.SSPS_DL_CRT_DT, I.SSPS_DL_ID ORDER BY I.FIU_TMSG_TRX_DT DESC) AS RNUM FROM FIU04B I ,NIC66B J WHERE 1 = 1 AND I.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT --혐의거래생성일자 AND I.SSPS_DL_ID = J.SSPS_DL_ID --혐의거래ID
AND I.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
) T1 WHERE T1.RNUM = 1 ) F WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.GDS_NO = C.GDS_NO AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.SSPS_DL_ID = D.SSPS_DL_ID(+) AND C.GNL_AC_NO = D.GNL_AC_NO(+) AND C.GDS_NO = D.GDS_NO(+) AND C.DL_DT = D.DL_DT(+) AND C.DL_SQ = D.DL_SQ(+) AND A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = E.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = F.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_CCD IN ('CTR', 'CAC') AND A.RPR_PRGRS_CCD IN ('9', '10', '99')
AND A.SSPS_DL_CRT_DT >= #{startDate}
AND A.SSPS_DL_CRT_DT <= #{endDate}
AND #{branchCode} IN (SELECT X2.MN_DL_BRN_CD FROM NIC73B X2 WHERE X2.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X2.SSPS_DL_ID = A.SSPS_DL_ID )
AND A.OK_CCD = #{OK_CCD}
AND A.DL_P_RNMCNO LIKE '%' || #{RNMCNO} || '%'
AND F.FIU_RPT_TYPE_C = #{FIU_RPT_TYPE_C}
AND F.FIU_SEND_PRBL_C = #{FIU_SEND_PRBL_C}
AND A.DL_P_RNMCNO IN (SELECT DISTINCT X3.RNMCNO FROM NIC01B X3 WHERE X3.CS_NM LIKE '%' || UPPER(#{DL_P_NM}) || '%' )
ORDER BY A.SSPS_DL_CRT_DT DESC ,A.SSPS_DL_ID ,A.DL_P_RNMCNO ,C.DL_TM

SELECT '0' AS SELECTED ,A.FIU_TMSG_VER ,TO_CHAR(A.FIU_TMSG_ID) AS FIU_TMSG_ID -- 전문ID ,A.FIU_TMSG_KOR_NM -- 전문한글명 ,A.FIU_TMSG_ENG_NM -- 전문영문명 ,A.FIU_SEND_FRQ_C -- 발송주기 ,A.FIU_TMSG_LEN -- 전문길이 ,A.FIU_ALL_COMN_YN -- 전사공통여부 ,A.FIU_IF_COMN_YN -- 인터페이스 공통여부 ,A.FIU_BAS_COMN_YN -- 기간계 공통여부 ,A.FIU_TMSG_COMN_YN -- 전문(KoFIU) 공통여부 ,A.FIU_INDV_COMN_YN -- 전문개발공통여부 ,A.FIU_TMSG_DESC -- 전문설명 ,TO_CHAR(TO_DATE(A.DR_DH, 'YYYYMMDDHH24MISS'), 'YYYY-MM-YY HH24:MI:SS') AS DR_DH -- 등록일 --,GET_USER_NAME(A.DR_OP_JKW_NO) AS DR_OP_JKW_NO -- 등록자 ,A.DR_OP_JKW_NO ,TO_CHAR(TO_DATE(A.CHG_DH, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS CHG_DH -- 등록일 --,GET_USER_NAME(A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NO -- 변경자 ,A.CHG_OP_JKW_NO ,(SELECT SUBSTR(MAX(I.FIU_ITEM_ID), 9, 11) FROM FIU02B I WHERE I.FIU_TMSG_VER = A.FIU_TMSG_VER AND I.FIU_TMSG_ID = A.FIU_TMSG_ID ) AS MAX_ITEM_ID ,(SELECT MAX(J.FIU_ITEM_ORD) FROM FIU02B J WHERE J.FIU_TMSG_VER = A.FIU_TMSG_VER AND J.FIU_TMSG_ID = A.FIU_TMSG_ID ) AS MAX_ORD FROM FIU01B A WHERE 1 = 1
AND A.FIU_TMSG_ID = #{FIU_TMSG_ID}
AND ( A.FIU_TMSG_KOR_NM LIKE '%' || #{FIU_NM, jdbcType=VARCHAR} || '%' OR UPPER(A.FIU_TMSG_ENG_NM) LIKE '%' || UPPER(#{FIU_NM, jdbcType=VARCHAR}) || '%' )

mapper.insert:
INSERT INTO FIU01B
     ( FIU_TMSG_VER
      ,FIU_TMSG_ID               -- 전문ID
      ,FIU_TMSG_KOR_NM           -- 전문한글명
      ,FIU_TMSG_ENG_NM           -- 전문영문명
      ,FIU_SEND_FRQ_C            -- 발송주기
      ,FIU_TMSG_LEN              -- 전문길이
      ,FIU_ALL_COMN_YN           -- 전사공통여부
      ,FIU_IF_COMN_YN            -- 인터페이스 공통여부
      ,FIU_BAS_COMN_YN           -- 기간계 공통여부
      ,FIU_TMSG_COMN_YN          -- 전문(KoFIU) 공통여부
      ,FIU_INDV_COMN_YN          -- 전문개발공통여부
      ,FIU_TMSG_DESC             -- 전문설명
      ,DR_DH                     -- 등록일시
      ,DR_OP_JKW_NO              -- 등록자
     )
VALUES
     ( #{FIU_TMSG_VER, jdbcType=VARCHAR}
      ,#{FIU_TMSG_ID, jdbcType=VARCHAR}
      ,#{FIU_TMSG_KOR_NM, jdbcType=VARCHAR}
      ,#{FIU_TMSG_ENG_NM, jdbcType=VARCHAR}
      ,#{FIU_SEND_FRQ_C, jdbcType=VARCHAR}
      ,#{FIU_TMSG_LEN, jdbcType=VARCHAR}
      ,#{FIU_ALL_COMN_YN, jdbcType=VARCHAR}
      ,#{FIU_IF_COMN_YN, jdbcType=VARCHAR}
      ,#{FIU_BAS_COMN_YN, jdbcType=VARCHAR}
      ,#{FIU_TMSG_COMN_YN, jdbcType=VARCHAR}
      ,#{FIU_INDV_COMN_YN, jdbcType=VARCHAR}
      ,#{FIU_TMSG_DESC, jdbcType=VARCHAR}
      ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
     )

mapper.delete:
DELETE
  FROM FIU01B
 WHERE FIU_TMSG_ID = #{FIU_TMSG_ID}

DELETE
  FROM FIU02B
 WHERE FIU_TMSG_ID = #{FIU_TMSG_ID}

DELETE
  FROM FIU02B
 WHERE FIU_TMSG_ID = #{FIU_TMSG_ID, jdbcType=VARCHAR}
   AND FIU_ITEM_ID = #{FIU_ITEM_ID, jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(*) AS COUNT
  FROM FIU02B
 WHERE FIU_TMSG_ID = #{FIU_TMSG_ID, jdbcType=VARCHAR}

SELECT ROW_NUMBER() OVER(PARTITION BY SUBSTR(A.FIU_TMSG_TRX_DH, 1, 8) ORDER BY A.FIU_TMSG_TRX_DH) AS RNUM --순번 ,A.FIU_TMSG_ID --전문ID ,(SELECT I.FIU_TMSG_KOR_NM FROM FIU01B I WHERE I.FIU_TMSG_ID = A.FIU_TMSG_ID ) AS FIU_TMSG_NM --전문ID ,A.FIU_TMSG_TRA_C ,A.FIU_TMSG_TRX_SEQ ,CASE WHEN A.FIU_TMSG_TRX_DH IS NOT NULL THEN SUBSTR(A.FIU_TMSG_TRX_DH, 1, 4) || '-' || SUBSTR(A.FIU_TMSG_TRX_DH, 5, 2) || '-' || SUBSTR(A.FIU_TMSG_TRX_DH, 7, 2) || ' ' || SUBSTR(A.FIU_TMSG_TRX_DH, 9, 2) || ':' || SUBSTR(A.FIU_TMSG_TRX_DH, 11, 2) || ':' || SUBSTR(A.FIU_TMSG_TRX_DH, 13, 2) ELSE '' END AS FIU_TMSG_TRX_DH --전문거래일시 ,A.FIU_SEND_G_C --송수신구분코드 ,GET_CODE_NAME('F005', A.FIU_SEND_G_C) AS FIU_SEND_NM ,A.FIU_RPT_TYPE_C --보고메세지유형코드 ,GET_CODE_NAME('F002', A.FIU_RPT_TYPE_C) AS FIU_RPT_TYPE_NM ,A.FIU_SEND_PRBL_C --송수신장애코드 ,GET_CODE_NAME('F004', A.FIU_SEND_PRBL_C) AS FIU_SEND_PRBL_NM ,CASE WHEN A.SSPS_DL_CRT_DT IS NULL THEN '' ELSE A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID END AS SSPS_DL_ID --혐의거래일 ,A.FIU_TRX_COMN_DATA --전문공통 ,A.FIU_USER_ID --사용자ID ,CASE WHEN A.DR_DH IS NOT NULL THEN SUBSTR(A.DR_DH, 1, 4) || '-' || SUBSTR(A.DR_DH, 5, 2) || '-' || SUBSTR(A.DR_DH, 7, 2) || ' ' || SUBSTR(A.DR_DH, 9, 2) || ':' || SUBSTR(A.DR_DH, 11, 2) || ':' || SUBSTR(A.DR_DH, 13, 2) ELSE '' END AS DR_DH --등록일시 ,A.DR_OP_JKW_NO --등록조작자번호 ,CASE WHEN A.CHG_DH IS NOT NULL THEN SUBSTR(A.CHG_DH, 1, 4) || '-' || SUBSTR(A.CHG_DH, 5, 2) || '-' || SUBSTR(A.CHG_DH, 7, 2) || ' ' || SUBSTR(A.CHG_DH, 9, 2) || ':' || SUBSTR(A.CHG_DH, 11, 2) || ':' || SUBSTR(A.CHG_DH, 13, 2) ELSE '' END AS CHG_DH --변경일시 ,A.CHG_OP_JKW_NO --변경조작자번호 FROM FIU03B A WHERE 1 = 1
AND A.FIU_TMSG_TRX_DH >= #{startDate} ||'000000'
AND A.FIU_TMSG_TRX_DH <= #{endDate} ||'235959'
AND A.FIU_TMSG_ID = #{FIU_TMSG_ID}
AND A.FIU_SEND_G_C = #{FIU_SEND_G_C}
AND A.FIU_RPT_TYPE_C = #{FIU_RPT_TYPE_C}
AND A.FIU_SEND_PRBL_C = #{FIU_SEND_PRBL_C}

mapper.insert:
INSERT INTO NIC80B_LOG
     ( SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,SQ
      ,PROC_FALG
      ,PROC_CTNT
      ,HNDL_DY_TM
      ,HNDL_P_ENO
     )
VALUES
     ( #{SSPS_DL_CRT_DT}
      ,#{SSPS_DL_ID}
      ,(SELECT NVL(MAX(A.SQ), 0) + 1
          FROM NIC80B_LOG A
         WHERE A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
           AND A.SSPS_DL_ID = #{SSPS_DL_ID}
       )
      ,#{PROC_FALG}
      ,#{PROC_CTNT}
      ,SYSDATE
      ,#{HNDL_P_ENO}
     )

mapper.select:
SELECT RNMCNO AS RNMCNO ,RNMCNO ,RPAD(SUBSTR(RNMCNO,1,LENGTH(RNMCNO)-6),LENGTH(RNMCNO),'*') AS RNMCNO_VIEW ,CS_NM ,(SELECT RPAD(SUBSTR(GNL_AC_NO,1,8),14,'*') AS GNL_AC_NO_VIEW FROM NIC17B WHERE RNMCNO = A.RNMCNO AND ROWNUM = 1) AS GNL_AC_NO_VIEW ,RNM_CNFR_CCD ,GET_CODE_NAME('M002',TRIM(RNM_CNFR_CCD)) AS RNM_CNFR_CCD_NM ,CORP_RGST_NO ,NVL(TRIM(NTN_CD),'KR') AS NTN_CD ,GET_CODE_NAME('M004',NVL(TRIM(NTN_CD),'KR')) AS NTN_NM ,INDV_CORP_CCD ,DECODE(INDV_CORP_CCD,'1','개인','2','법인',INDV_CORP_CCD) AS INDV_CORP_CCD_NM ,AML_JOB_GUBN ,LG_AMT_ASTS_F ,CS_DLT_DT FROM NIC01B A WHERE 1=1
AND RNMCNO = #{RNMCNO}
AND RNMCNO LIKE #{RNMCNO}||'%'
AND CS_NM LIKE #{CS_NM}||'%'
AND CS_NM = #{CS_NM}
AND RNMCNO IN (SELECT RNMCNO FROM NIC17B WHERE GNL_AC_NO = #{GNL_AC_NO})

SELECT A.CNTNT ,A.CD_NM ,(SELECT CD_NM FROM NIC91B WHERE CD = A.CD) AS GR_CD_NM FROM NIC92B A WHERE A.CD = #{SCH_CD}
AND (A.CNTNT LIKE #{SCH_VAL}||'%' OR A.CD_NM LIKE '%'||#{SCH_VAL}||'%')
AND A.USE_F = 'Y' ORDER BY CD_RNK_SQ

SELECT GET_CODE_NAME('M056', '01') AS RELATIONROLE -- 의심거래자일 경우 ,'01' AS RELATIONROLECODE -- 거래역할코드 ,A.INDV_CORP_CCD AS INDV_CORP_CCD -- 개인법인구분코드 ,NVL(DECODE(TRIM(A.DL_P_RNM_NO_CCD), '04', (SELECT TRIM(W.DL_P_PSPT_NO) FROM NIC78B W WHERE W.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND W.DL_P_RNMCNO = A.DL_P_RNMCNO ), TRIM(A.CS_NO) ), TRIM(A.CS_NO) ) AS REALNUMBERCONFIRM -- 의심거래자 실명번호 확인? ,TRIM(A.CS_NO) AS REALNUMBER -- 의심거래자 실명번호 ,TRIM(A.DL_P_RNM_NO_CCD) AS REALNUMBERCODE -- 의심거래자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(A.DL_P_RNM_NO_CCD)) AS REALNUMBERCODENAME ,'' INSURELDESC -- 의심거래자 거래자와의 관계 ,'' PARREALNUMBER -- 관계구분 ,A.DL_P_NM -- 성명 ,GET_CODE_NAME('M004', TRIM(A.DL_P_NTNLT_CD)) AS NATIONALITY --국가명 ,TRIM(A.DL_P_NTNLT_CD) AS NATIONALITYCODE --국가코드 ,A.DL_P_RNMCNO AS RNMCNO FROM NIC70B A ,NIC66B B ,NIC75B C WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = B.DL_P_RNMCNO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND C.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND C.SSPS_DL_ID = #{SSPS_DL_ID} AND C.GNL_AC_NO = #{GNL_AC_NO} AND C.GDS_NO = #{GDS_NO} AND C.DL_DT = #{DL_DT} AND C.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '02') AS RELATIONROLE -- 의심거래자 대표자일 경우 ,'02' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(D.RPRST_P_RNMCNO) AS REALNUMBERCONFIRM -- 의심거래자 실명번호 확인? ,TRIM(D.RPRST_P_RNMCNO) AS REALNUMBER -- 의심거래자 실명번호 ,TRIM(D.RPRST_P_RNM_CNFR_CCD) AS REALNUMBERCODE -- 의심거래자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(D.RPRST_P_RNM_CNFR_CCD)) AS REALNUMBERCODENAME ,'' AS INSURELDESC -- 의심거래자 거래자와의 관계 ,D.CS_NO AS PARREALNUMBER -- 관계구분 ,D.RPRST_P_NM -- 성명 ,GET_CODE_NAME('M004', TRIM(D.RPRST_P_NTNLT)) AS NATIONALITY --국가명 ,TRIM(D.RPRST_P_NTNLT) AS NATIONALITYCODE --국가코드 ,D.RNMCNO AS RNMCNO FROM NIC03B A ,NIC01B D ,NIC66B E ,NIC75B F WHERE A.RNMCNO = E.DL_P_RNMCNO AND E.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND E.SSPS_DL_ID = F.SSPS_DL_ID AND A.RNMCNO = D.RNMCNO AND TRIM(A.RPRST_P_RNMCNO) IS NOT NULL AND TRIM(A.RPRST_P_RNM_CNFR_CCD) IS NOT NULL AND TRIM(A.RPRST_P_NTNLT) IS NOT NULL AND TRIM(D.RPRST_P_HSE_PST_NO) IS NOT NULL AND TRIM(A.RPRST_P_TEL_NO) IS NOT NULL AND F.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND F.SSPS_DL_ID = #{SSPS_DL_ID} AND F.GNL_AC_NO = #{GNL_AC_NO} AND F.GDS_NO = #{GDS_NO} AND F.DL_DT = #{DL_DT} AND F.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '03') AS RELATIONROLE -- 거래대리인일 경우 ,'03' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(G.PRXY_RNMCNO) AS REALNUMBERCONFIRM -- 거래대리인 실명번호 확인 ,TRIM(G.PRXY_RNMCNO) AS REALNUMBER -- 거래대리인 실명번호 ,TRIM(G.PRXY_RNM_NO_CCD) AS REALNUMBERCODE -- 거래대리인 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(G.PRXY_RNM_NO_CCD)) AS REALNUMBERCODENAME ,GET_CODE_NAME('M042', TRIM(G.AC_OWN_P_RLTNS_CD)) AS INSURELDESC ,'' AS PARREALNUMBER ,G.PRXY_NM --성명 ,GET_CODE_NAME('M004', TRIM(G.PRXY_NTNLT_CD)) AS NATIONALITY --국가명 ,TRIM(G.PRXY_NTNLT_CD) AS NATIONALITYCODE --국가코드 ,'' AS RNMCNO FROM NIC98B G ,NIC75B H WHERE G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT AND G.SSPS_DL_ID = H.SSPS_DL_ID AND G.GNL_AC_NO = H.GNL_AC_NO AND G.GDS_NO = H.GDS_NO AND G.DL_DT = H.DL_DT AND G.DL_SQ = H.DL_SQ AND TRIM(G.PRXY_RNMCNO) IS NOT NULL AND TRIM(G.PRXY_RNM_NO_CCD) IS NOT NULL AND H.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND H.SSPS_DL_ID = #{SSPS_DL_ID} AND H.GNL_AC_NO = #{GNL_AC_NO} AND H.GDS_NO = #{GDS_NO} AND H.DL_DT = #{DL_DT} AND H.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '08') AS REALATIONROLE -- 관련계좌 개설자일 경우 ,'08' AS RELATIONROLECODE -- 거래역할 코드 ,K.INDV_CORP_CCD AS INDV_CORP_CCD -- 사업자 유형 코드 ,NVL(DECODE(TRIM(K.DL_P_RNM_NO_CCD), '04', (SELECT X.DL_P_PSPT_NO FROM NIC78B X WHERE X.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT AND X.DL_P_RNMCNO = K.DL_P_RNMCNO ), TRIM(K.RNMCNO) ), TRIM(K.RNMCNO) ) AS REALNUMBERCONFIRM -- 관련계좌 개설자 실명번호 확인 ,TRIM(K.RNMCNO) AS REALNUMBER -- 관련계좌 개설자 실명번호 ,TRIM(K.DL_P_RNM_NO_CCD) AS REALNUMBERCODE -- 관련계좌 개설자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(K.DL_P_RNM_NO_CCD)) AS REALNUMBERCODENAME ,'' AS INSURELDESC -- 관계 구분 코드 ,'' AS PARREALNUMBER ,K.DL_P_NM -- 고객명 ,GET_CODE_NAME('M004', TRIM(K.DL_P_NTNLT_CD)) AS NATIONALITY --국가명 ,TRIM(K.DL_P_NTNLT_CD) AS NATIONALITYCODE --국가코드 ,K.DL_P_RNMCNO AS RNMCNO FROM NIC75B I ,NIC71B J ,NIC70B K WHERE I.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT AND I.SSPS_DL_ID = J.SSPS_DL_ID AND I.GNL_AC_NO = J.GNL_AC_NO AND I.GDS_NO = J.GDS_NO AND J.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT AND J.RNMCNO = K.DL_P_RNMCNO AND I.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND I.SSPS_DL_ID = #{SSPS_DL_ID}
UNION
SELECT GET_CODE_NAME('M056', '09') AS RELATIONROLE -- 관련계좌 개설 대리인일 경우 ,'09' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(M.PRXY_RNMCNO) AS REALNUMBERCONFIRM -- 계좌개설대리인 실명번호 확인 ,TRIM(M.PRXY_RNMCNO) AS REALNUMBER -- 계좌개설대리인 실명번호 ,TRIM(M.PRXY_RNM_NO_CCD) AS REALNUMBERCODE -- 계좌개설대리인 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(M.PRXY_RNM_NO_CCD)) AS REALNUMBERCODENAME ,GET_CODE_NAME('M042', TRIM(M.AC_OWN_P_RLTNS_CD)) AS INSURELDESC ,'' AS PARREALNUMBER ,M.PRXY_NM --성명 ,GET_CODE_NAME('M004', TRIM(M.PRXY_NTNLT_CD)) AS NATIONALITY --국가명 ,TRIM(M.PRXY_NTNLT_CD) AS NATIONALITYCODE --국가코드 ,'' AS RNMCNO FROM NIC71B L ,NIC72B M ,NIC75B N WHERE L.SSPS_DL_CRT_DT = N.SSPS_DL_CRT_DT AND L.SSPS_DL_ID = N.SSPS_DL_ID AND L.GNL_AC_NO = N.GNL_AC_NO AND L.GDS_NO = N.GDS_NO AND L.SSPS_DL_CRT_DT = M.SSPS_DL_CRT_DT AND L.SSPS_DL_ID = M.SSPS_DL_ID AND L.GNL_AC_NO = M.GNL_AC_NO AND L.GDS_NO = M.GDS_NO AND TRIM(M.PRXY_RNMCNO) IS NOT NULL AND TRIM(M.PRXY_RNM_NO_CCD) IS NOT NULL AND N.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND N.SSPS_DL_ID = #{SSPS_DL_ID} AND N.GNL_AC_NO = #{GNL_AC_NO} AND N.GDS_NO = #{GDS_NO} AND N.DL_DT = #{DL_DT} AND N.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '11') AS RELATIONROLE -- 거래역할: 당행송수취 계좌개설자 ,'11' AS RELATIONROLECODE -- 거래역할 코드: 11 ,R.INDV_CORP_CCD AS INDV_CORP_CCD -- 개인법인 구분코드 ,NVL(DECODE(TRIM(R.RNM_CNFR_CCD), '04', TRIM(S.PSPT_NO), TRIM(O.RNMCNO)), TRIM(R.RNMCNO) ) AS REALNUMBERCONFIRM -- 당행송수취 계좌개설자 실명번호 확인 ,TRIM(O.RNMCNO) AS REALNUMBER -- 당행송수취 계좌개설자 실명번호 ,TRIM(R.RNM_CNFR_CCD) AS REALNUMBERCODE -- 당행송수취 계좌개설자 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(R.RNM_CNFR_CCD)) AS REALNUMBERCODENAME -- 당행송수취 계좌개설자 실명 구분코드명 ,'' INSURELDESC -- 당행송수취 계좌개설자 거래자와의 관계 ,'' PARREALNUMBER -- 관계구분 ,R.CS_NM -- 성명 ,GET_CODE_NAME('M004', TRIM(R.NTN_CD)) AS NATIONALITY -- 국가 ,TRIM(R.NTN_CD) AS NATIONALITYCODE -- 국가코드 ,O.RNMCNO AS RNMCNO FROM NIC17B O ,NIC83B P ,NIC75B Q ,NIC01B R ,NIC02B S WHERE O.GNL_AC_NO = (SELECT DISTINCT(Y.GNL_AC_NO) FROM NIC17B Y WHERE Y.GNL_AC_NO = P.CPRTY_TRSNS_AC_NO) AND P.SSPS_DL_CRT_DT = Q.SSPS_DL_CRT_DT AND P.SSPS_DL_ID = Q.SSPS_DL_ID AND P.GNL_AC_NO = Q.GNL_AC_NO AND P.DL_DT = Q.DL_DT AND P.DL_SQ = Q.DL_SQ AND O.RNMCNO = R.RNMCNO AND R.RNMCNO = S.RNMCNO(+) AND TRIM(O.RNMCNO ) IS NOT NULL AND TRIM(R.RNM_CNFR_CCD) IS NOT NULL AND Q.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND Q.SSPS_DL_ID = #{SSPS_DL_ID} AND Q.GNL_AC_NO = #{GNL_AC_NO} AND Q.GDS_NO = #{GDS_NO} AND Q.DL_DT = #{DL_DT} AND Q.DL_SQ = #{DL_SQ}
UNION
SELECT GET_CODE_NAME('M056', '12') AS RELATIONROLE -- 당행송수취 계좌개설 대리인 ,'12' AS RELATIONROLECODE -- 거래역할코드 ,'1' AS INDV_CORP_CCD -- 개인법인구분코드 ,TRIM(T.PRXY_RNMCNO) AS REALNUMBERCONFIRM -- 당행송수취 계좌개설 대리인 실명번호 확인 ,TRIM(T.PRXY_RNMCNO) AS REALNUMBER -- 당행송수취 계좌개설 대리인 실명번호 ,TRIM(T.PRXY_RNM_NO_CCD) AS REALNUMBERCODE -- 당행송수취 계좌개설 대리인 실명 구분코드 ,GET_CODE_NAME('M002', TRIM(T.PRXY_RNM_NO_CCD)) AS REALNUMBERCODENAME -- 당행송수취 계좌개설 대리인 실명 구분코드명 ,GET_CODE_NAME('M042', TRIM(CASE WHEN T.PRXY_RLTNS_CD > '4' THEN '9' ELSE T.PRXY_RLTNS_CD END)) AS INSURELDESC ,'' PARREALNUMBER -- 관계구분 ,T.PRXY_NM --성명 ,GET_CODE_NAME('M004', TRIM(T.NTN_CD)) AS NATIONALITY --국가명 ,TRIM(T.NTN_CD) AS NATIONALITYCODE --국가코드 ,'' AS P_RNMCNO FROM NIC18B T ,NIC83B U ,NIC75B V WHERE T.GNL_AC_NO = (SELECT DISTINCT(Z.GNL_AC_NO) FROM NIC17B Z WHERE Z.GNL_AC_NO = U.CPRTY_TRSNS_AC_NO) AND U.SSPS_DL_CRT_DT = V.SSPS_DL_CRT_DT AND U.SSPS_DL_ID = V.SSPS_DL_ID AND U.GNL_AC_NO = V.GNL_AC_NO AND U.DL_DT = V.DL_DT AND U.DL_SQ = V.DL_SQ AND TRIM(T.PRXY_RNMCNO) IS NOT NULL AND TRIM(T.PRXY_RNM_NO_CCD) IS NOT NULL AND V.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND V.SSPS_DL_ID = #{SSPS_DL_ID} AND V.GNL_AC_NO = #{GNL_AC_NO} AND V.GDS_NO = #{GDS_NO} AND V.DL_DT = #{DL_DT} AND V.DL_SQ = #{DL_SQ}

mapper.update:
UPDATE NIC76B
   SET HNDL_DY_TM = SYSDATE
      ,HNDL_P_ENO = #{HNDL_P_ENO}

      ,ISNG_BNK_CD  = #{ISNG_BNK_CD}
      ,ISNG_BNK_NM = (SELECT GET_CODE_NAME('M050',#{ISNG_BNK_CD}) FROM DUAL)


      ,CHCK_KND_CD  = #{CHCK_KND_CD}


      ,CHCK_ISNG_DT = #{CHCK_ISNG_DT}


      ,CHCK_AMT = #{CHCK_AMT}


      ,ENDRS_P_RNM_NO = #{ENDRS_P_RNM_NO}


      ,ENDRS_P_NM = #{ENDRS_P_NM}


      ,ENDRS_P_KND_CD = #{ENDRS_P_KND_CD}


      ,ENDRS_P_TEL_NO = #{ENDRS_P_TEL_NO}

 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID = #{SSPS_DL_ID}
   AND GNL_AC_NO = #{GNL_AC_NO}
   AND GDS_NO = #{GDS_NO}
   AND DL_DT = #{DL_DT}
   AND DL_SQ = #{DL_SQ}
   AND CHCK_STRT_NO = #{CHCK_STRT_NO}

mapper.insert:
INSERT INTO NIC76B (
       GNL_AC_NO
      ,GDS_NO
      ,DL_DT
      ,DL_SQ
      ,SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,CHCK_STRT_NO
      ,CHCK_END_NO
      ,ISNG_BNK_CD
      ,ISNG_BNK_NM
      ,BLL_TYP_AMT
      ,CHCK_AMT
      ,CHCK_ISNG_DT
      ,CHCK_KND_CD
      ,IO_CCD
      ,CHCK_B
      ,CNCL_F
      ,ENDRS_P_F
      ,ENDRS_P_KND_CD
      ,ENDRS_P_NM
      ,ENDRS_P_RNM_NO
      ,ENDRS_P_TEL_NO
      ,HNDL_DY_TM
      ,HNDL_P_ENO
) VALUES (
       #{GNL_AC_NO}
      ,#{GDS_NO}
      ,#{DL_DT}
      ,#{DL_SQ}
      ,#{SSPS_DL_CRT_DT}
      ,#{SSPS_DL_ID}
      ,#{CHCK_STRT_NO}
      ,#{CHCK_END_NO}
      ,#{ISNG_BNK_CD}
      ,(SELECT GET_CODE_NAME('M050',#{ISNG_BNK_CD}) FROM DUAL)
      ,#{BLL_TYP_AMT}
      ,#{CHCK_AMT}
      ,#{CHCK_ISNG_DT}
      ,#{CHCK_KND_CD}
      ,#{IO_CCD}
      ,#{CHCK_B}
      ,#{CNCL_F}
      ,#{ENDRS_P_F}
      ,#{ENDRS_P_KND_CD}
      ,#{ENDRS_P_NM}
      ,#{ENDRS_P_RNM_NO}
      ,#{ENDRS_P_TEL_NO}
      ,SYSDATE
      ,#{HNDL_P_ENO}
)

mapper.delete:
DELETE
  FROM NIC76B
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID = #{SSPS_DL_ID}
