mapper.select:
SELECT ROW_NUMBER() OVER(ORDER BY V.SSPS_DL_CRT_DT DESC, V.SSPS_DL_ID, V.DL_P_RNMCNO , V.DL_TM) AS NU ,GET_CODE_NAME('A103',V.RPR_CCD) AS RPR_NM ,FN_CDINFO_VAR('DT',V.DL_DT||V.DL_TM,'') AS DL_DT_TM_VIEW ,FN_CDINFO_VAR('DPT',V.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM ,GET_CODE_NAME('M045',V.DL_TYP_CD) AS DL_TYP_CD_NM ,FN_NIC70B_INFO(V.SSPS_DL_CRT_DT , V.DL_P_RNMCNO , 'DL_P_NM') AS DL_P_NM ,V.DL_P_RNMCNO ,GET_CODE_NAME('M062',V.CTR_DL_KND_CD) AS CTR_DL_KND_CD_NM ,GET_CODE_NAME('A029',V.RPR_PRGRS_CCD) AS RPR_CCD_NM ,( SELECT /*+ INDEX(I PK_NIC84B)*/ CASE WHEN (SELECT /*+ INDEX(X PK_NIC66B) */ X.RPR_PRGRS_CCD || X.OK_CCD FROM NIC66B X WHERE X.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = I.SSPS_DL_ID) = '92' THEN '' ELSE DECODE(V.RPR_DOC_NO_DL_YR, NULL, '', V.RPR_DOC_NO_DL_YR||'-')||DECODE(I.RPR_DOC_NO_FNL_SQ, '0', '', TRIM(LPAD(I.RPR_DOC_NO_FNL_SQ, '7', '0'))) END FROM NIC84B I WHERE I.ORG_SSPS_DL_CRT_DT = V.SSPS_DL_CRT_DT AND I.ORG_SSPS_DL_ID = V.SSPS_DL_ID AND I.RPR_DOC_NO_DL_YR = V.RPR_DOC_NO_DL_YR AND I.RPR_DOC_NO_FNL_SQ = V.RPR_DOC_NO_FNL_SQ_ORI AND ROWNUM = 1 ) AS RPR_DOC_NO_FNL_SQ_CAN ,FN_NIC70B_INFO(V.SSPS_DL_CRT_DT, V.DL_P_RNMCNO , 'RNMCNO') AS RNMCNO ,(SELECT FN_CDINFO_VAR('DT',SUBSTR(MAX(I.RPR_P_DY_TM),1,8),'') FROM NIC66B_W I WHERE I.INST_ID = V.INST_ID) AS WF_END_DT ,FN_CDINFO_VAR('DT',V.RPR_DT,'') AS RPR_DT ,DECODE( (SELECT COUNT(*) FROM NIC64B I WHERE I.SSPS_DL_CRT_DT=V.SSPS_DL_CRT_DT AND I.SSPS_DL_ID=V.SSPS_DL_ID),0,'No','Yes') AS FILE_ATT_YN ,V.* FROM ( SELECT /*+ INDEX(A PK_NIC66B) */ A.RPR_CCD ,A.SSPS_DL_CRT_DT||'-'||A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A ,A.SSPS_DL_CRT_CCD ,A.SSPS_DL_CRT_DT ,A.RNM_PR_DL_SQ ,C.HANDLNG_BRN_CD ,TO_CHAR(C.CSH, 'FM999,999,999,999') AS CSH ,C.DL_TYP_CD ,A.DL_P_RNMCNO ,C.CNCT_AC_NO AS RL_AC_NO ,C.CTR_DL_KND_CD ,CASE WHEN C.CTR_DL_KND_CD IN ('21','22') THEN NVL(D.CPRTY_TRSNS_AC_NO,B.GNL_AC_NO) END AS CPRTY_TRSNS_AC_NO ,CASE WHEN C.CTR_DL_KND_CD IN ('11','12') THEN B.GNL_AC_NO ELSE '' END AS GNL_AC_NO_FULL ,A.RPR_PRGRS_CCD ,A.RPR_DOC_NO_FNL_SQ AS RPR_DOC_NO_FNL_SQ_ORI ,CASE WHEN A.RPR_PRGRS_CCD IN ('99','10') THEN TRIM(A.RPR_DOC_NO_DL_YR) || '-' || TRIM(TO_CHAR(A.RPR_DOC_NO_FNL_SQ, '0000000')) END AS RPR_DOC_NO_FNL_SQ ,TRIM(A.RPR_DOC_NO_DL_YR) || '-' || TRIM(TO_CHAR(A.RPR_DOC_NO_FNL_SQ, '0000000')) AS RPR_DOC_NO_FNL_SQ_TMP ,CASE WHEN A.RPR_PRGRS_CCD in ('99','10') THEN TRIM(A.DOC_NO_YR) || '-' || TRIM(TO_CHAR(A.DOC_SQ, '0000000')) END AS DOC_SQ ,H.SND_RCPT_FILE_NM AS KOFIU_FILE ,CASE WHEN A.RPR_PRGRS_CCD IN ('99','10') THEN 'download' END AS TRSMT_ST_NM ,A.XCL_RSN_CNTNT AS SN_COMMENT ,A.SSPS_DL_ID ,A.SSPS_DL_RPR_CCD ,A.OK_CCD ,A.SSPS_DL_ANLYS_BRN_CD ,A.SSPS_DL_ANLYS_BRN_NM ,A.RPR_DOC_NO_DL_YR ,A.XCL_RSN_CNTNT ,A.INST_ID ,H.FIU_NO ,H.FIU_REG_DT ,C.DL_TM ,C.DL_DT ,A.RPR_DT FROM NIC66B A ,NIC71B B ,NIC75B C ,NIC83B D ,NIC80B H WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND B.GDS_NO = C.GDS_NO AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.SSPS_DL_ID = D.SSPS_DL_ID(+) AND C.GNL_AC_NO = D.GNL_AC_NO(+) AND C.GDS_NO = D.GDS_NO(+) AND C.DL_DT = D.DL_DT(+) AND C.DL_SQ = D.DL_SQ(+) AND A.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = H.SSPS_DL_ID(+) -- AND A.SSPS_DL_CRT_CCD IN ('CTR','CAC') AND A.SSPS_DL_CRT_CCD IN ('CTR') AND A.RPR_PRGRS_CCD IN (SELECT CNTNT FROM NIC92B WHERE CD = 'A029' ) )V WHERE 1=1
AND V.SSPS_DL_CRT_DT >= #{stDate}
AND V.SSPS_DL_CRT_DT <= #{edDate}
AND #{branchCode} IN (SELECT I.MN_DL_BRN_CD FROM NIC73B I WHERE I.SSPS_DL_CRT_DT = V.SSPS_DL_CRT_DT AND I.SSPS_DL_ID = V.SSPS_DL_ID)
AND V.RPR_PRGRS_CCD = #{RPR_PRGRS_CCD}
AND V.OK_CCD = #{OK_CCD}
AND V.DL_P_RNMCNO like #{RNMCNO}|| '%'
AND V.GNL_AC_NO like #{accountNo}|| '%'

