INSERT INTO NIC80B (
       CTR_STR_CCD
      ,RPR_YR
      ,RPR_DT
      ,SQ
      ,IT_CHRG_P_CNFR_ENO
      ,IT_CHRG_P_CNFR_P_NM
      ,IT_CHRG_P_CNFR_DT
      ,RPR_OGN_CD
      ,SND_RCPT_DOC_NO
      ,IT_CHRG_P_CNFR_TM
      ,HNDL_DY_TM
      ,HNDL_P_ENO
      ,SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,TRSMT_ST_CD
      ,SND_RSLT_CD
      ,SND_RCPT_CCD
      ,SND_RCPT_FILE_NM
      ,RPR_RSPSB_P_NM
      ,RPR_CHRG_P_NM

      /* byun add */
      ,RPR_CHRG_P_ENO
      ,RPR_CHRG_P_CNFR_RCG_ST_CD
      ,RPR_CHRG_P_TEL_NO
      ,RPR_OGN_NM
      ,RPR_CHRG_P_RCG_DT
      ,RPR_CHRG_P_RCG_TM
      ,FNL_HNDL_FNSH_TM
      ,SND_RCPT_TM
) VALUES (
       #{CTR_STR_CCD}
      ,#{RPR_YR}
      ,#{RPR_DT}
      ,( SELECT NVL(MAX(SQ),'0') + 1 FROM NIC80B WHERE RPR_YR = #{RPR_YR} )
      ,#{IT_CHRG_P_CNFR_ENO}
      ,#{IT_CHRG_P_CNFR_P_NM}
      ,TO_CHAR(SYSDATE, 'YYYYMMDD')
      ,#{RPR_OGN_CD}
      ,#{SND_RCPT_DOC_NO}
      ,TO_CHAR(SYSDATE, 'HH24MISS')
      ,SYSDATE
      ,#{HNDL_P_ENO}
      ,#{SSPS_DL_CRT_DT}
      ,#{SSPS_DL_ID}
      ,#{TRSMT_ST_CD}
      ,#{SND_RSLT_CD}
      ,#{SND_RCPT_CCD}
      ,#{SND_RCPT_FILE_NM}
      ,(SELECT RPR_RSPSB_P_NM FROM NIC86B WHERE ROWNUM = 1)
      ,(SELECT RPR_CHRG_P_NM FROM NIC86B WHERE ROWNUM = 1) 

