UPDATE NIC66B
   SET RPR_DOC_NO_DL_YR  = #{RPR_DOC_NO_DL_YR}
      ,RPR_DOC_NO_FNL_SQ = #{RPR_DOC_NO_FNL_SQ}
      ,DOC_NO_YR         = #{DOC_NO_YR}
      ,DOC_SQ            = LPAD(#{DOC_SQ}, '10', '0')
      ,RNM_PR_DL_SQ      = #{RNM_PR_DL_SQ}
      ,RPR_DT            = TO_CHAR(SYSDATE,'yyyyMMdd')
      ,HNDL_DY_TM        = SYSDATE
      ,HNDL_P_ENO        = #{HNDL_P_ENO}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID     = #{SSPS_DL_ID}

mapper.select:
SELECT SND_RCPT_FILE_NM
  FROM NIC80B
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID     = #{SSPS_DL_ID}

SELECT RPR_CCD
      ,SSPS_DL_CRT_CCD
  FROM NIC66B
 WHERE 1=1
   AND SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID     = #{SSPS_DL_ID}

SELECT /* 문서시작 */ 'CTRSTART' AS CTR00 -- 0 문서시작 ,A.RPR_CCD AS CTR01 -- 1 메시지타입
/* 표제부에 관한 정보 */ ,TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.RPR_DOC_NO_FNL_SQ,8,'0')) AS CTR02 -- 2 문서번호(YYYY ,TO_CHAR(SYSDATE,'YYYYMMDD') AS CTR03 -- 3 보고일자 ,CASE WHEN A.RPR_CCD NOT IN ('01','99') THEN TRIM(B.RPR_DOC_NO_DL_YR||'-'||LPAD(B.RPR_DOC_NO_FNL_SQ,8,'0')) ELSE '' END AS CTR04 -- 4 종전문서번호 ,LPAD(A.RNM_PR_DL_SQ,7,'0') || '/'|| LPAD(A.RNM_PR_TL_DL_CNT,7,'0') AS CTR05 -- 5 거래순번 ,TRIM(A.DOC_NO_YR||'-'||LPAD(A.DOC_SQ,8,'0')) AS CTR06 -- 6 기본문서번호
/* I. 보고기관에 관한 정보 */ ,O.RPR_OGN_NM AS CTR07 -- 7 보고기관명 ,O.TRNS_OGN_CD AS CTR08 -- 8 보고기관코드 ,O.RPR_RSPSB_P_NM AS CTR09 -- 9 보고책임자명 ,O.RPR_CHRG_P_NM AS CTR10 -- 10 보고담당자명 ,O.RPR_CHRG_P_TEL_NO AS CTR11 -- 11 보고담당자전화번호
/* II 거래자에 관한 정보 */ /* II-1 공통사항 */ -- 12,13,14항목을 반드시 기입하되, 단 20번항목이 기입될 경우 13,14항목 선택항목 ,C.DL_P_NM AS CTR12 -- 12 거래자명 ,C.DL_P_RNM_NO_CCD AS CTR13 -- 13 거래자실명번호구분 ,C.DL_P_RNMCNO AS CTR14 -- 14 거래자실명번호 ,C.DL_P_NTNLT_CD AS CTR15 -- 15 거래자국적코드 ,GET_CODE_NAME('M004',C.DL_P_NTNLT_CD) AS CTR16 -- 16 거래자국적명
/* II-2 개인인 경우 */ -- (13번 거래자 실명번호 구분 중 주민등록번호(개인),외국인등록번호, 여권번호,국내거소신고번호, 기타일경우 기입) -- (20번 실명조합번호는 15번 국적에서 코드가 KR이 아닐 경우 기입) ,REPLACE(NVL(TRIM(D.DL_P_HSE_PST_NO),TRIM(D.DL_P_WP_PST_NO)),'-','') AS CTR17 -- 17 거래자우편번호 ,NVL(D.DL_P_HSE_ADDR,D.DL_P_WP_ADDR) AS CTR18 -- 18 거래자주소 ,D.DL_P_BRTDY AS CTR19 -- 19 거래자생년월일 ,CASE WHEN D.DL_P_SEX_CD IN ('1', '3') THEN '3' WHEN D.DL_P_SEX_CD IN ('2', '4') THEN '4' ELSE '' END AS CTR20 -- 20 성별 ,NVL(D.DL_P_HSE_TEL_NO,D.DL_P_MBL_TEL_NO) AS CTR21 -- 21 거래자전화번호 ,D.RNM_CMBNTN_NO AS CTR22 -- 22 실명조합번호 ,D.DL_P_PSPT_NO AS CTR23 -- 23 여권번호 ,CASE WHEN D.OCPTN_CCD = '91' OR D.OCPTN_CCD IS NULL THEN '99' ELSE D.OCPTN_CCD END AS CTR24 -- 24 거래자직업구분 ,D.WP_NM AS CTR25 -- 25 거래자직장(회사)명 ,SUBSTR(D.IND_TYP_CD,2,LENGTH(D.IND_TYP_CD)) AS CTR26 -- 26 거래자직장업종코드 ,'' AS CTR27 -- 27 거래자직장사업자번호
/* II-3 법인인 경우 */ -- 13번 거래자 실명번호 구분 중 주민등록번호(기타단체), 사업자등록번호, 투자등록번호, 고유번호/납세번호, 기타일 경우 기입되며, 모두 선택기재사항 ,M.RPRST_P_NM AS CTR28 -- 28 대표자명 ,M.RPRST_P_RNM_CNFR_CCD AS CTR29 -- 29 대표자실명번호구분 ,M.RPRST_P_RNMCNO AS CTR30 -- 30 대표자실명번호 ,M.RPRST_P_NTNLT AS CTR31 -- 31 대표자국적코드 ,GET_CODE_NAME('M004',M.RPRST_P_NTNLT) AS CTR32 -- 32 대표자국적명 ,E.BSNSG_FNDTN_DT AS CTR33 -- 33 사업체설립일 -- 업종코드 앞에 안자르게 수정 20190725 -- , SUBSTR(E.IND_TYP_CD,2,LENGTH(E.IND_TYP_CD)) AS CTR34 -- 34 업종코드 -- , E.IND_TYP_CD AS CTR34 -- 34 업종코드 -- 업종코드 앞에 자르도록 다시 수정 20190819 ,CASE WHEN SUBSTR(E.IND_TYP_CD, 0, 1) = 'A' THEN SUBSTR(E.IND_TYP_CD, 2, LENGTH(E.IND_TYP_CD)) ELSE E.IND_TYP_CD END AS CTR34 -- 34 업종코드 옵션 05 /5자리 KSIC코드 ,E.CORP_RGST_NO AS CTR35 -- 35 법인등록번호 ,TRIM(E.HD_BRNCH_PST_NO) AS CTR36 -- 36 사업체본점우편번호 ,TRIM(E.BSNS_CMPNY_PST_NO) AS CTR37 -- 37 사업체사업장우편번호 ,E.HD_BRNCH_ADDR AS CTR38 -- 38 사업체본점주소 ,E.BSNS_CMPNY_ADDR AS CTR39 -- 39 사업체사업장주소 ,E.HD_BRNCH_TEL_NO AS CTR40 -- 40 사업체본점전화번호 ,E.BSNS_CMPNY_TEL_NO AS CTR41 -- 41 사업체사업장전화번호
/* III 현금거래 내역에 관한 정보 */ /* III-1 공통사항 */ -- 전체 필수항목 ,G.DL_DT||LPAD(DL_TM,6,'0') AS CTR42 -- 42 거래발생일시 ,G.HANDLNG_BRN_NM AS CTR43 -- 43 거래영업점명 ,TRIM(G.HANDLNG_BRN_PST_NO) AS CTR44 -- 44 거래영업점우편번호
,G.DL_CHNNL_CD AS CTR45_TEMP -- 45 거래채널 ,DECODE(G.DL_CHNNL_CD,'01','01','02','02','99') AS CTR45 -- 45 거래채널(20.07.30 수정)
,'01' AS CTR46 -- 46 거래수단 ,G.CSH AS CTR47 -- 47 거래금액 ,G.CTR_DL_KND_CD AS CTR48 -- 48 거래종류 ,DECODE(NVL(H.SSPS_DL_CRT_DT,''),'','2','1') AS CTR49 -- 49 거래대리인존재여부 ,H.PRXY_NM AS CTR50 -- 50 거래대리인명 ,DECODE(DECODE(NVL(H.SSPS_DL_CRT_DT,''),'','2','1'),'2','',NVL(H.PRXY_RNM_NO_CCD,'99')) AS CTR51 -- 51 거래대리인실명번호구분 ,H.PRXY_RNMCNO AS CTR52 -- 52 거래대리인실명번호 ,H.PRXY_TEL_NO AS CTR53 -- 53 거래대리인전화번호 ,H.PRXY_NTNLT_CD AS CTR54 -- 54 거래대리인국적코드 ,GET_CODE_NAME('M004',H.PRXY_NTNLT_CD) AS CTR55 -- 55 거래대리인국적명
,H.AC_OWN_P_RLTNS_CD AS CTR56_TEMP -- 56 거래대리인거래자와관계코드 ,CASE H.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE H.AC_OWN_P_RLTNS_CD END AS CTR56 -- 56 거래대리인거래자와관계코드 ,GET_CODE_NAME('M070',CASE H.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE H.AC_OWN_P_RLTNS_CD END) AS CTR57 -- 57 거래대리인거래자와 관계명
/* III-2 계좌거래의 경우 */ -- 선택사항이며, 35번 거래종류코드값이 11.계좌+지급,12계좌+영수 일 경우 모두 필수 ,L.GNL_AC_NO AS CTR58 -- 58 관련계좌번호
,L.AC_OPN_BRN_NM AS CTR59 -- 59 계좌개설점 ,TRIM(L.AC_OPN_BRN_PST_NO) AS CTR60 -- 60 계좌개설점우편번호 ,L.GDS_OPN_DT AS CTR61 -- 61 계좌개설일 ,CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN DECODE(NVL(I.PRXY_NM,''),'','2','1') ELSE '' END AS CTR62 -- 62 계좌대리인존재여부 ,I.PRXY_NM AS CTR63 -- 63 계좌대리인명 ,DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN DECODE(NVL(I.PRXY_NM,''),'','2','1') ELSE '' END), 2, '', I.PRXY_RNM_NO_CCD) AS CTR64 -- 64 계좌대리인실명번호구분 ,I.PRXY_RNMCNO AS CTR65 -- 65 계좌대리인실명번호 ,I.PRXY_TEL_NO AS CTR66 -- 66 계좌대리인전화번호 ,I.PRXY_NTNLT_CD AS CTR67 -- 67 계좌대리인국적코드 ,GET_CODE_NAME('M004',I.PRXY_NTNLT_CD) AS CTR68 -- 68 계좌대리인국적명 ,I.AC_OWN_P_RLTNS_CD AS CTR69_TEMP -- 69 계좌대리인관계코드 ,DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN DECODE(NVL(I.PRXY_NM,''),'','2','1') ELSE '' END), 2, '', CASE I.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE I.AC_OWN_P_RLTNS_CD END) AS CTR69 -- 69 계좌대리인관계코드
,GET_CODE_NAME('M070', DECODE((CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN DECODE(NVL(I.PRXY_NM,''),'','2','1') ELSE '' END), 2, '', CASE I.AC_OWN_P_RLTNS_CD WHEN '1' THEN '03' WHEN '2' THEN '02' WHEN '3' THEN '04' WHEN '4' THEN '05' WHEN '5' THEN '07' WHEN '6' THEN '12' WHEN '7' THEN '08' WHEN '9' THEN '98' ELSE I.AC_OWN_P_RLTNS_CD END)) AS CTR70 -- 70 계좌대리인관계명
/* III-3 유가증권거래의 경우 */ -- 선택사항이며, 35번 거래종류코드값이 25.비계좌(유가증권)+지급, 26.비계좌(유가증권)+영수일경우 모두필수이나, -- 40. 관련유가증권종류 코드값이 11.선불카드일 경우 33,33-1 선택항목 ,J.CHCK_KND_CD AS CTR71 -- 71 관련유가증권종류 ,J.CHCK_STRT_NO AS CTR72 -- 72 관련유가증권시작번호 ,J.CHCK_END_NO AS CTR73 -- 73 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ -- 40번 유가증권종류에서 코드값이 05.자기앞수표일경우 필수 항목 ,J.BNK_NM AS CTR74 -- 74 현금지급은행명 ,J.BNK_CD AS CTR75 -- 75 현금지급은행기관코드 ,J.BRN_NM AS CTR76 -- 76 현금지급영업점명 ,TRIM(J.BRN_PST_NO) AS CTR77 -- 77 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ --35번 거래종류항목코드 중 22.비계좌(송금)+영수일 경우 필수 항목 ,K.CPRTY_TRSNS_AC_NO AS CTR78 -- 78 수취인계좌번호 ,K.CPRTY_TRSNS_FOGN_NM AS CTR79 -- 79 수취금융기관명 ,K.CPRTY_TRSNS_OGN_CD AS CTR80 -- 80 수취금융기관코드 ,K.CPRTY_TRSNS_AC_NM AS CTR81 -- 81 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ -- 선택사항이며, 01번 메시지 타입 코드값이 02,03,97,98일경우 필수 항목
/* ,CASE WHEN A.RPR_CCD NOT IN ('01','93') THEN SUBSTRB(( SELECT CNTNT FROM NIC66B_W WHERE (INST_ID,WORK_ID) IN ( SELECT INST_ID,MIN(WORK_ID) FROM NIC66B_W WHERE INST_ID = A.INST_ID GROUP BY INST_ID ) ), 1, 1000) ELSE '' END AS CTR82 -- 82 정정,취소 */ ,CORT_CNCL_RSN_CNTNT AS CTR82 --82 정정,취소 ,'CTREND' AS CTR83 -- 83 문서끝 ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,G.GNL_AC_NO --종합계좌번호 ,G.GDS_NO --상품번호 ,G.DL_DT --거래일자 ,G.DL_SQ --거래일련번호 ,K.CPRTY_TRSNS_AC_RNM_NO ,K.CPRTY_TRSNS_AC_RNM_CNFR_CCD ,K.CPRTY_TRSNS_AC_OWN_NTN_CD FROM NIC66B A ,NIC84B B ,NIC70B C /*혐의거래고객공통정보*/ ,NIC78B D /*혐의거래고객개인정보*/ ,NIC79B E /*혐의거래고객법인정보*/ ,NIC71B F /*혐의거래계좌정보*/ ,NIC75B G /*혐의거래내역*/ ,NIC98B H ,NIC72B I /*혐의계좌대리인정보*/ ,(SELECT X.SSPS_DL_CRT_DT ,X.SSPS_DL_ID ,X.GNL_AC_NO ,X.GDS_NO ,X.DL_DT ,X.DL_SQ ,Y.CHCK_KND_CD ,Y.CHCK_STRT_NO ,Y.CHCK_END_NO ,DECODE(Y.CHCK_KND_CD, '05', Z.RPR_OGN_NM, '') AS BNK_NM ,DECODE(Y.CHCK_KND_CD, '05', Z.TRNS_OGN_CD, '') AS BNK_CD ,DECODE(Y.CHCK_KND_CD, '05', X.HANDLNG_BRN_NM, '') AS BRN_NM ,DECODE(Y.CHCK_KND_CD, '05', X.HANDLNG_BRN_PST_NO, '') AS BRN_PST_NO FROM NIC71B W ,NIC75B X ,NIC76B Y ,NIC86B Z WHERE W.SSPS_DL_CRT_DT = X.SSPS_DL_CRT_DT AND W.SSPS_DL_ID = X.SSPS_DL_ID AND W.GNL_AC_NO = X.GNL_AC_NO AND W.GDS_NO = X.GDS_NO AND X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT(+) AND X.SSPS_DL_ID = Y.SSPS_DL_ID(+) AND X.GNL_AC_NO = Y.GNL_AC_NO(+) AND X.GDS_NO = Y.GDS_NO(+) AND X.DL_DT = Y.DL_DT(+) AND X.DL_SQ = Y.DL_SQ(+) AND X.CTR_DL_KND_CD IN ('25','26') AND W.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND W.SSPS_DL_ID = #{SSPS_DL_ID} ) J -- 수표정보 ,(SELECT X.SSPS_DL_CRT_DT ,X.SSPS_DL_ID ,X.GNL_AC_NO ,X.GDS_NO ,X.DL_DT ,X.DL_SQ ,NVL(Y.CPRTY_TRSNS_AC_NO, W.GNL_AC_NO) AS CPRTY_TRSNS_AC_NO ,NVL(Y.CPRTY_TRSNS_FOGN_NM, Z.RPR_OGN_NM) AS CPRTY_TRSNS_FOGN_NM ,NVL(Y.CPRTY_TRSNS_OGN_CD, Z.TRNS_OGN_CD) AS CPRTY_TRSNS_OGN_CD ,NVL(Y.CPRTY_TRSNS_AC_NM, W.CS_NM) AS CPRTY_TRSNS_AC_NM ,Y.CPRTY_TRSNS_AC_RNM_NO ,Y.CPRTY_TRSNS_AC_RNM_CNFR_CCD ,Y.CPRTY_TRSNS_AC_OWN_NTN_CD FROM NIC71B W ,NIC75B X ,NIC83B Y ,NIC86B Z WHERE W.SSPS_DL_CRT_DT = X.SSPS_DL_CRT_DT AND W.SSPS_DL_ID = X.SSPS_DL_ID AND W.GNL_AC_NO = X.GNL_AC_NO AND W.GDS_NO = X.GDS_NO AND X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT(+) AND X.SSPS_DL_ID = Y.SSPS_DL_ID(+) AND X.GNL_AC_NO = Y.GNL_AC_NO(+) AND X.GDS_NO = Y.GDS_NO(+) AND X.DL_DT = Y.DL_DT(+) AND X.DL_SQ = Y.DL_SQ(+) AND X.CTR_DL_KND_CD IN ('21','22') AND W.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND W.SSPS_DL_ID = #{SSPS_DL_ID} ) K ,(SELECT W.* FROM NIC71B W ,NIC75B X WHERE W.SSPS_DL_CRT_DT = X.SSPS_DL_CRT_DT AND W.SSPS_DL_ID = X.SSPS_DL_ID AND W.GNL_AC_NO = X.GNL_AC_NO AND W.GDS_NO = X.GDS_NO AND X.CTR_DL_KND_CD IN ('11','12') AND W.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND W.SSPS_DL_ID = #{SSPS_DL_ID} ) L ,( SELECT A.* FROM NIC03B_1 A , ( SELECT RNMCNO , MIN(RPRST_P_SQ) AS RPRST_P_SQ FROM NIC03B_1 WHERE RPR_TGT_YN = 'Y' GROUP BY RNMCNO ) B WHERE A.RNMCNO = B.RNMCNO AND A.RPRST_P_SQ = B.RPRST_P_SQ ) M ,NIC86B O WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = C.DL_P_RNMCNO
AND NVL(A.FRST_SSPS_DL_CRT_DT, A.SSPS_DL_CRT_DT) = D.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = D.DL_P_RNMCNO(+) AND NVL(A.FRST_SSPS_DL_CRT_DT, A.SSPS_DL_CRT_DT)= E.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = E.DL_P_RNMCNO(+)
AND C.DL_P_RNMCNO = M.RNMCNO(+)
AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = F.SSPS_DL_ID
AND F.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND F.SSPS_DL_ID = G.SSPS_DL_ID AND F.GNL_AC_NO = G.GNL_AC_NO AND F.GDS_NO = G.GDS_NO
AND F.SSPS_DL_CRT_DT = L.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = L.SSPS_DL_ID(+) AND F.GNL_AC_NO = L.GNL_AC_NO(+) AND F.GDS_NO = L.GDS_NO(+)
AND G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = H.SSPS_DL_ID(+) AND G.GNL_AC_NO = H.GNL_AC_NO(+) AND G.GDS_NO = H.GDS_NO(+) AND G.DL_DT = H.DL_DT(+) AND G.DL_SQ = H.DL_SQ(+)
AND F.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = I.SSPS_DL_ID(+) AND F.GNL_AC_NO = I.GNL_AC_NO(+) AND F.GDS_NO = I.GDS_NO(+)
AND G.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = J.SSPS_DL_ID(+) AND G.GNL_AC_NO = J.GNL_AC_NO(+) AND G.GDS_NO = J.GDS_NO(+) AND G.DL_DT = J.DL_DT(+) AND G.DL_SQ = J.DL_SQ(+)
AND G.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = K.SSPS_DL_ID(+) AND G.GNL_AC_NO = K.GNL_AC_NO(+) AND G.GDS_NO = K.GDS_NO(+) AND G.DL_DT = K.DL_DT(+) AND G.DL_SQ = K.DL_SQ(+)
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

mapper.insert:
INSERT INTO NIC84B (
       SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,RPR_DOC_NO_DL_YR
      ,RPR_DOC_NO_FNL_SQ
      ,HNDL_DY_TM
      ,HNDL_P_ENO
      ,ORG_SSPS_DL_CRT_DT
      ,ORG_SSPS_DL_ID
) VALUES (
       #{SSPS_DL_CRT_DT_CAC}
      ,#{SSPS_DL_ID_CAC}
      ,#{RPR_DOC_NO_DL_YR}
      ,( SELECT RPR_DOC_NO_FNL_SQ
           FROM NIC66B
          WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
            AND SSPS_DL_ID = #{SSPS_DL_ID} )
      ,SYSDATE
      ,#{AML_LOGIN_ID}
      ,#{SSPS_DL_CRT_DT}
      ,#{SSPS_DL_ID}
)

mapper.update:
UPDATE NIC66B
   SET INST_ID    = #{INST_ID}
      ,HNDL_DY_TM = SYSDATE
      ,HNDL_P_ENO = #{HNDL_P_ENO}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT_CAC}
   AND SSPS_DL_ID     = #{SSPS_DL_ID_CAC}

UPDATE NIC66B
   SET RPR_DOC_NO_DL_YR  = #{RPR_DOC_NO_DL_YR}
      ,RPR_DOC_NO_FNL_SQ = #{RPR_DOC_NO_FNL_SQ}
      ,DOC_NO_YR         = #{DOC_NO_YR}
      ,DOC_SQ            = LPAD(#{DOC_SQ}, '10', '0')
      ,RPR_DT            = TO_CHAR(SYSDATE,'yyyyMMdd')
      ,HNDL_DY_TM        = SYSDATE
      ,HNDL_P_ENO        = #{HNDL_P_ENO}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID     = #{SSPS_DL_ID}

UPDATE NIC66B
   SET RPR_PRGRS_CCD       = #{RPR_PRGRS_CCD}
      ,RPR_COMPLITE_DT     = TO_DATE(TO_CHAR(#{RPR_COMPLITE_DT}),'yyyymmddHH24miss')
      ,RPR_COMPLITE_P_ENO  = #{USER_ID}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID      = #{SSPS_DL_ID}

UPDATE NIC80B
   SET FIU_NO     = #{FIU_NO}
      ,FIU_REG_DT = #{FIU_REG_DT}
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID     = #{SSPS_DL_ID}

mapper.select:
SELECT * FROM ( SELECT COUNT(*)OVER() AS TOTALCOUNT ,ROWNUM AS SEQ ,V.* FROM ( SELECT DISTINCT C.DL_DT ,FN_CDINFO_VAR('DT',C.DL_DT,'') AS DL_DT_VIEW -- 거래일자 ,C.RNMCNO AS DL_P_RNMCNO ,NVL(TRIM(D.CS_NM), D.ENG_CS_NM) AS CS_NM -- 고객명 ,C.GNL_AC_NO -- 계좌번호 ,C.GDS_NO -- 상품번호 ,C.DL_SQ -- 거래일련번호 ,C.HANDLNG_BRN_CD AS BRN_CD -- 거래지점코드 ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = C.HANDLNG_BRN_CD) AS BRN_NM -- 거래지점 ,GET_CODE_NAME('M045',C.DL_TYP_CD) AS DL_TYP -- 거래종류 ,C.DL_AMT -- 거래금액 ,A.AI_SCORE -- AI 위험도 ,A.AI_CLASS_CD -- AI 위험분류코드, ,GET_CODE_NAME('AI03', A.AI_CLASS_CD) AS AI_CLASS_NM ,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN 'Y' ELSE 'N' END AS ALERT_YN-- ALERT 여부 ,B.SSPS_TYP_CD
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT MA01_6 || ' : ' || BIZ_NM FROM C_BIZ A, MMA010TB B WHERE BIZ_ID=RT30_1 AND MA01_6=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT SCNR_ID || ' : ' || SCNR_NM FROM TMS_APPL WHERE SCNR_ID=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.RPR_PRGRS_CCD = '10' THEN 'Y' WHEN B.RPR_PRGRS_CCD = '9' AND B.OK_CCD = '2' THEN 'N' ELSE '-' END AS RPR_YN -- STR보고여부 ,CASE B.RPR_PRGRS_CCD WHEN '10' THEN FN_CDINFO_VAR('DT',B.RPR_DT,'') ELSE '-' END AS RPR_DT -- STR보고일 ,B.SSPS_DL_CRT_DT ,B.SSPS_DL_ID FROM NIC61B C ,NIC01B D ,AI_STR_SCORE A ,( SELECT F.GNL_AC_NO ,F.GDS_NO ,F.DL_DT ,F.DL_SQ ,E.RPR_PRGRS_CCD ,E.OK_CCD ,E.RPR_DT ,E.SSPS_TYP_CD ,E.SSPS_DL_CRT_DT ,E.SSPS_DL_ID FROM NIC66B E, NIC75B F WHERE E.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND E.SSPS_DL_ID = F.SSPS_DL_ID AND E.SSPS_DL_CRT_CCD IN ('STR') ) B WHERE C.RNMCNO = D.RNMCNO AND C.DL_DT = A.DL_DT AND C.GNL_AC_NO = A.GNL_AC_NO AND C.GDS_NO = A.GDS_NO AND C.DL_SQ = A.DL_SQ AND C.DL_DT = B.DL_DT(+) AND C.GNL_AC_NO = B.GNL_AC_NO(+) AND C.GDS_NO = B.GDS_NO(+) AND C.DL_SQ = B.DL_SQ(+)
AND C.DL_DT >= #{stDate} AND C.DL_DT <= #{edDate}
ORDER BY
DL_P_RNMCNO CS_NM GNL_AC_NO BRN_NM DL_TYP DL_AMT AI_SCORE AI_CLASS_NM ALERT_YN SSPS_TYP_NM RPR_YN RPR_DT DL_DT_VIEW
ASC DESC
) V WHERE 1=1
AND V.BRN_CD = #{branchCode}
AND V.SSPS_TYP_CD = #{SSPS_TYP_CD}
AND V.AI_CLASS_CD = #{AI_CLASS_CD}
AND V.ALERT_YN = #{ALERT_YN}
AND V.DL_P_RNMCNO = #{DL_P_RNMCNO}
AND V.GNL_AC_NO = #{GNL_AC_NO}
AND V.CS_NM = #{CS_NM}
AND V.RPR_YN = #{RPR_YN}
AND V.AI_SCORE >= #{stScore}
AND V.AI_SCORE <= #{edScore}
) WHERE 1=1
AND SEQ >= ( ( #{thisPage} - 1 ) * #{pageCount} + 1 ) AND SEQ <= ( #{thisPage} * #{pageCount} )

WITH TMP AS (SELECT ROWNUM AS SEQ ,V.* FROM (SELECT DISTINCT FN_CDINFO_VAR('DT',C.DL_DT,'') AS DL_DT_VIEW -- 거래일자 ,C.RNMCNO -- 고객 실명확인번호 ,NVL(TRIM(D.CS_NM), D.ENG_CS_NM) AS CS_NM -- 고객명 ,C.GNL_AC_NO -- 계좌번호 ,C.HANDLNG_BRN_CD AS BRN_CD -- 거래지점코드 ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = C.HANDLNG_BRN_CD) AS BRN_NM -- 거래지점 ,A.AI_SCORE -- AI 위험도 ,A.AI_CLASS_CD -- AI 위험분류코드 ,GET_CODE_NAME('AI03', A.AI_CLASS_CD) AS AI_CLASS_NM ,B.SSPS_TYP_CD -- 추출룰 코드 ,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN 'Y' ELSE 'N' END AS ALERT_YN-- ALERT 여부
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT MA01_6 || ' : ' || BIZ_NM FROM C_BIZ A, MMA010TB B WHERE BIZ_ID=RT30_1 AND MA01_6=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT SCNR_ID || ' : ' || SCNR_NM FROM TMS_APPL WHERE SCNR_ID=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.RPR_PRGRS_CCD = '10' THEN 'Y' WHEN B.RPR_PRGRS_CCD = '9' AND B.OK_CCD = '2' THEN 'N' ELSE '-' END AS RPR_YN -- STR보고여부 ,CASE B.RPR_PRGRS_CCD WHEN '10' THEN FN_CDINFO_VAR('DT',B.RPR_DT,'') ELSE '-' END AS RPR_DT -- STR보고일 FROM NIC61B C ,NIC01B D ,AI_STR_SCORE A ,(SELECT F.GNL_AC_NO ,F.GDS_NO ,F.DL_DT ,F.DL_SQ ,E.RPR_PRGRS_CCD ,E.OK_CCD ,E.RPR_DT ,E.SSPS_TYP_CD FROM NIC66B E ,NIC75B F WHERE E.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND E.SSPS_DL_ID = F.SSPS_DL_ID AND E.SSPS_DL_CRT_CCD IN ('STR') ) B WHERE C.RNMCNO = D.RNMCNO AND C.DL_DT = A.DL_DT AND C.GNL_AC_NO = A.GNL_AC_NO AND C.GDS_NO = A.GDS_NO AND C.DL_SQ = A.DL_SQ AND C.DL_DT = B.DL_DT AND C.GNL_AC_NO = B.GNL_AC_NO AND C.GDS_NO = B.GDS_NO AND C.DL_SQ = B.DL_SQ
AND C.DL_DT >= #{stDate} AND C.DL_DT <= #{edDate} ) V
WHERE 1=1
AND V.BRN_CD = #{branchCode}
AND V.SSPS_TYP_CD = #{SSPS_TYP_CD}
) SELECT 'STR 보고건수' AS RPR_YN_CNT ,COUNT(CASE WHEN AI_CLASS_CD ='UH' AND RPR_YN = 'Y' THEN 1 END) AS AI_UH ,COUNT(CASE WHEN AI_CLASS_CD ='H' AND RPR_YN = 'Y' THEN 1 END) AS AI_H ,COUNT(CASE WHEN AI_CLASS_CD ='M' AND RPR_YN = 'Y' THEN 1 END) AS AI_M ,COUNT(CASE WHEN AI_CLASS_CD ='L' AND RPR_YN = 'Y' THEN 1 END) AS AI_L ,COUNT(CASE WHEN AI_CLASS_CD ='UL' AND RPR_YN = 'Y' THEN 1 END) AS AI_UL ,COUNT(CASE WHEN RPR_YN = 'Y' THEN 1 END) AS AI_ALL ,1 AS DISPLAY_ORDER FROM TMP UNION SELECT 'STR 보고제외건수' AS RPR_YN_CNT ,COUNT(CASE WHEN AI_CLASS_CD ='UH' AND RPR_YN = 'N' THEN 1 END) AS AI_UH ,COUNT(CASE WHEN AI_CLASS_CD ='H' AND RPR_YN = 'N' THEN 1 END) AS AI_H ,COUNT(CASE WHEN AI_CLASS_CD ='M' AND RPR_YN = 'N' THEN 1 END) AS AI_M ,COUNT(CASE WHEN AI_CLASS_CD ='L' AND RPR_YN = 'N' THEN 1 END) AS AI_L ,COUNT(CASE WHEN AI_CLASS_CD ='UL' AND RPR_YN = 'N' THEN 1 END) AS AI_UL ,COUNT(CASE WHEN RPR_YN = 'N' THEN 1 END) AS AI_ALL ,2 AS DISPLAY_ORDER FROM TMP
ORDER BY DISPLAY_ORDER

WITH TMP AS ( SELECT ROWNUM AS SEQ ,V.* FROM ( SELECT DISTINCT FN_CDINFO_VAR('DT',C.DL_DT,'') AS DL_DT_VIEW -- 거래일자 ,C.RNMCNO AS DL_P_RNMCNO ,NVL(TRIM(D.CS_NM), D.ENG_CS_NM) AS CS_NM -- 고객명 ,C.GNL_AC_NO -- 계좌번호 ,C.HANDLNG_BRN_CD AS BRN_CD -- 거래지점코드 ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = C.HANDLNG_BRN_CD) AS BRN_NM -- 거래지점 ,A.AI_SCORE -- AI 위험도 ,A.AI_CLASS_CD -- AI 위험분류코드 ,GET_CODE_NAME('AI03', A.AI_CLASS_CD) AS AI_CLASS_NM -- AI 위험분류명 ,B.SSPS_TYP_CD -- 추출룰 코드 ,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN 'Y' ELSE 'N' END AS ALERT_YN-- ALERT 여부
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT MA01_6 || ' : ' || BIZ_NM FROM C_BIZ A, MMA010TB B WHERE BIZ_ID=RT30_1 AND MA01_6=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT SCNR_ID || ' : ' || SCNR_NM FROM TMS_APPL WHERE SCNR_ID=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.RPR_PRGRS_CCD = '10' THEN 'Y' WHEN B.RPR_PRGRS_CCD = '9' AND B.OK_CCD = '2' THEN 'N' ELSE '-' END AS RPR_YN -- STR보고여부 ,CASE B.RPR_PRGRS_CCD WHEN '10' THEN FN_CDINFO_VAR('DT',B.RPR_DT,'') ELSE '-' END AS RPR_DT -- STR보고일 FROM NIC61B C ,NIC01B D ,AI_STR_SCORE A ,(SELECT Y.GNL_AC_NO ,Y.GDS_NO ,Y.DL_DT ,Y.DL_SQ ,X.RPR_PRGRS_CCD ,X.OK_CCD ,X.RPR_DT ,X.SSPS_TYP_CD FROM NIC66B X ,NIC75B Y WHERE X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = Y.SSPS_DL_ID AND X.SSPS_DL_CRT_CCD IN ('STR') ) B WHERE C.RNMCNO = D.RNMCNO AND C.DL_DT = A.DL_DT AND C.GNL_AC_NO = A.GNL_AC_NO AND C.GDS_NO = A.GDS_NO AND C.DL_SQ = A.DL_SQ AND C.DL_DT = B.DL_DT AND C.GNL_AC_NO = B.GNL_AC_NO AND C.GDS_NO = B.GDS_NO AND C.DL_SQ = B.DL_SQ
AND C.DL_DT >= #{stDate} AND C.DL_DT <= #{edDate}
) V WHERE 1=1
AND V.BRN_CD = #{branchCode}
AND V.SSPS_TYP_CD = #{SSPS_TYP_CD}
) SELECT H.AI_CLASS_CD ,H.AI_CLASS_NM ,H.RPR_YN ,COUNT(CASE WHEN G.RPR_YN = H.RPR_YN THEN 1 END) AS CNT FROM TMP G ,(SELECT DISTINCT AI_CLASS_CD ,AI_CLASS_NM ,'Y' AS RPR_YN FROM AI_STR_RANGE_INFO UNION SELECT DISTINCT AI_CLASS_CD ,AI_CLASS_NM ,'N' AS RPR_YN FROM AI_STR_RANGE_INFO ) H WHERE G.AI_CLASS_NM(+) = H.AI_CLASS_NM AND G.RPR_YN(+) = H.RPR_YN GROUP BY H.AI_CLASS_CD, H.AI_CLASS_NM, H.RPR_YN UNION SELECT J.AI_CLASS_CD ,J.AI_CLASS_NM ,J.RPR_YN AS RPR_YN ,COUNT(CASE WHEN I.RPR_YN = J.RPR_YN THEN 1 END) AS CNT FROM TMP I ,(SELECT '' AS AI_CLASS_CD ,'전체' AS AI_CLASS_NM ,'Y' AS RPR_YN FROM DUAL UNION SELECT '' AS AI_CLASS_CD ,'전체' AS AI_CLASS_NM ,'N' AS RPR_YN FROM DUAL ) J WHERE I.RPR_YN(+) = J.RPR_YN GROUP BY J.AI_CLASS_CD, J.AI_CLASS_NM, J.RPR_YN

WITH T_TEMP AS ( SELECT SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' THEN 1 ELSE 0 END) AS STR_Y_CNT ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' THEN 1 ELSE 0 END) AS STR_N_CNT ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >0 AND C.AI_SCORE <=5 THEN 1 ELSE 0 END) AS STR_CNT01 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >5 AND C.AI_SCORE <=10 THEN 1 ELSE 0 END) AS STR_CNT02 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >10 AND C.AI_SCORE <=15 THEN 1 ELSE 0 END) AS STR_CNT03 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >15 AND C.AI_SCORE <=20 THEN 1 ELSE 0 END) AS STR_CNT04 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >20 AND C.AI_SCORE <=25 THEN 1 ELSE 0 END) AS STR_CNT05 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >25 AND C.AI_SCORE <=30 THEN 1 ELSE 0 END) AS STR_CNT06 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >30 AND C.AI_SCORE <=35 THEN 1 ELSE 0 END) AS STR_CNT07 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >35 AND C.AI_SCORE <=40 THEN 1 ELSE 0 END) AS STR_CNT08 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >40 AND C.AI_SCORE <=45 THEN 1 ELSE 0 END) AS STR_CNT09 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >45 AND C.AI_SCORE <=50 THEN 1 ELSE 0 END) AS STR_CNT10 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >50 AND C.AI_SCORE <=55 THEN 1 ELSE 0 END) AS STR_CNT11 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >55 AND C.AI_SCORE <=60 THEN 1 ELSE 0 END) AS STR_CNT12 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >60 AND C.AI_SCORE <=65 THEN 1 ELSE 0 END) AS STR_CNT13 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >65 AND C.AI_SCORE <=70 THEN 1 ELSE 0 END) AS STR_CNT14 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >70 AND C.AI_SCORE <=75 THEN 1 ELSE 0 END) AS STR_CNT15 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >75 AND C.AI_SCORE <=80 THEN 1 ELSE 0 END) AS STR_CNT16 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >80 AND C.AI_SCORE <=85 THEN 1 ELSE 0 END) AS STR_CNT17 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >85 AND C.AI_SCORE <=90 THEN 1 ELSE 0 END) AS STR_CNT18 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >90 AND C.AI_SCORE <=95 THEN 1 ELSE 0 END) AS STR_CNT19 ,SUM(CASE WHEN A.RPR_PRGRS_CCD = '10' AND C.AI_SCORE >95 AND C.AI_SCORE <=100 THEN 1 ELSE 0 END) AS STR_CNT20
,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >0 AND AI_SCORE <=5 THEN 1 ELSE 0 END) AS STR_CNT21 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >5 AND AI_SCORE <=10 THEN 1 ELSE 0 END) AS STR_CNT22 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >10 AND AI_SCORE <=15 THEN 1 ELSE 0 END) AS STR_CNT23 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >15 AND AI_SCORE <=20 THEN 1 ELSE 0 END) AS STR_CNT24 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >20 AND AI_SCORE <=25 THEN 1 ELSE 0 END) AS STR_CNT25 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >25 AND AI_SCORE <=30 THEN 1 ELSE 0 END) AS STR_CNT26 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >30 AND AI_SCORE <=35 THEN 1 ELSE 0 END) AS STR_CNT27 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >35 AND AI_SCORE <=40 THEN 1 ELSE 0 END) AS STR_CNT28 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >40 AND AI_SCORE <=45 THEN 1 ELSE 0 END) AS STR_CNT29 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >45 AND AI_SCORE <=50 THEN 1 ELSE 0 END) AS STR_CNT30 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >50 AND AI_SCORE <=55 THEN 1 ELSE 0 END) AS STR_CNT31 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >55 AND AI_SCORE <=60 THEN 1 ELSE 0 END) AS STR_CNT32 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >60 AND AI_SCORE <=65 THEN 1 ELSE 0 END) AS STR_CNT33 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >65 AND AI_SCORE <=70 THEN 1 ELSE 0 END) AS STR_CNT34 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >70 AND AI_SCORE <=75 THEN 1 ELSE 0 END) AS STR_CNT35 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >75 AND AI_SCORE <=80 THEN 1 ELSE 0 END) AS STR_CNT36 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >80 AND AI_SCORE <=85 THEN 1 ELSE 0 END) AS STR_CNT37 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >85 AND AI_SCORE <=90 THEN 1 ELSE 0 END) AS STR_CNT38 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >90 AND AI_SCORE <=95 THEN 1 ELSE 0 END) AS STR_CNT39 ,SUM(CASE WHEN A.RPR_PRGRS_CCD='9' AND A.OK_CCD='2' AND C.AI_SCORE >95 AND AI_SCORE <=100 THEN 1 ELSE 0 END) AS STR_CNT40 FROM ( SELECT J.GNL_AC_NO ,J.GDS_NO ,J.DL_DT ,J.DL_SQ ,I.RPR_PRGRS_CCD ,I.OK_CCD ,I.SSPS_TYP_CD ,I.SSPS_DL_CRT_DT ,I.SSPS_DL_ID FROM NIC66B I ,NIC75B J WHERE I.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT AND I.SSPS_DL_ID = J.SSPS_DL_ID AND I.SSPS_DL_CRT_CCD IN ('STR') ) A ,NIC73B B ,AI_STR_SCORE C WHERE A.DL_DT = C.DL_DT AND A.GNL_AC_NO = C.GNL_AC_NO AND A.GDS_NO = C.GDS_NO AND A.DL_SQ = C.DL_SQ AND A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.SSPS_DL_CRT_DT >= #{stDate} AND A.SSPS_DL_CRT_DT <= #{edDate}
AND B.MN_DL_BRN_CD = #{branchCode}
AND A.SSPS_TYP_CD = #{SSPS_TYP_CD}
AND C.AI_CLASS_CD = #{AI_CLASS_CD}
AND C.AI_SCORE > #{stScore}
AND C.AI_SCORE >= #{stScore}
AND C.AI_SCORE <= #{edScore}
AND A.RPR_PRGRS_CCD IN ('10')
AND A.RPR_PRGRS_CCD IN ('9')
AND A.RPR_PRGRS_CCD IN ('9','10')
) SELECT CASE WHEN NVL(STR_LANGE,'0') = '0' THEN ' 합 계 ' ELSE STR_LANGE END AS GUGAN ,CASE WHEN TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) >90 THEN '초고위험' WHEN TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) >70 THEN '고위험' WHEN TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) >30 THEN '중위험' WHEN TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) >10 THEN '저위험'
WHEN TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) >=5 AND TO_NUMBER(REPLACE(SUBSTR(STR_LANGE,-4),'%')) <=10 THEN '초저위험'
ELSE '' END AI_CLASS_NM ,MAX(STR_CNT_N) AS STR_N_CNT ,MAX(STR_CNT_Y) AS STR_Y_CNT ,SUM(STR_CNT_Y+STR_CNT_N) AS STR_CNT ,CASE WHEN MAX(STR_CNT_N) = 0 THEN 100 ELSE ROUND(MAX(STR_CNT_Y)/SUM(STR_CNT_Y+STR_CNT_N)*100,2) END AS STR_RATE FROM ( SELECT STR_KOFIU AS STR_KOFIU_Y ,STR_CNT AS STR_CNT_Y ,'' AS STR_KOFIU_N ,0 AS STR_CNT_N ,CASE WHEN STR_KOFIU='STR_CNT01' THEN ' 0% ≤ 위험도 ≤ 5%' WHEN STR_KOFIU='STR_CNT02' THEN ' 5% ＜ 위험도 ≤ 10%' WHEN STR_KOFIU='STR_CNT03' THEN '10% ＜ 위험도 ≤ 15%' WHEN STR_KOFIU='STR_CNT04' THEN '15% ＜ 위험도 ≤ 20%' WHEN STR_KOFIU='STR_CNT05' THEN '20% ＜ 위험도 ≤ 25%' WHEN STR_KOFIU='STR_CNT06' THEN '25% ＜ 위험도 ≤ 30%' WHEN STR_KOFIU='STR_CNT07' THEN '30% ＜ 위험도 ≤ 35%' WHEN STR_KOFIU='STR_CNT08' THEN '35% ＜ 위험도 ≤ 40%' WHEN STR_KOFIU='STR_CNT09' THEN '40% ＜ 위험도 ≤ 45%' WHEN STR_KOFIU='STR_CNT10' THEN '45% ＜ 위험도 ≤ 50%' WHEN STR_KOFIU='STR_CNT11' THEN '50% ＜ 위험도 ≤ 55%' WHEN STR_KOFIU='STR_CNT12' THEN '55% ＜ 위험도 ≤ 60%' WHEN STR_KOFIU='STR_CNT13' THEN '60% ＜ 위험도 ≤ 65%' WHEN STR_KOFIU='STR_CNT14' THEN '65% ＜ 위험도 ≤ 70%' WHEN STR_KOFIU='STR_CNT15' THEN '70% ＜ 위험도 ≤ 75%' WHEN STR_KOFIU='STR_CNT16' THEN '75% ＜ 위험도 ≤ 80%' WHEN STR_KOFIU='STR_CNT17' THEN '80% ＜ 위험도 ≤ 85%' WHEN STR_KOFIU='STR_CNT18' THEN '85% ＜ 위험도 ≤ 90%' WHEN STR_KOFIU='STR_CNT19' THEN '90% ＜ 위험도 ≤ 95%' WHEN STR_KOFIU='STR_CNT20' THEN '95% ＜ 위험도 ≤ 100%' ELSE '' END STR_LANGE FROM T_TEMP UNPIVOT ( STR_CNT FOR STR_KOFIU IN ( STR_Y_CNT ,STR_CNT01,STR_CNT02,STR_CNT03,STR_CNT04,STR_CNT05,STR_CNT06,STR_CNT07,STR_CNT08,STR_CNT09,STR_CNT10 ,STR_CNT11,STR_CNT12,STR_CNT13,STR_CNT14,STR_CNT15,STR_CNT16,STR_CNT17,STR_CNT18,STR_CNT19,STR_CNT20 ) ) UNION ALL SELECT '' AS STR_KOFIU_Y ,0 AS STR_CNT_Y ,STR_KOFIU AS STR_KOFIU_N ,STR_CNT AS STR_CNT_N ,CASE WHEN STR_KOFIU='STR_CNT21' THEN ' 0% ≤ 위험도 ≤ 5%' WHEN STR_KOFIU='STR_CNT22' THEN ' 5% ＜ 위험도 ≤ 10%' WHEN STR_KOFIU='STR_CNT23' THEN '10% ＜ 위험도 ≤ 15%' WHEN STR_KOFIU='STR_CNT24' THEN '15% ＜ 위험도 ≤ 20%' WHEN STR_KOFIU='STR_CNT25' THEN '20% ＜ 위험도 ≤ 25%' WHEN STR_KOFIU='STR_CNT26' THEN '25% ＜ 위험도 ≤ 30%' WHEN STR_KOFIU='STR_CNT27' THEN '30% ＜ 위험도 ≤ 35%' WHEN STR_KOFIU='STR_CNT28' THEN '35% ＜ 위험도 ≤ 40%' WHEN STR_KOFIU='STR_CNT29' THEN '40% ＜ 위험도 ≤ 45%' WHEN STR_KOFIU='STR_CNT30' THEN '45% ＜ 위험도 ≤ 50%' WHEN STR_KOFIU='STR_CNT31' THEN '50% ＜ 위험도 ≤ 55%' WHEN STR_KOFIU='STR_CNT32' THEN '55% ＜ 위험도 ≤ 60%' WHEN STR_KOFIU='STR_CNT33' THEN '60% ＜ 위험도 ≤ 65%' WHEN STR_KOFIU='STR_CNT34' THEN '65% ＜ 위험도 ≤ 70%' WHEN STR_KOFIU='STR_CNT35' THEN '70% ＜ 위험도 ≤ 75%' WHEN STR_KOFIU='STR_CNT36' THEN '75% ＜ 위험도 ≤ 80%' WHEN STR_KOFIU='STR_CNT37' THEN '80% ＜ 위험도 ≤ 85%' WHEN STR_KOFIU='STR_CNT38' THEN '85% ＜ 위험도 ≤ 90%' WHEN STR_KOFIU='STR_CNT39' THEN '90% ＜ 위험도 ≤ 95%' WHEN STR_KOFIU='STR_CNT40' THEN '95% ＜ 위험도 ≤ 100%' ELSE '' END STR_LANGE FROM T_TEMP UNPIVOT ( STR_CNT FOR STR_KOFIU IN ( STR_N_CNT ,STR_CNT21,STR_CNT22,STR_CNT23,STR_CNT24,STR_CNT25,STR_CNT26,STR_CNT27,STR_CNT28,STR_CNT29,STR_CNT30 ,STR_CNT31,STR_CNT32,STR_CNT33,STR_CNT34,STR_CNT35,STR_CNT36,STR_CNT37,STR_CNT38,STR_CNT39,STR_CNT40 ) ) ) GROUP BY STR_LANGE ORDER BY GUGAN DESC

WITH TMP AS ( SELECT ROWNUM AS SEQ, V.* FROM ( SELECT DISTINCT FN_CDINFO_VAR('DT',C.DL_DT,'') AS DL_DT_VIEW -- 거래일자 ,C.RNMCNO AS DL_P_RNMCNO ,NVL(TRIM(D.CS_NM), D.ENG_CS_NM) AS CS_NM -- 고객명 ,C.GNL_AC_NO -- 계좌번호 ,C.HANDLNG_BRN_CD AS BRN_CD --거래지점코드 ,( SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = C.HANDLNG_BRN_CD ) AS BRN_NM -- 거래지점 ,A.AI_SCORE -- AI 위험도 ,A.AI_CLASS_CD -- AI 위험분류코드 ,GET_CODE_NAME('AI03', A.AI_CLASS_CD) AS AI_CLASS_NM -- AI 위험분류명 ,B.SSPS_TYP_CD -- 추출룰 코드 ,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN 'Y' ELSE 'N' END AS ALERT_YN -- ALERT 여부
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT MA01_6 || ' : ' || BIZ_NM FROM C_BIZ A, MMA010TB B WHERE BIZ_ID=RT30_1 AND MA01_6=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.GNL_AC_NO IS NOT NULL THEN NVL((SELECT SCNR_ID || ' : ' || SCNR_NM FROM TMS_APPL WHERE SCNR_ID=B.SSPS_TYP_CD), '수기등록') ELSE '-' END AS SSPS_TYP_NM -- 추출룰
,CASE WHEN B.RPR_PRGRS_CCD = '10' THEN 'Y' WHEN B.RPR_PRGRS_CCD = '9' AND B.OK_CCD = '2' THEN 'N' ELSE '-' END AS RPR_YN -- STR보고여부 ,CASE B.RPR_PRGRS_CCD WHEN '10' THEN FN_CDINFO_VAR('DT',B.RPR_DT,'') ELSE '-' END AS RPR_DT -- STR보고일 FROM NIC61B C ,NIC01B D ,AI_STR_SCORE A ,(SELECT F.GNL_AC_NO ,F.GDS_NO ,F.DL_DT ,F.DL_SQ ,E.RPR_PRGRS_CCD ,E.OK_CCD ,E.RPR_DT ,E.SSPS_TYP_CD FROM NIC66B E ,NIC75B F WHERE E.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND E.SSPS_DL_ID = F.SSPS_DL_ID AND E.SSPS_DL_CRT_CCD IN ('STR') ) B WHERE C.RNMCNO = D.RNMCNO AND C.DL_DT = A.DL_DT AND C.GNL_AC_NO = A.GNL_AC_NO AND C.GDS_NO = A.GDS_NO AND C.DL_SQ = A.DL_SQ AND C.DL_DT = B.DL_DT AND C.GNL_AC_NO = B.GNL_AC_NO AND C.GDS_NO = B.GDS_NO AND C.DL_SQ = B.DL_SQ
AND C.DL_DT >= #{stDate} AND C.DL_DT <= #{edDate}
) V WHERE 1=1
AND V.BRN_CD = #{branchCode}
AND V.SSPS_TYP_CD = #{SSPS_TYP_CD}
) SELECT F.AI_CLASS_CD ,F.AI_CLASS_NM ,COUNT(CASE WHEN E.RPR_YN = F.RPR_YN THEN 1 END) AS CNT FROM TMP E ,(SELECT DISTINCT AI_CLASS_CD ,AI_CLASS_NM ,'Y' AS RPR_YN FROM AI_STR_RANGE_INFO ) F WHERE E.AI_CLASS_NM(+) = F.AI_CLASS_NM AND E.RPR_YN(+) = F.RPR_YN GROUP BY F.AI_CLASS_CD, F.AI_CLASS_NM, F.RPR_YN ORDER BY DECODE(AI_CLASS_CD, 'UL', 1, 'L', 2, 'M', 3, 'H', 4, 'UH', 5)

SELECT A.AI_ML_CRT_DT ,A.AI_ML_TYP ,A.AI_ML_ID ,A.AI_ML_NM ,A.AI_ML_FILE ,A.AI_ML_L_DT ,A.AI_ML_L_DATA_CNT ,A.AI_ML_ACC ,A.AI_ML_PRC ,A.AI_ML_REC ,A.AI_ML_F1S ,A.AI_ML_ACTIVE ,B.AI_FP_ID FROM AI_MODEL A ,AI_ML_FP_MAP B WHERE 1=1 AND A.AI_ML_ID = B.AI_ML_ID AND A.AI_ML_CRT_DT >= #{stDate} AND A.AI_ML_CRT_DT <= #{edDate}
AND A.AI_ML_ACTIVE = #{ACTIVE_YN}
AND A.AI_ML_TYP = #{AI_ML_TYP}
ORDER BY A.AI_ML_L_DT DESC NULLS LAST

