UPDATE NIC35B
   SET CTR_RPR_TNO = ( SELECT SUM(CTR) - SUM(CAC) AS CAC
                         FROM ( SELECT CASE WHEN (SSPS_DL_CRT_CCD='CTR') THEN 1 ELSE 0 END AS CTR
                                      ,CASE WHEN (SSPS_DL_CRT_CCD='CAC') THEN 1 ELSE 0 END AS CAC
                                  FROM NIC66B
                                 WHERE DL_P_RNMCNO  = ( SELECT DL_P_RNMCNO
                                                              FROM NIC66B
                                                             WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                                                               AND SSPS_DL_ID = #{SSPS_DL_ID}
                                                            )
                                  AND RPR_PRGRS_CCD = #{RPR_PRGRS_CCD}
                                  AND SSPS_DL_CRT_CCD IN ('CTR' , 'CAC')
                               )
                     )
 WHERE RNMCNO  = ( SELECT DL_P_RNMCNO
                         FROM NIC66B
                        WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                          AND SSPS_DL_ID = #{SSPS_DL_ID}
                     )

UPDATE NIC35B
   SET STR_RPR_TNO = ( SELECT COUNT(*)
                         FROM NIC66B
