                                                      AND SSPS_DL_ID = #{SSPS_DL_ID}
                                                  )
                          AND RPR_PRGRS_CCD = #{RPR_PRGRS_CCD}
                          AND SSPS_DL_CRT_CCD IN ('STR', 'KYC')
                       )
 WHERE RNMCNO  = ( SELECT DL_P_RNMCNO
                         FROM NIC66B
                        WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                          AND SSPS_DL_ID = #{SSPS_DL_ID}
                      )

