 WHERE SSPS_DL_ID = #{SSPS_DL_ID}
   AND SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}

SELECT DECODE(NVL(A.SSPS_DL_CRT_DT,'Y'),'Y',B.SSPS_DL_CRT_DT, A.SSPS_DL_CRT_DT) AS SSPS_DL_CRT_DT
      ,DECODE(NVL(A.SSPS_DL_CRT_DT,'Y'),'Y',B.SSPS_DL_ID, A.SSPS_DL_ID) AS SSPS_DL_ID
      ,DECODE(NVL(A.SSPS_DL_CRT_DT,'Y'),'Y',B.DOBT_TYP_KND_CD, A.DOBT_TYP_KND_CD) AS DOBT_TYP_KND_CD -- 의심유형종류코드
      ,DECODE(NVL(A.SSPS_DL_CRT_DT,'Y'),'Y',B.F_CCD, A.F_CCD) AS F_CCD -- 여부구분코드
      ,DECODE(NVL(A.SSPS_DL_CRT_DT,'Y'),'Y',B.ETC_CNTNT, A.ETC_CNTNT) AS ETC_CNTNT -- 기타내용
  FROM NIC68B A
      ,(
         SELECT *
           FROM NIC89B
          WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
            AND SSPS_DL_ID = #{SSPS_DL_ID}
            AND MN_DL_BRN_CD = ( SELECT MIN(MN_DL_BRN_CD)
                                   FROM NIC89B
                                  WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                                    AND SSPS_DL_ID = #{SSPS_DL_ID}
                                )
         )B
 WHERE A.SSPS_DL_CRT_DT(+) = B.SSPS_DL_CRT_DT
   AND A.SSPS_DL_ID(+) = B.SSPS_DL_ID

SELECT SSPS_DL_CRT_DT
      ,SSPS_DL_ID
      ,DOBT_TYP_KND_CD -- 의심유형종류코드
      ,F_CCD           -- 여부구분코드
      ,ETC_CNTNT        -- 기타내용
  FROM NIC89B
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID = #{SSPS_DL_ID}
   AND MN_DL_BRN_CD = #{MN_DL_BRN_CD}

