SELECT A.SCNR_MRK
      ,A.SCNR_WGHTS
      ,ROUND(NVL(A.SCNR_MRK,0) * NVL(A.SCNR_WGHTS,0),2) AS EXCH_MRK
      ,A.SSPS_TYP_CD, GET_SYNARIO_NAME(A.SSPS_TYP_CD) AS SSPS_NAME
      ,NVL(B.SCORE_MRK,0) AS SCORE_MRK
      ,1-NVL(A.SCNR_WGHTS,0) AS SCORE_WGHTS
      ,ROUND(NVL(B.SCORE_MRK,0) * (1-NVL(A.SCNR_WGHTS,0)),2) AS SCORE_EXCH_MRK
      ,ROUND(NVL(A.SCNR_MRK,0) * NVL(A.SCNR_WGHTS,0),2) + ROUND(NVL(B.SCORE_MRK,0) * (1-NVL(A.SCNR_WGHTS,0)),2) AS TOTAL_MRK
      ,RSK_GRD_CD
  FROM NIC66B A
      ,( SELECT SUM(I.EXCH_MRK) AS SCORE_MRK
           FROM NIC06B_1 I
          WHERE I.RNMCNO  = #{RNMCNO}
            AND I.KYC_TMS_CCD = #{KYC_TMS_CCD}
            AND I.AML_CRT_DT = ( SELECT MAX(X.AML_CRT_DT)
                                 FROM NIC06B_1 X
                                WHERE X.RNMCNO  = #{RNMCNO}
                                  AND X.KYC_TMS_CCD = #{KYC_TMS_CCD}
                                  AND X.AML_CRT_DT LIKE  #{SSPS_DL_CRT_DT} || '%' )
       ) B
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID = #{SSPS_DL_ID}

