SELECT A.ROLE_ID ,B.USER_ID ,B.USER_NM ,(SELECT ROLE_NM FROM C_ROLE WHERE ROLE_ID = A.ROLE_ID) AS ROLE_NM ,C.DEP_DESC AS HANDLNG_BRN_CD ,FN_CDINFO_VAR('DPT',C.DEP_DESC,'') AS HANDLNG_BRN_NM ,B.LOGIN_ID ,B.SOC_NO ,B.CELL_PHONE FROM C_USER_GROUP_ROLE A ,C_USER B ,C_DEP_INFO C WHERE A.USER_ID = B.USER_ID AND B.DEP_ID = C.DEP_ID AND A.GROUP_ID = 5 AND (1 = #{BRANCH_CODE_YN} OR C.DEP_DESC = #{BRANCH_CODE} ) AND (1 = #{ROLE_ID_YN} OR TO_CHAR(A.ROLE_ID) = #{ROLE_ID} ) AND (1 = #{RPR_PRGRS_CCD_YN} OR A.ROLE_ID IN
#{MASTER_ROLE}
) AND B.USER_ID NOT IN ( SELECT D.PARTICIPANT_ID AS USER_ID FROM NIC66B X , V_WF_STANDBY D WHERE X.INST_ID = D.PAR_INST_ID AND X.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND X.SSPS_DL_ID = #{SSPS_DL_ID} ) ORDER BY C.DEP_DESC, A.ROLE_ID DESC

SELECT (
          SELECT DEP_ID || '.' || #{PARTICIPANT_RULE}
            FROM C_DEP_INFO
           WHERE DEP_DESC = #{NEW_BRANCH}
             AND ROWNUM = 1
       ) AS NEW_DEP_ID
      ,(
          SELECT DEP_ID || '.' || #{PARTICIPANT_RULE}
            FROM C_DEP_INFO
           WHERE DEP_DESC = #{OLD_BRANCH}
             AND ROWNUM = 1
       ) AS OLD_DEP_ID
  FROM DUAL

