SELECT A.ALERT_ID ,A.ALERT_DT ,A.CUST_ID ,B.CS_NM ,B.INDV_CORP_CCD ,GET_CODE_NAME('M004', B.NTN_CD) AS NTN_NM -- 국가 ,C.BRTDY AS DOB ,A.STR_CNT ,A.RULE_ID ,A.PROC_STEP ,(SELECT SCNR_NM FROM TMS_APPL X WHERE A.RULE_ID = X.SCNR_ID) RULE_NM FROM TMP_ALERT A LEFT OUTER JOIN NIC01B B ON A.CUST_ID = B.RNMCNO
LEFT OUTER JOIN NIC02B C ON B.RNMCNO = C.RNMCNO
WHERE ALERT_DT = #{ALERT_DT} AND ALERT_ID = #{ALERT_ID}

SELECT A.ALERT_ID ,A.ALERT_DT ,A.CUST_ID ,B.CS_NM ,B.INDV_CORP_CCD ,GET_CODE_NAME('M004', B.NTN_CD) AS NTN_NM -- 국가 ,C.FNDTN_DT AS DOB ,D.RPRST_P_NM -- 대표자명 ,A.STR_CNT ,A.RULE_ID ,A.PROC_STEP ,(SELECT SCNR_NM FROM TMS_APPL X WHERE A.RULE_ID = X.SCNR_ID) RULE_NM FROM TMP_ALERT A LEFT OUTER JOIN NIC01B B ON A.CUST_ID = B.RNMCNO
LEFT OUTER JOIN NIC03B C ON B.RNMCNO = C.RNMCNO LEFT OUTER JOIN ( SELECT A.* FROM NIC03B_1 A , ( SELECT RNMCNO , MIN(RPRST_P_SQ) AS RPRST_P_SQ FROM NIC03B_1 WHERE RPR_TGT_YN = 'Y' GROUP BY RNMCNO ) B WHERE A.RNMCNO = B.RNMCNO AND A.RPRST_P_SQ = B.RPRST_P_SQ ) D ON B.RNMCNO = D.RNMCNO
WHERE A.ALERT_DT = #{ALERT_DT} AND A.ALERT_ID = #{ALERT_ID}

