mapper.select:
SELECT
(SELECT round(SUM(CASE WHEN AA.PROC_STEP = 1 THEN 1 ELSE 0 END)/COUNT(*) *100,2) FROM TMP_ALERT AA WHERE X1.GUBN=AA.GUBN) AS CON_RATE,
SEQ,GUBN,SCNR_ID,SCNR_NM,WORK_ST_CD,WORK_ST_CD_NM,START_DT,TIME_DIFF,UPP_VAL1,LOW_VAL1,SECT_VAL1,UPP_VAL2,LOW_VAL2,SECT_VAL2,VAL1_NM,VAL2_NM,WORK_START_DTTM,WORK_END_DTTM ,COND1||CASE WHEN COND2 IS NOT NULL AND SCNR_ID = 'A0002' THEN ','||COND2 ELSE NULL END AS COND1 FROM ( SELECT ROW_NUMBER() OVER(ORDER BY WORK_START_DTTM DESC) AS SEQ, SCNR_ID, (SELECT SCNR_NM FROM TMS_APPL X WHERE X.SCNR_ID = A.SCNR_ID ) AS SCNR_NM,WORK_ST_CD ,TO_CHAR(TO_DATE(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'), 'YYYYMMDD') AS START_DT ,CASE WHEN A.WORK_START_DTTM IS NOT NULL AND A.WORK_END_DTTM IS NOT NULL THEN EXTRACT(HOUR FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '시간 ' || EXTRACT(MINUTE FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '분 ' || EXTRACT(SECOND FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '초' ELSE '' END AS TIME_DIFF ,UPP_VAL1 ,LOW_VAL1 ,SECT_VAL1 ,UPP_VAL2 ,LOW_VAL2 ,SECT_VAL2 ,VAL1_NM ,VAL2_NM ,WORK_START_DTTM ,WORK_END_DTTM ,(SELECT SET_VAL FROM TMS_SET_VAL X WHERE A.SCNR_ID = X.SCNR_ID AND ROWNUM=1 AND SET_VAL_CD = 1 GROUP BY SCNR_ID, SET_VAL_CD, SET_VAL) AS COND1 ,(SELECT SET_VAL FROM TMS_SET_VAL X WHERE A.SCNR_ID = X.SCNR_ID AND ROWNUM=1 AND SET_VAL_CD = 2 GROUP BY SCNR_ID, SET_VAL_CD, SET_VAL) AS COND2 ,GUBN ,WORK_ST_CD_NM ,CON_RATE FROM TMP_ALERT_ASSIGN A ) X1 WHERE 1=1
AND WORK_ST_CD = #{WORK_ST_CD}
AND SCNR_ID = #{SSPS_TYP_CD}

SELECT A.ALERT_ID ,A.ALERT_DT ,A.CUST_ID ,B.CS_NM ,A.ALERT_CNT ,A.STR_CNT ,A.STR_YN ,A.STR_CHRG_ID ,A.RULE_ID ,(SELECT SCNR_NM FROM TMS_APPL X WHERE A.RULE_ID = X.SCNR_ID) RULE_NM ,(ALERT_SCORE || '/' || ALERT_LEVEL) AS ALERT_SCORE ,A.ASSIGN ,A.CHRG_ID ,A.CHRG_NM ,A.ASSIGN_DT ,A.PROC_STEP ,B.INDV_CORP_CCD FROM TMP_ALERT A LEFT OUTER JOIN NIC01B B ON A.CUST_ID = B.RNMCNO WHERE A.PROC_STEP ='4'
AND A.ALERT_DT BETWEEN #{stDate} AND #{edDate}
AND A.RULE_ID = #{SSPS_TYP_CD}
AND A.ASSIGN = #{selectAsg}
AND A.CUST_ID LIKE '%' || #{custId} || '%'A
AND B.CS_NM LIKE '%' || #{custNm} || '%'
ORDER BY A.ALERT_DT DESC

