SELECT A.SCNR_ID ,A.SCNR_NM ,A.SCNR_CCD ,GET_CODE_NAME('A047', A.SCNR_CCD) AS SCNR_CCD_NM ,CASE WHEN B.WORK_CYCL = 'D' THEN 'Y' ELSE 'N' END AS D_FLAG ,CASE WHEN B.WORK_CYCL = 'W' THEN 'Y' ELSE 'N' END AS W_FLAG ,CASE WHEN B.WORK_CYCL = 'M' THEN 'Y' ELSE 'N' END AS M_FLAG ,CASE WHEN B.WORK_CYCL = 'Q' THEN 'Y' ELSE 'N' END AS Q_FLAG ,NVL(B.USE_YN, 'N') AS USE_YN FROM TMS_REQ A LEFT JOIN TMS_RUN_INFO B ON A.SCNR_ID = B.SCNR_ID LEFT JOIN TMS_BZDM_MNG C ON A.BZDM_CD = C.BZDM_CD AND A.BIZ_CD = C.BIZ_CD WHERE 1=1
AND B.USE_YN = #{USE_YN}
AND A.SCNR_CCD = #{SCNR_CCD}
AND A.BZDM_CD = #{amlType}
ORDER BY DECODE(A.SCNR_CCD, 'STR', 1, 'CTR', 2), A.SCNR_ID

