SELECT A.SCNR_ID AS CODE ,A.SCNR_ID || '::' || A.SCNR_NM AS NAME FROM TMS_APPL A ,TMS_RUN_INFO B ,TMS_BZDM_MNG C WHERE A.SCNR_ID = B.SCNR_ID AND A.SCNR_CCD = 'STR' AND B.USE_YN = 'Y' AND A.BZDM_CD = C.BZDM_CD AND A.BIZ_CD = C.BIZ_CD
AND A.BZDM_CD = #{amlType}
ORDER BY A.SCNR_ID

SELECT A.SMUL_ID -- 시뮬레이션ID ,A.SMUL_NM -- 시뮬레이션명 ,A.SMUL_CTNT -- 시뮬레이션내용 ,A.SCNR_ID -- 시나리오ID ,B.SCNR_NM -- 시나리오명 ,A.SSPS_DL_TRGT_START_DT -- 혐의거래대상시작일자 ,A.SSPS_DL_TRGT_END_DT -- 혐의거래대상종료일자 ,TO_CHAR(TO_DATE(A.SSPS_DL_TRGT_START_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD')|| ' ~ ' || TO_CHAR(TO_DATE(A.SSPS_DL_TRGT_END_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS SSPL_DL_TRGT_DT -- 혐의거래대상기간 ,A.WORK_ST_CD -- 작업상태코드 ,GET_CODE_NAME('A039', A.WORK_ST_CD) AS WORK_ST_NM -- 작업상태명 ,TO_CHAR(TO_DATE(A.WORK_START_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_START_DTTM -- 작업시작일시 ,TO_CHAR(TO_DATE(A.WORK_END_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_END_DTTM -- 작업종료일시 ,CASE WHEN A.WORK_START_DTTM IS NOT NULL AND A.WORK_END_DTTM IS NOT NULL THEN EXTRACT(HOUR FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '시간 ' || EXTRACT(MINUTE FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '분 ' || EXTRACT(SECOND FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '초' ELSE '' END AS TIME_DIFF -- 작업시간 ,A.WRKR_ID -- 작업자ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = A.WRKR_ID) AS WRKR_NM -- 작업자명 ,C.SSPS_DL_CRT_CNT -- 추출결과 ,A.CS_CCD -- 고객구분코드 ,A.ERR_CTNT -- 오류내용 ,A.REG_ID -- 등록자ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = A.REG_ID) AS REG_NM -- 등록자명 ,TO_CHAR(TO_DATE(A.REG_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REG_DTTM -- 등록일시 ,D.WORK_CYCL FROM TMS_SMUL A LEFT JOIN TMS_APPL B ON A.SCNR_ID = B.SCNR_ID LEFT JOIN ( SELECT SMUL_ID ,SUM(SSPS_DL_CRT_CNT) AS SSPS_DL_CRT_CNT FROM TMS_SMUL_RSLT_DT GROUP BY SMUL_ID ) C ON A.SMUL_ID = C.SMUL_ID LEFT JOIN TMS_RUN_INFO D ON A.SCNR_ID = D.SCNR_ID WHERE A.WORK_START_DTTM BETWEEN #{RUN_DT_SD}||'0000' AND #{RUN_DT_ED}||'235959'
AND A.SCNR_ID = #{SCNR_ID}
ORDER BY A.SMUL_ID DESC

