SELECT A.SCNR_CCD ,A.SCNR_ID ,A.SCNR_NM ,C.USE_YN ,CASE WHEN B.WORK_ST_CD IS NULL THEN '실행' ELSE '재실행' END AS EXCUTE ,B.JOB_DT AS JOB_DT_ORG ,TO_CHAR(TO_TIMESTAMP(B.JOB_DT, 'YYYYMMDDHH24MISSFF3'), 'YYYY-MM-DD HH24:MI:SS') AS JOB_DT ,B.JOB_SEQ ,TO_CHAR(TO_DATE(B.WORK_START_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_START_DTTM ,TO_CHAR(TO_DATE(B.WORK_END_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_END_DTTM ,CASE WHEN B.WORK_START_DTTM IS NOT NULL AND B.WORK_END_DTTM IS NOT NULL THEN EXTRACT(HOUR FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '시간 ' || EXTRACT(MINUTE FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '분 ' || EXTRACT(SECOND FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '초' ELSE '' END AS TIME_DIFF ,TO_CHAR(TO_DATE(B.LST_APPL_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS LST_APPL_DTTM ,B.LST_APP_NO ,TO_CHAR(TO_DATE(B.SSPS_DL_TRGT_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS SSPS_DL_TRGT_DT ,TO_CHAR(TO_DATE(B.SSPS_DL_CRT_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS SSPS_DL_CRT_DT ,B.WORK_ST_CD ,NVL(GET_CODE_NAME('A039', B.WORK_ST_CD),'미수행') AS WORK_ST_NM ,B.ERR_CTNT ,B.WRKR_ID ,( SELECT USER_NM FROM C_USER WHERE USER_ID = B.WRKR_ID ) AS WRKR_NM ,B.REG_ID ,( SELECT USER_NM FROM C_USER WHERE USER_ID = B.REG_ID ) AS REG_NM ,TO_CHAR(TO_DATE(B.REG_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REG_DTTM ,B.UPD_ID ,( SELECT USER_NM FROM C_USER WHERE USER_ID = B.REG_ID ) AS UPD_NM ,TO_CHAR(TO_DATE(B.UPD_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS UPD_DTTM FROM ( SELECT T.* FROM TMS_APPL T
WHERE T.BZDM_CD = #{BZDM_CD}
UNION SELECT T.* FROM TMS_APPL T WHERE T.SCNR_ID = 'CTR01' ) A LEFT JOIN ( SELECT * FROM TMS_BTCH_HIST X WHERE 1=1 AND ( JOB_DT , JOB_SEQ ) IN ( SELECT JOB_DT ,MAX(JOB_SEQ) FROM TMS_BTCH_HIST WHERE X.SCNR_ID = SCNR_ID AND JOB_DT = ( SELECT MAX(JOB_DT) FROM TMS_BTCH_HIST WHERE X.SCNR_ID = SCNR_ID
AND JOB_DT LIKE #{startDate}||'%'
AND SSPS_DL_CRT_DT = #{startDate}
AND ( JOB_DT LIKE #{startDate} || '%' OR SSPS_DL_CRT_DT = #{startDate} )
) GROUP BY JOB_DT ) ) B ON A.SCNR_ID = B.SCNR_ID LEFT JOIN TMS_RUN_INFO C ON A.SCNR_ID = C.SCNR_ID WHERE 1=1
AND A.BZDM_CD = #{amlType}
AND A.SCNR_CCD = #{SCNR_CCD}
AND C.USE_YN = #{USE_YN}
AND B.WORK_ST_CD = #{WORK_ST_CD}
ORDER BY SCNR_ID

SELECT A.SCNR_CCD ,A.SCNR_ID ,A.SCNR_NM ,'실행요청' AS EXCUTE ,B.JOB_DT AS JOB_DT_ORG ,TO_CHAR(TO_TIMESTAMP(B.JOB_DT, 'YYYYMMDDHH24MISSFF3'), 'YYYY-MM-DD HH24:MI:SS') AS JOB_DT ,B.JOB_SEQ ,TO_CHAR(TO_DATE(B.WORK_START_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_START_DTTM ,TO_CHAR(TO_DATE(B.WORK_END_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_END_DTTM ,CASE WHEN B.WORK_START_DTTM IS NOT NULL AND B.WORK_END_DTTM IS NOT NULL THEN EXTRACT(HOUR FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '시간 ' || EXTRACT(MINUTE FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '분 ' || EXTRACT(SECOND FROM (TO_TIMESTAMP(B.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(B.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '초' ELSE '' END AS TIME_DIFF ,TO_CHAR(TO_DATE(B.LST_APPL_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS LST_APPL_DTTM ,B.LST_APP_NO ,TO_CHAR(TO_DATE(B.SSPS_DL_TRGT_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS SSPS_DL_TRGT_DT ,TO_CHAR(TO_DATE(B.SSPS_DL_CRT_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS SSPS_DL_CRT_DT ,B.WORK_ST_CD ,GET_CODE_NAME('A039', B.WORK_ST_CD) AS WORK_ST_NM ,B.ERR_CTNT ,B.WRKR_ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = B.WRKR_ID) AS WRKR_NM ,B.REG_ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = B.REG_ID) AS REG_NM ,TO_CHAR(TO_DATE(B.REG_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REG_DTTM ,B.UPD_ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = B.REG_ID) AS UPD_NM ,TO_CHAR(TO_DATE(B.UPD_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS UPD_DTTM FROM ( SELECT X.* FROM TMS_APPL X INNER JOIN TMS_BZDM_MNG Y ON X.BZDM_CD = Y.BZDM_CD AND X.BIZ_CD = Y.BIZ_CD UNION SELECT X.* FROM TMS_APPL X WHERE X.SCNR_ID = 'CTR01' ) A ,TMS_BTCH_HIST B WHERE 1=1 AND A.SCNR_ID = B.SCNR_ID AND UPPER(A.SCNR_ID) = UPPER(#{SCNR_ID})
AND TO_CHAR(TO_TIMESTAMP(B.JOB_DT, 'YYYYMMDDHH24MISSFF3'), 'YYYYMMDD') BETWEEN #{startDate} AND #{endDate}
AND B.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
AND (TO_CHAR(TO_TIMESTAMP(B.JOB_DT, 'YYYYMMDDHH24MISSFF3'), 'YYYYMMDD') BETWEEN #{startDate} AND #{endDate}) OR B.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
AND B.WORK_ST_CD = #{WORK_ST_CD}
ORDER BY B.JOB_DT DESC

