	MERGE
     INTO TMS_REQ
    USING DUAL
       ON (SCNR_ID = #{SCNR_ID})
     WHEN MATCHED THEN
           UPDATE
              SET BZDM_CD = #{BZDM_CD}
                 ,BIZ_CD = #{BIZ_CD}
                 ,SCNR_CCD = 'STR'
                 ,SCNR_NM = #{SCNR_NM}
                 ,SCNR_DESC = #{SCNR_DESC}
                 ,AC_DL_CCD = #{AC_DL_CCD}
                 ,UPD_ID = #{userId jdbcType=VARCHAR}
                 ,UPD_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
     WHEN NOT MATCHED THEN
           INSERT
                (
                  SCNR_ID
                 ,BZDM_CD
                 ,BIZ_CD
                 ,SCNR_CCD
                 ,SCNR_NM
                 ,SCNR_DESC
                 ,AC_DL_CCD
                 ,REG_ID
                 ,REG_DTTM
                 ,UPD_ID
                 ,UPD_DTTM
               )
          VALUES
               (
                  #{SCNR_ID}
                 ,#{BZDM_CD}
                 ,#{BIZ_CD}
                 ,'STR'
                 ,#{SCNR_NM}
                 ,#{SCNR_DESC}
                 ,#{AC_DL_CCD}
                 ,#{userId jdbcType=VARCHAR}
                 ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
                 ,#{userId jdbcType=VARCHAR}
                 ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
               )

