SELECT T1.* FROM (SELECT COUNT(*) OVER() AS TOTALCOUNT ,ROWNUM AS SEQ ,T2.* FROM (SELECT A.SSPS_DL_CRT_DT || '-' || A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A ,NVL(TRIM(B.CS_NM), B.ENG_CS_NM) AS DL_P_NM ,A.DL_P_RNMCNO ,GET_CODE_NAME('M002', B.RNM_CNFR_CCD) AS DL_P_RNM_NO_CCD_NM
,NVL((SELECT X1.BIZ_NM FROM C_BIZ X1 ,MMA010TB Y1 WHERE X1.BIZ_ID = Y1.RT30_1 AND Y1.MA01_6 = A.SSPS_TYP_CD ), '수기등록' ) AS SSPS_TYP_NM
,NVL((SELECT X2.SCNR_NM FROM TMS_APPL X2 WHERE X2.SCNR_ID = A.SSPS_TYP_CD ), '수기등록' ) AS SSPS_TYP_NM
,C.LST_RSK_EAL_SOR AS RSK_GRD_MRK ,C.RSK_GRD_CD AS RSK_GRD_CD ,GET_CODE_NAME('A004', C.RSK_GRD_CD) AS RSK_GRD_CD_NM ,A.RSK_MRK AS RSK_MRK ,A.RSK_GRD_CD AS RSK_GRD ,GET_CODE_NAME('A004', A.RSK_GRD_CD) AS RSK_GRD_NM ,J.DL_AMT ,CASE WHEN A.RPR_PRGRS_CCD = '2' THEN F.ACT_NAME ELSE GET_CODE_NAME('A029', A.RPR_PRGRS_CCD) END AS ACT_NAME ,GET_CODE_NAME('A301', NVL(A.OK_CCD, '0')) AS OK_CCD_NM ,A.XCL_RSN_CNTNT ,A.XCL_RSN_CNTNT2 ,A.DNY_RSN_CNTNT ,A.SSPS_DL_CRT_DT ,A.SSPS_DL_ID ,A.INST_ID ,D.MN_DL_BRN_NM AS MN_DL_BRN_NM -- 처리점 ,D.MN_DL_BRN_CD AS MN_DL_BRN_CD -- 처리점 ,G.GNL_AC_NO ,H.CNT ,I.SSPS_DL_CRT_DT AS RPR_DT ,B.LG_AMT_ASTS_F ,CASE WHEN TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'), 'YYYYMMDD') - TO_DATE(A.SSPS_DL_CRT_DT, 'YYYYMMDD') < 10 THEN '1' ELSE '2' END AS REPORTDATE ,A.SSPS_TYP_CD ,A.SCNR_MRK ,(NVL(A.OK_CCD, '0')) AS OK_CCD ,TO_CHAR(A.RPR_COMPLITE_DT, 'YYYYMMDD') AS RPR_COMPLITE_DT ,DECODE((SELECT COUNT(*) FROM NIC66B J WHERE J.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND J.DL_P_RNMCNO = A.DL_P_RNMCNO AND J.M_SSPS_DL_ID IS NOT NULL), 0, '', 'Y') AS MERGE_YN ,F.PARTICIPANT_ID ,F.ACT_ID ,F.WORK_ID ,A.RPR_PRGRS_CCD FROM NIC66B A INNER JOIN NIC01B B ON A.DL_P_RNMCNO = B.RNMCNO LEFT JOIN NIC35B C ON B.RNMCNO = C.RNMCNO INNER JOIN NIC73B D ON A.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = D.SSPS_DL_ID INNER JOIN NIC70B E ON A.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = E.DL_P_RNMCNO
INNER JOIN (SELECT X3.INST_ID ,X3.WORK_ID ,Y3.ACT_NAME ,X3.PROC_ID ,Y3.ACT_ID ,Z3.PARTICIPANT_ID FROM WF_PROC_INSTANCE X3 LEFT JOIN MV_APRV_STATUS Y3 ON X3.INST_ID = Y3.PAR_INST_ID AND Y3.INST_STATUS_CD != 'DELETED' LEFT JOIN WF_WORK_PARTICIPANT Z3 ON X3.WORK_ID = Z3.WORK_ID AND ( ( Z3.PERSON_YN = 'Y' AND Z3.PARTICIPANT_ID = #{USER_ID} ) OR ( Z3.PERSON_YN = 'N' AND Z3.PARTICIPANT_ID IN (SELECT Y1.DEP_ID || '.' || ROLE_ID FROM C_USER_GROUP_ROLE X1 ,C_USER Y1 WHERE X1.USER_ID = #{USER_ID} AND X1.USER_ID = Y1.USER_ID AND Y1.DEP_ID || '.' || ROLE_ID = #{DPT_ROLE} ) ) OR ( Z3.PERSON_YN = 'N' AND Z3.PARTICIPANT_ID IN (SELECT Z2.TGT_DEP_ID || '.' || Z2.ROLE_ID FROM C_USER_GROUP_ROLE X2 ,C_USER Y2 ,(SELECT XX.* FROM C_MULTI_POSITION XX WHERE XX.CHRG_P_ID = #{USER_ID} AND XX.APPR_STAT_CD = 'E' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN XX.START_DT AND XX.END_DT AND ROWNUM = 1 ) Z2 WHERE X2.USER_ID = #{USER_ID} AND X2.USER_ID = Y2.USER_ID AND X2.USER_ID = Z2.CHRG_P_ID AND Y2.DEP_ID || '.' || X2.ROLE_ID = #{DPT_ROLE} ) ) ) ) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X4.INST_ID ,X4.WORK_ID ,Y4.ACT_NAME ,X4.PROC_ID ,Y4.ACT_ID ,ZZ4.PARTICIPANT_ID FROM WF_PROC_INSTANCE X4 LEFT JOIN MV_APRV_STATUS Y4 ON X4.INST_ID = Y4.PAR_INST_ID AND Y4.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z4 ON X4.INST_ID = Z4.INST_ID LEFT JOIN WF_WORK_PARTICIPANT ZZ4 ON X3.WORK_ID = ZZ4.WORK_ID AND ( ( ZZ4.PERSON_YN = 'Y' AND ZZ4.PARTICIPANT_ID = #{USER_ID} ) OR ( ZZ4.PERSON_YN = 'N' AND ZZ4.PARTICIPANT_ID IN (SELECT Y1.DEP_ID || '.' || ROLE_ID FROM C_USER_GROUP_ROLE X1 ,C_USER Y1 WHERE X1.USER_ID = #{USER_ID} AND X1.USER_ID = Y1.USER_ID AND Y1.DEP_ID || '.' || ROLE_ID = #{DPT_ROLE} ) ) OR ( ZZ4.PERSON_YN = 'N' AND ZZ4.PARTICIPANT_ID IN (SELECT Z2.TGT_DEP_ID || '.' || Z2.ROLE_ID FROM C_USER_GROUP_ROLE X2 ,C_USER Y2 ,(SELECT XX.* FROM C_MULTI_POSITION XX WHERE XX.CHRG_P_ID = #{USER_ID} AND XX.APPR_STAT_CD = 'E' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN XX.START_DT AND XX.END_DT AND ROWNUM = 1 ) Z2 WHERE X2.USER_ID = #{USER_ID} AND X2.USER_ID = Y2.USER_ID AND X2.USER_ID = Z2.CHRG_P_ID AND Y2.DEP_ID || '.' || X2.ROLE_ID = #{DPT_ROLE} ) ) ) WHERE Z4.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND Y4.ACT_NAME IN (SELECT XX.ACT_NAME FROM WF_ACT XX WHERE XX.ACT_ID IN
#{wfCodeArray1, jdbcType=VARCHAR}
) UNION SELECT X5.INST_ID ,GET_CODE_NAME('A029', X5.RPR_PRGRS_CCD) AS ACT_NAME ,0 AS PROC_ID ,0 AS ACT_ID FROM NIC66B X5 WHERE X5.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND X5.RPR_PRGRS_CCD IN
#{wfCodeArray2, jdbcType=VARCHAR}
) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X6.INST_ID ,X6.WORK_ID ,Y6.ACT_NAME ,X6.PROC_ID ,Y6.ACT_ID ,ZZ6.PARTICIPANT_ID FROM WF_PROC_INSTANCE X6 LEFT JOIN MV_APRV_STATUS Y6 ON X6.INST_ID = Y6.PAR_INST_ID AND Y6.INST_STATUS_CD != 'DELETED' INNER JOIN NIC66B Z6 ON X6.INST_ID = Z6.INST_ID LEFT JOIN WF_WORK_PARTICIPANT ZZ6 ON X6.WORK_ID = ZZ6.WORK_ID AND ( ( ZZ6.PERSON_YN = 'Y' AND ZZ6.PARTICIPANT_ID = #{USER_ID} ) OR ( ZZ6.PERSON_YN = 'N' AND ZZ6.PARTICIPANT_ID IN (SELECT Y1.DEP_ID || '.' || ROLE_ID FROM C_USER_GROUP_ROLE X1 ,C_USER Y1 WHERE X1.USER_ID = #{USER_ID} AND X1.USER_ID = Y1.USER_ID AND Y1.DEP_ID || '.' || ROLE_ID = #{DPT_ROLE} ) ) OR ( ZZ6.PERSON_YN = 'N' AND ZZ6.PARTICIPANT_ID IN (SELECT Z2.TGT_DEP_ID || '.' || Z2.ROLE_ID FROM C_USER_GROUP_ROLE X2 ,C_USER Y2 ,(SELECT XX.* FROM C_MULTI_POSITION XX WHERE XX.CHRG_P_ID = #{USER_ID} AND XX.APPR_STAT_CD = 'E' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN XX.START_DT AND XX.END_DT AND ROWNUM = 1 ) Z2 WHERE X2.USER_ID = #{USER_ID} AND X2.USER_ID = Y2.USER_ID AND X2.USER_ID = Z2.CHRG_P_ID AND Y2.DEP_ID || '.' || X2.ROLE_ID = #{DPT_ROLE} ) ) ) WHERE Z6.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') AND Y6.ACT_NAME IN (SELECT YY.ACT_NAME FROM WF_ACT YY WHERE YY.ACT_ID IN
#{wfCodeArray1, jdbcType=VARCHAR}
) ) F ON A.INST_ID = F.INST_ID
INNER JOIN (SELECT X7.SSPS_DL_CRT_DT ,X7.SSPS_DL_ID ,MAX(X7.GNL_AC_NO) KEEP (DENSE_RANK FIRST ORDER BY X7.DL_DT DESC, X7.DL_TM DESC) AS GNL_AC_NO FROM NIC75B X7 GROUP BY X7.SSPS_DL_CRT_DT ,X7.SSPS_DL_ID ) G ON A.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = G.SSPS_DL_ID LEFT JOIN (SELECT X8.DL_P_RNMCNO ,COUNT(*) AS CNT FROM NIC66B X8 WHERE X8.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') GROUP BY X8.DL_P_RNMCNO ) H ON A.DL_P_RNMCNO = H.DL_P_RNMCNO LEFT JOIN (SELECT X9.DL_P_RNMCNO ,MAX(X9.SSPS_DL_CRT_DT) AS SSPS_DL_CRT_DT FROM NIC66B X9 WHERE X9.OK_CCD ='1' AND X9.RPR_PRGRS_CCD = '10' AND X9.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC') GROUP BY X9.DL_P_RNMCNO ) I ON A.DL_P_RNMCNO = I.DL_P_RNMCNO LEFT JOIN (SELECT SUM(X10.DL_AMT) AS DL_AMT ,X10.SSPS_DL_CRT_DT ,X10.SSPS_DL_ID FROM NIC75B X10 GROUP BY X10.SSPS_DL_CRT_DT ,X10.SSPS_DL_ID ) J ON A.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = J.SSPS_DL_ID WHERE 1 = 1 AND A.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC')
AND A.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND A.SSPS_DL_CRT_CCD = #{SSPS_DL_CRT_CCD}
AND #{branchCode} IN (SELECT X11.MN_DL_BRN_CD FROM NIC73B X11 WHERE X11.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND X11.SSPS_DL_ID = A.SSPS_DL_ID )
AND A.SSPS_TYP_CD IN
#{SSPS_TYP_CD_ARRAY}
AND A.RPR_PRGRS_CCD IN
#{wfCodeArray2, jdbcType=VARCHAR}
AND A.OK_CCD = #{wfCodeSts}
AND (B.CS_NM LIKE '%' || #{CS_NM} || '%' OR B.ENG_CS_NM LIKE '%' || #{CS_NM} || '%')
AND A.DL_P_RNMCNO LIKE '%' || UPPER(#{RNMCNO}) || '%'
ORDER BY
SSPS_DL_CRT_DT_A MN_DL_BRN_NM DL_P_NM DL_P_RNMCNO DL_P_RNM_NO_CCD_NM GNL_AC_NO DL_AMT SSPS_TYP_CD SSPS_TYP_NM CNT RPR_DT RSK_GRD_MRK DECODE(RSK_GRD_CD_NM, '고', 1, '중', 2, '저', 3) LG_AMT_ASTS_F ACT_NAME OK_CCD_NM XCL_RSN_CNTNT
ASC DESC
ORDER BY A.SSPS_DL_CRT_DT DESC ,A.SSPS_DL_ID ASC
) T2 WHERE 1 = 1
AND T2.REPORTDATE = #{reportdate}
) T1 WHERE 1 = 1
AND T1.SEQ >= (( #{thisPage} - 1) * #{pageCount} + 1) AND T1.SEQ <= (#{thisPage} * #{pageCount})

SELECT TRDG_CODE --거래코드 , TRDG_NAME --거래명 , DTLS_TRDG_NAME --상세거래명 , DL_TYP_CD --거래종류 , CTR_OBJ_YN --CTR대상여부 , USE_YN --사용여부 , ROW_NUMBER() OVER (ORDER BY TRDG_CODE) AS ROW_NUM FROM NIC81B_1 WHERE 1=1
AND UPPER(TRDG_CODE) LIKE '%'||UPPER(#{TRDG_CODE})||'%'
AND UPPER(TRDG_NAME) LIKE '%'||UPPER(#{TRDG_NAME})||'%'
AND DL_TYP_CD = #{DL_TYP_CD}
AND CTR_OBJ_YN = #{CTR_OBJ_YN}
AND USE_YN = #{USE_YN}
ORDER BY TRDG_CODE

